#[derive(Clone, Debug)]
struct GenericSourceEvent<'a> {
    source: &'a str,
    text: Option<&'a str>,
    key: Option<&'a str>,
    list_id: Option<&'a str>,
    target_text: Option<&'a str>,
    target_occurrence: Option<usize>,
    target_key: Option<u64>,
    target_generation: Option<u64>,
    bind_epoch: Option<u64>,
    address: Option<&'a str>,
    source_epoch: Option<u64>,
    payload: BTreeMap<String, &'a str>,
    payload_bytes: BTreeMap<String, Vec<u8>>,
    pointer_x: Option<&'a str>,
    pointer_y: Option<&'a str>,
    pointer_width: Option<&'a str>,
    pointer_height: Option<&'a str>,
}

impl<'a> GenericSourceEvent<'a> {
    fn from_step(step: &'a ScenarioStep) -> RuntimeResult<Option<Self>> {
        let Some(expected) = &step.expected_source_event else {
            return Ok(None);
        };
        let decoded = decode_plan_expected_source_event(&step.id, expected)?;
        Ok(Some(Self {
            source: decoded.source,
            text: decoded.text,
            key: decoded.key,
            list_id: decoded.list_id,
            target_text: decoded.target_text,
            target_occurrence: decoded.target_occurrence,
            target_key: decoded.target_key,
            target_generation: decoded.target_generation,
            bind_epoch: decoded.bind_epoch,
            address: decoded.address,
            source_epoch: decoded.source_epoch,
            payload: decoded.payload,
            payload_bytes: decoded.payload_bytes,
            pointer_x: decoded.pointer_x,
            pointer_y: decoded.pointer_y,
            pointer_width: decoded.pointer_width,
            pointer_height: decoded.pointer_height,
        }))
    }

    fn require(step: &'a ScenarioStep) -> RuntimeResult<Self> {
        Self::from_step(step)?.ok_or_else(|| {
            format!(
                "{} routed a source-producing event without expected_source_event",
                step.id
            )
            .into()
        })
    }
}

fn generic_source_event_payload_value<'a>(
    event: &GenericSourceEvent<'a>,
    field: &str,
) -> Option<&'a str> {
    source_payload_value(
        field,
        event.key,
        event.text,
        event.address,
        &event.payload,
        event.pointer_x,
        event.pointer_y,
        event.pointer_width,
        event.pointer_height,
    )
}

fn generic_source_event_row_lookup_value<'a>(
    event: &GenericSourceEvent<'a>,
    row_lookup_field: &str,
) -> Option<&'a str> {
    generic_source_event_payload_value(event, row_lookup_field).or(event.address)
}

fn plan_executor_scenario_step_meta(steps: &[ScenarioStep]) -> Vec<PlanExecutorScenarioStepMeta> {
    steps
        .iter()
        .map(|step| PlanExecutorScenarioStepMeta {
            id: step.id.clone(),
            has_expected_source_event: step.expected_source_event.is_some(),
        })
        .collect()
}

fn validate_live_source_event_payload_bytes_fields(
    event: &LiveSourceEvent,
    context: &str,
) -> RuntimeResult<()> {
    for field in event.payload_bytes.keys() {
        validate_plan_source_payload_bytes_field_name(field)
            .map_err(|error| format!("{context}: {error}"))?;
    }
    Ok(())
}

#[cfg(test)]
#[derive(Clone, Debug)]
struct GenericRoutedSourceEvent<'a> {
    event: GenericSourceEvent<'a>,
    route_kind: SourceActionKind,
}

#[cfg(test)]
impl<'a> GenericRoutedSourceEvent<'a> {
    fn source(&self) -> &'a str {
        self.event.source
    }

    fn require_text(&self, step_id: &str) -> RuntimeResult<&'a str> {
        self.event.text.ok_or_else(|| {
            format!(
                "{step_id} source `{}` route `{}` requires text",
                self.event.source,
                self.route_kind.as_str()
            )
            .into()
        })
    }

    fn require_address(self, step_id: &str) -> RuntimeResult<&'a str> {
        self.event.address.ok_or_else(|| {
            format!(
                "{step_id} source `{}` route `{}` requires address",
                self.event.source,
                self.route_kind.as_str()
            )
            .into()
        })
    }
}

