pub fn run_plan_initial_state(
    source_path: &Path,
    target_profile: TargetProfile,
    report_path: Option<&Path>,
) -> RuntimeResult<PlanInitialStateOutput> {
    let compiled = compile_source_path_to_machine_plan(source_path, target_profile)?;
    let report_context = compiled.report_context();
    let plan = compiled.plan;
    let output = execute_machine_plan_initial_state_inner(&plan)?;
    let report = json!({
        "status": "pass",
        "report_version": 1,
        "command": "run-plan",
        "command_argv": std::env::args().collect::<Vec<_>>(),
        "measurement_mode": "proof",
        "exit_status": 0,
        "generated_at_utc": now_string(),
        "git_commit": git_commit(),
        "worktree_fingerprint": worktree_fingerprint(),
        "binary_hash": current_binary_hash(),
        "binary_path": current_binary_path(),
        "source_path": source_path.display().to_string(),
        "source_hash": report_context.source_hash,
        "source_files": report_context.source_files,
        "scenario_hash": "n/a",
        "program_hash": report_context.program_hash,
        "program_kind": report_context.program_kind,
        "program_file_count": report_context.program_file_count,
        "budget_hash": "n/a",
        "graph_node_count": report_context.graph_node_count,
        "load_pipeline_profile": report_context.load_pipeline_profile,
        "target_profile": target_profile.as_str(),
        "plan_hash": output.plan_hash,
        "plan_version": plan.version,
        "capability_summary": plan.capability_summary,
        "state_summary": output.state_summary,
        "per_step_pass_fail": [
            {
                "id": "machine-plan-verified",
                "pass": true,
                "detail": "MachinePlan verifier passed before CPU initial-state execution"
            },
            {
                "id": "cpu-plan-executor-initial-state",
                "pass": true,
                "detail": "CPU PlanExecutor initialized scalar storage from typed plan constants"
            },
            {
                "id": "legacy-runtime-not-used",
                "pass": true,
                "detail": "initial-state PlanExecutor path did not call legacy scenario execution"
            }
        ],
        "artifact_sha256s": [],
        "plan_executor": output.executor_report,
    });
    if let Some(report_path) = report_path {
        write_json(report_path, &report)?;
    }
    Ok(PlanInitialStateOutput {
        plan_hash: output.plan_hash,
        state_summary: output.state_summary,
        report,
    })
}

pub fn run_plan_source_route(
    source_path: &Path,
    target_profile: TargetProfile,
    source_route: &str,
    target_state: &str,
    event: LiveSourceEvent,
    report_path: Option<&Path>,
) -> RuntimeResult<PlanRouteOutput> {
    validate_live_source_event_payload_bytes_fields(&event, "run-plan-route source event")?;
    let compiled = compile_source_path_to_machine_plan(source_path, target_profile)?;
    let report_context = compiled.report_context();
    let plan = compiled.plan;
    let root_json_event = root_json_source_event_from_live(&event);
    let host_file_root = source_path.parent();
    let output = execute_plan_source_route_with_runtime_callbacks(
        &plan,
        source_route,
        target_state,
        &root_json_event,
        |route_context: &SourceRouteExecutionContext,
         _execution_surface: &SourceRouteExecutionSurface,
         source_route_json_execution_report: &JsonValue| {
            let (root_state, _, _) = plan_root_scalar_initial_state(&plan)?;
            let executed = execute_root_scalar_update_branch(
                &plan,
                &route_context.update_op,
                route_context.selection.source_id,
                &route_context.source_route_slot,
                &event,
                None,
                &root_state,
                host_file_root,
            )?
            .ok_or_else(|| {
                format!(
                    "selected update branch {} source guard did not match the supplied event",
                    route_context.update_op.id.0
                )
            })?;
            Ok(assemble_plan_source_route_runtime_branch_execution(
                SourceRouteRuntimeBranchExecutionInput {
                    value: executed.value,
                    expression_kind: executed.expression_kind.to_owned(),
                    source_payload_field: executed.source_payload_field,
                    update_constant_id: executed.update_constant_id,
                    update_constant_value: executed.update_constant_value,
                    host_effect: executed.host_effect,
                    state_write_core: executed.state_write_core,
                    bytes_state_core: executed.bytes_state_core,
                    runtime_branch_core: executed.executor_core,
                },
                source_route_json_execution_report,
            ))
        },
        || {
            let step = event.clone().into_step(0);
            let full_execution =
                execute_machine_plan_root_scenario_inner(&plan, &[&step], host_file_root)?;
            Ok(SourceRouteFullExecution {
                state_summary: full_execution.state_summary,
                semantic_delta_signatures: full_execution.semantic_delta_signatures,
                semantic_deltas: full_execution.semantic_deltas,
                per_step: full_execution.per_step,
                executor_report: full_execution.executor_report,
            })
        },
    )?;
    let command_output =
        assemble_plan_source_route_command_output(SourceRouteCommandOutputInput {
            current_args: std::env::args().collect::<Vec<_>>(),
            generated_at_utc: now_string(),
            git_commit: git_commit(),
            worktree_fingerprint: worktree_fingerprint(),
            binary_hash: current_binary_hash(),
            binary_path: current_binary_path(),
            source_path: source_path.display().to_string(),
            source_hash: report_context.source_hash.clone(),
            source_files: report_context.source_files,
            program_hash: report_context.program_hash,
            program_kind: report_context.program_kind,
            program_file_count: report_context.program_file_count,
            graph_node_count: report_context.graph_node_count,
            load_pipeline_profile: report_context.load_pipeline_profile,
            target_profile: target_profile.as_str().to_owned(),
            source_route: source_route.to_owned(),
            target_state: target_state.to_owned(),
            event: SourceRouteSourceEventReportInput {
                source: source_route.to_owned(),
                source_id: output.source_id.0 as u64,
                text: event.text.clone(),
                key: event.key.clone(),
                list_id: event.list_id.clone(),
                address: event.address.clone(),
                target_text: event.target_text.clone(),
                target_occurrence: event.target_occurrence,
                target_key: event.target_key,
                target_generation: event.target_generation,
                bind_epoch: event.bind_epoch,
                source_epoch: event.source_epoch,
                payload: event.payload.clone(),
                payload_bytes_report: JsonValue::Null,
                pointer_x: event.pointer_x.clone(),
                pointer_y: event.pointer_y.clone(),
                pointer_width: event.pointer_width.clone(),
                pointer_height: event.pointer_height.clone(),
            },
            payload_bytes: event.payload_bytes.clone(),
            report_path: report_path.map(Path::to_path_buf),
            plan_hash: output.plan_hash.clone(),
            plan_version: serde_json::to_value(plan.version)?,
            capability_summary: serde_json::to_value(&plan.capability_summary)?,
            route_surface: output.route_surface.clone(),
            state_summary: output.state_summary.clone(),
            semantic_delta_signatures: output.semantic_delta_signatures.clone(),
            semantic_deltas: output.semantic_deltas.clone(),
            plan_executor: output.executor_report.clone(),
            inline_byte_limit: SOURCE_EVENT_INLINE_BYTES_LIMIT,
        })?;
    let report = command_output.report;
    if let Some(report_path) = report_path {
        write_json(report_path, &report)?;
    }
    Ok(PlanRouteOutput {
        plan_hash: output.plan_hash,
        state_summary: output.state_summary,
        report,
    })
}

pub fn run_plan_root_scalar_scenario(
    source_path: &Path,
    scenario_path: &Path,
    target_profile: TargetProfile,
    selected_step_ids: &[String],
    report_path: Option<&Path>,
) -> RuntimeResult<PlanRootScalarScenarioOutput> {
    let compiled = compile_source_path_to_machine_plan(source_path, target_profile)?;
    let report_context = compiled.report_context();
    let plan = compiled.plan;
    let scenario = parse_scenario(scenario_path)?;
    let scenario_step_meta = plan_executor_scenario_step_meta(&scenario.step);
    let step_selection = select_plan_explicit_root_scenario_steps(
        &scenario.name,
        &scenario_step_meta,
        selected_step_ids,
    )?;
    let selected_steps = step_selection
        .selected_indices
        .iter()
        .map(|index| &scenario.step[*index])
        .collect::<Vec<_>>();

    let output =
        execute_machine_plan_root_scenario_inner(&plan, &selected_steps, source_path.parent())?;
    let command_output =
        assemble_plan_root_scenario_command_output(RootScenarioCommandOutputInput {
            command_argv: std::env::args().collect::<Vec<_>>(),
            generated_at_utc: now_string(),
            git_commit: git_commit(),
            worktree_fingerprint: worktree_fingerprint(),
            binary_hash: current_binary_hash(),
            binary_path: current_binary_path(),
            source_path: source_path.display().to_string(),
            source_hash: report_context.source_hash.clone(),
            source_files: report_context.source_files,
            scenario_path: scenario_path.display().to_string(),
            scenario_hash: sha256_file(scenario_path)?,
            program_hash: report_context.program_hash,
            program_kind: report_context.program_kind,
            program_file_count: report_context.program_file_count,
            graph_node_count: report_context.graph_node_count,
            load_pipeline_profile: report_context.load_pipeline_profile,
            target_profile: target_profile.as_str().to_owned(),
            plan_hash: output.plan_hash.clone(),
            plan_version: serde_json::to_value(plan.version)?,
            capability_summary: serde_json::to_value(&plan.capability_summary)?,
            selected_step_ids: selected_step_ids.to_vec(),
            state_summary: output.state_summary.clone(),
            semantic_delta_signatures: output.semantic_delta_signatures.clone(),
            semantic_deltas: output.semantic_deltas.clone(),
            plan_executor: output.executor_report.clone(),
        });
    let report = command_output.report;
    if let Some(report_path) = report_path {
        write_json(report_path, &report)?;
    }
    Ok(PlanRootScalarScenarioOutput {
        plan_hash: output.plan_hash,
        state_summary: output.state_summary,
        report,
    })
}

pub fn run_plan_scenario_events(
    source_path: &Path,
    scenario_path: &Path,
    target_profile: TargetProfile,
    report_path: Option<&Path>,
) -> RuntimeResult<PlanRootScalarScenarioOutput> {
    let compiled = compile_source_path_to_machine_plan(source_path, target_profile)?;
    let report_context = compiled.report_context();
    let plan = compiled.plan;
    let scenario = parse_scenario(scenario_path)?;
    let scenario_step_meta = plan_executor_scenario_step_meta(&scenario.step);
    let step_selection = select_plan_scenario_event_steps(&scenario.name, &scenario_step_meta)?;
    let selected_steps = step_selection
        .selected_indices
        .iter()
        .map(|index| &scenario.step[*index])
        .collect::<Vec<_>>();
    let all_steps = step_selection
        .all_indices
        .iter()
        .map(|index| &scenario.step[*index])
        .collect::<Vec<_>>();
    let output = execute_machine_plan_root_scenario_inner(&plan, &all_steps, source_path.parent())?;
    let coverage_report = assemble_plan_root_scenario_coverage_report(
        scenario.step.len(),
        selected_steps.len(),
        &step_selection.selected_step_ids,
        &step_selection.assertion_only_step_ids,
        &output.assertion_checkpoints,
    );
    let assertion_only_covered = coverage_report.assertion_only_covered;
    let plan_executor_coverage = coverage_report.coverage;
    let command_output =
        assemble_plan_scenario_events_command_output(ScenarioEventsCommandOutputInput {
            command_argv: std::env::args().collect::<Vec<_>>(),
            generated_at_utc: now_string(),
            git_commit: git_commit(),
            worktree_fingerprint: worktree_fingerprint(),
            binary_hash: current_binary_hash(),
            binary_path: current_binary_path(),
            source_path: source_path.display().to_string(),
            source_hash: report_context.source_hash.clone(),
            source_files: report_context.source_files,
            scenario_path: scenario_path.display().to_string(),
            scenario_hash: sha256_file(scenario_path)?,
            program_hash: report_context.program_hash,
            program_kind: report_context.program_kind,
            program_file_count: report_context.program_file_count,
            graph_node_count: report_context.graph_node_count,
            load_pipeline_profile: report_context.load_pipeline_profile,
            target_profile: target_profile.as_str().to_owned(),
            plan_hash: output.plan_hash.clone(),
            plan_version: serde_json::to_value(plan.version)?,
            capability_summary: serde_json::to_value(&plan.capability_summary)?,
            state_summary: output.state_summary.clone(),
            semantic_delta_signatures: output.semantic_delta_signatures.clone(),
            semantic_deltas: output.semantic_deltas.clone(),
            plan_executor_coverage,
            assertion_only_covered,
            plan_executor: output.executor_report.clone(),
        });
    let mut report = command_output.report;
    insert_plan_executor_source_replay_worktree_fields(&mut report);
    insert_plan_executor_source_replay_identity(&mut report);
    if let Some(report_path) = report_path {
        write_json(report_path, &report)?;
    }
    Ok(PlanRootScalarScenarioOutput {
        plan_hash: output.plan_hash,
        state_summary: output.state_summary,
        report,
    })
}

struct InitialStateExecution {
    plan_hash: String,
    state_summary: JsonValue,
    executor_report: JsonValue,
}

struct RootScenarioExecution {
    plan_hash: String,
    state_summary: JsonValue,
    semantic_delta_signatures: Vec<String>,
    semantic_deltas: JsonValue,
    per_step: Vec<JsonValue>,
    assertion_checkpoints: Vec<JsonValue>,
    executor_report: JsonValue,
}

type RootBytesState = BTreeMap<usize, PlanExecutorBytes>;
type RootFixedBytesBanks = BTreeMap<usize, Vec<u8>>;

#[derive(Clone)]
struct PlanExecutorRuntimeState {
    root_state: PlanExecutorRootState,
    root_bytes_initialization_core: JsonValue,
    initialized_state_count: usize,
    list_state: BTreeMap<usize, Vec<PlanListRowState>>,
    list_next_keys: BTreeMap<usize, u64>,
    bytes_counter_baseline: RuntimeBytesStorageCounters,
    list_append_row_bool_delta_lists: BTreeSet<usize>,
    per_step: Vec<JsonValue>,
    semantic_delta_signatures: Vec<String>,
    semantic_deltas: Vec<JsonValue>,
    executed_update_branch_count: usize,
    executed_derived_value_count: usize,
    executed_list_append_count: usize,
    executed_list_remove_count: usize,
    executed_indexed_update_count: usize,
    emitted_source_bind_count: usize,
    emitted_source_unbind_count: usize,
    executed_list_retain_count: usize,
    executed_list_view_count: usize,
    retained_list_row_count: usize,
    assertion_checkpoints: Vec<JsonValue>,
}

#[derive(Clone)]
struct PlanExecutorLiveSession {
    plan: Arc<MachinePlan>,
    generic_output_plan: RuntimeGenericDerivedPlan,
    state: PlanExecutorRuntimeState,
    host_file_root: Option<PathBuf>,
    next_step: usize,
}

impl PlanExecutorRuntimeState {
    fn new(plan: &MachinePlan) -> RuntimeResult<Self> {
        let (mut root_state, root_bytes_initialization_core, initialized_state_count) =
            plan_root_scalar_initial_state(plan)?;
        let mut list_state = plan_initial_list_state(plan)?;
        refresh_plan_initial_list_state_with_root_context(
            plan,
            &root_state.root_state,
            &mut list_state,
        )?;
        let initial_list_derived_values = root_pure_number_compare_values(plan, &list_state)?
            .into_iter()
            .map(|(field_id, value)| (FieldId(field_id), value))
            .collect::<BTreeMap<_, _>>();
        let initial_list_derived_commits = commit_plan_source_derived_values_to_root_state(
            plan,
            &mut root_state.root_state,
            &initial_list_derived_values,
        );
        if let Some(report) = root_state.executor_report.as_object_mut() {
            report.insert(
                "initialized_root_list_derived_count".to_owned(),
                json!(initial_list_derived_values.len()),
            );
            report.insert(
                "root_list_derived_commits".to_owned(),
                JsonValue::Array(initial_list_derived_commits),
            );
        }
        let list_next_keys =
            initial_plan_list_next_keys(&plan_executor_list_state_for_materialization(&list_state));
        Ok(Self {
            root_state,
            root_bytes_initialization_core,
            initialized_state_count,
            list_state,
            list_next_keys,
            bytes_counter_baseline: runtime_bytes_storage_counters_snapshot(),
            list_append_row_bool_delta_lists: BTreeSet::new(),
            per_step: Vec::new(),
            semantic_delta_signatures: Vec::new(),
            semantic_deltas: Vec::new(),
            executed_update_branch_count: 0,
            executed_derived_value_count: 0,
            executed_list_append_count: 0,
            executed_list_remove_count: 0,
            executed_indexed_update_count: 0,
            emitted_source_bind_count: 0,
            emitted_source_unbind_count: 0,
            executed_list_retain_count: 0,
            executed_list_view_count: 0,
            retained_list_row_count: 0,
            assertion_checkpoints: Vec::new(),
        })
    }

    fn apply_step(
        &mut self,
        plan: &MachinePlan,
        step: &ScenarioStep,
        host_file_root: Option<&Path>,
    ) -> RuntimeResult<()> {
        if step.expected_source_event.is_none() {
            self.assertion_checkpoints
                .push(assert_plan_executor_scenario_checkpoint(
                    plan,
                    &self.root_state.root_state,
                    &self.list_state,
                    step,
                )?);
            return Ok(());
        }

        let step_bytes_counter_start = runtime_bytes_storage_counters_snapshot();
        let generic_event = GenericSourceEvent::require(step)?;
        let event = live_source_event_from_generic(&generic_event);
        let root_json_event = root_json_source_event_from_live(&event);
        let step_preparation = prepare_plan_root_scenario_step(
            plan,
            generic_event.source,
            &root_json_event,
            &self.root_state.root_state,
        )?;
        let source_id = step_preparation.source_id;
        let source_route_slot = &step_preparation.source_route_slot;
        let derived_values = step_preparation.derived_values;
        let route_ops = step_preparation.route_ops;
        let root_update_key_matches = step_preparation.root_update_key_matches;
        let root_dispatch_report = step_preparation.root_dispatch_report;

        let mut touched_states = serde_json::Map::new();
        let mut touched_updates: BTreeMap<usize, RootExecutedUpdate> = BTreeMap::new();
        let mut touched_update_candidates = RootUpdateCandidateTracker::default();
        let mut staged_root_state = self.root_state.clone();
        let mut step_signatures = Vec::new();
        let mut step_deltas = Vec::new();
        let mut updates = Vec::new();
        let mut derived = Vec::new();
        let mut indexed_updates = Vec::new();
        let mut pending_indexed_deltas = Vec::new();
        let mut list_removes = Vec::new();
        let root_derived_values_before_updates =
            plan_executor_root_derived_values(plan, &self.root_state.root_state, &self.list_state)?;
        let source_derived_step = assemble_plan_source_derived_step_deltas(plan, &derived_values);
        for (signature, delta) in source_derived_step
            .semantic_delta_signatures
            .iter()
            .cloned()
            .zip(source_derived_step.semantic_deltas.iter().cloned())
        {
            step_signatures.push(signature.clone());
            self.semantic_delta_signatures.push(signature);
            self.semantic_deltas.push(delta.clone());
            step_deltas.push(delta);
            self.executed_derived_value_count += 1;
        }
        derived.extend(source_derived_step.reports);
        let root_source_derived_commits = commit_plan_source_derived_values_to_root_state(
            plan,
            &mut self.root_state.root_state,
            &derived_values,
        );
        let _ = commit_plan_source_derived_values_to_root_state(
            plan,
            &mut staged_root_state.root_state,
            &derived_values,
        );
        derived.extend(root_source_derived_commits);

        let append_result = append_plan_list_rows_for_derived_values_with(
            plan,
            &mut self.list_state,
            &mut self.list_next_keys,
            &mut self.list_append_row_bool_delta_lists,
            &derived_values,
            |plan, list_state, row, expression| {
                eval_plan_row_expression(plan, list_state, row, expression).map_err(
                    |error| -> Box<dyn std::error::Error> {
                        format!("PlanExecutor list append row {}: {error}", row.key).into()
                    },
                )
            },
        )?;
        for delta in &append_result.semantic_deltas {
            let signature = plan_json_delta_signature(delta)?;
            step_signatures.push(signature.clone());
            self.semantic_delta_signatures.push(signature);
            self.semantic_deltas.push(delta.clone());
            step_deltas.push(delta.clone());
        }
        self.executed_list_append_count += append_result.appended_row_count;
        self.emitted_source_bind_count += append_result.source_bind_count;

        let remove_event = PlanExecutorLiveSourceEvent {
            source: generic_event.source,
            text: generic_event.text,
            key: generic_event.key,
            list_id: generic_event.list_id,
            address: generic_event.address,
            target_text: generic_event.target_text,
            target_occurrence: generic_event.target_occurrence.map(|value| value as u64),
            target_key: generic_event.target_key,
            target_generation: generic_event.target_generation,
            bind_epoch: generic_event.bind_epoch,
            source_epoch: generic_event.source_epoch,
            source_id: None,
        };
        let remove_result = remove_plan_list_rows_for_source_event(
            plan,
            source_id,
            source_route_slot,
            &remove_event,
            &mut self.list_state,
        )?;
        for delta in &remove_result.semantic_deltas {
            let signature = plan_json_delta_signature(delta)?;
            step_signatures.push(signature.clone());
            self.semantic_delta_signatures.push(signature);
            self.semantic_deltas.push(delta.clone());
            step_deltas.push(delta.clone());
        }
        self.executed_list_remove_count += remove_result.removed_row_count;
        self.emitted_source_unbind_count += remove_result.source_unbind_count;
        self.executed_derived_value_count += remove_result.derived_count;
        derived.extend(remove_result.report_derived);
        list_removes.extend(remove_result.report_rows);

        let mut row_resolution_cache = BTreeMap::new();
        for op in &route_ops {
            if !root_update_key_matches {
                continue;
            }
            if op.indexed {
                let targeted_or_scoped_indexed_update = source_route_slot.scoped
                    || generic_event.target_key.is_some()
                    || generic_event.target_text.is_some()
                    || generic_event.address.is_some();
                if targeted_or_scoped_indexed_update {
                    let indexed = execute_indexed_update_branch(
                        plan,
                        op,
                        source_id,
                        source_route_slot,
                        &generic_event,
                        &mut self.list_state,
                        &mut row_resolution_cache,
                        &root_derived_values_before_updates,
                        host_file_root,
                    )
                    .map_err(|error| -> Box<dyn std::error::Error> {
                        format!(
                            "PlanExecutor indexed update op {} for source {}: {error}",
                            op.id.0, source_id.0
                        )
                        .into()
                    })?;
                    pending_indexed_deltas.extend(indexed.semantic_deltas);
                    self.executed_update_branch_count += indexed.updated_row_count;
                    self.executed_indexed_update_count += indexed.updated_row_count;
                    indexed_updates.extend(indexed.report_rows);
                    continue;
                }
                let indexed_target_rows =
                    plan_executor_list_state_for_materialization(&self.list_state);
                let indexed_batch = execute_plan_indexed_update_batch_with(
                    plan,
                    op,
                    source_route_slot,
                    &IndexedUpdateTargetEvent {
                        source: generic_event.source.to_owned(),
                        list_id: generic_event.list_id.map(str::to_owned),
                        target_key: generic_event.target_key,
                        target_text: generic_event.target_text.map(str::to_owned),
                        address: generic_event.address.map(str::to_owned),
                    },
                    &indexed_target_rows,
                    |target: Option<IndexedUpdateTargetOverride>| {
                        if let Some(target) = target {
                            let mut row_event = generic_event.clone();
                            row_event.list_id = Some(target.list_label.as_str());
                            row_event.target_key = Some(target.key);
                            row_event.target_generation = Some(target.generation);
                            let mut per_row_resolution_cache = BTreeMap::new();
                            execute_indexed_update_branch(
                                plan,
                                op,
                                source_id,
                                source_route_slot,
                                &row_event,
                                &mut self.list_state,
                                &mut per_row_resolution_cache,
                                &root_derived_values_before_updates,
                                host_file_root,
                            )
                            .map_err(|error| -> Box<dyn std::error::Error> {
                                format!(
                                    "PlanExecutor indexed update op {} per-row override for source {}: {error}",
                                    op.id.0, source_id.0
                                )
                                .into()
                            })
                        } else {
                            execute_indexed_update_branch(
                                plan,
                                op,
                                source_id,
                                source_route_slot,
                                &generic_event,
                                &mut self.list_state,
                                &mut row_resolution_cache,
                                &root_derived_values_before_updates,
                                host_file_root,
                            )
                            .map_err(|error| -> Box<dyn std::error::Error> {
                                format!(
                                    "PlanExecutor indexed update op {} for source {}: {error}",
                                    op.id.0, source_id.0
                                )
                                .into()
                            })
                        }
                    },
                )
                .map_err(|error| -> Box<dyn std::error::Error> {
                    format!(
                        "PlanExecutor indexed update batch op {} for source {}: {error}",
                        op.id.0, source_id.0
                    )
                    .into()
                })?;
                pending_indexed_deltas.extend(indexed_batch.semantic_deltas);
                self.executed_update_branch_count += indexed_batch.updated_row_count;
                self.executed_indexed_update_count += indexed_batch.updated_row_count;
                indexed_updates.extend(indexed_batch.report_rows);
                continue;
            }
            let mut runtime_branch = |op: &boon_plan::PlanOp,
                                      staged_state: &PlanExecutorRootState|
             -> RuntimeResult<Option<RootExecutedUpdate>> {
                execute_root_scalar_update_branch(
                    plan,
                    op,
                    source_id,
                    source_route_slot,
                    &event,
                    Some(&self.list_state),
                    staged_state,
                    host_file_root,
                )
                .map_err(|error| -> Box<dyn std::error::Error> {
                    format!(
                        "PlanExecutor root update op {} for source {}: {error}",
                        op.id.0, source_id.0
                    )
                    .into()
                })
            };
            let collection = collect_plan_root_update_candidate_for_step(
                plan,
                op,
                source_id,
                generic_event.source,
                source_route_slot,
                &root_json_event,
                &mut staged_root_state,
                &mut touched_update_candidates,
                &mut touched_updates,
                &mut runtime_branch,
            )?;
            if collection.inserted_update {
                refresh_plan_root_row_expression_derived_values_in_state(
                    plan,
                    &mut staged_root_state.root_state,
                );
            }
        }

        let root_update_commit_batch = commit_plan_ordered_root_update_candidates(
            &mut self.root_state,
            plan,
            source_id,
            &touched_update_candidates,
            touched_updates,
        )?;
        touched_states.extend(root_update_commit_batch.touched_states);
        for signature in root_update_commit_batch.semantic_delta_signatures {
            step_signatures.push(signature.clone());
            self.semantic_delta_signatures.push(signature);
        }
        for delta in root_update_commit_batch.semantic_deltas {
            self.semantic_deltas.push(delta.clone());
            step_deltas.push(delta);
        }
        let changed_root_state_ids =
            changed_root_state_ids_from_update_reports(&root_update_commit_batch.update_reports);
        updates.extend(root_update_commit_batch.update_reports);
        self.executed_update_branch_count += root_update_commit_batch.executed_update_branch_count;
        pending_indexed_deltas.extend(refresh_indexed_derived_fields_after_root_state_changes(
            plan,
            &mut self.list_state,
            &changed_root_state_ids,
        )?);
        let pending_indexed_deltas = coalesce_plan_field_set_deltas(pending_indexed_deltas)?;
        for delta in &pending_indexed_deltas {
            let signature = plan_json_delta_signature(delta)?;
            step_signatures.push(signature.clone());
            self.semantic_delta_signatures.push(signature);
            self.semantic_deltas.push(delta.clone());
            step_deltas.push(delta.clone());
        }
        let root_list_derived_values_after_updates =
            plan_executor_root_derived_values(plan, &self.root_state.root_state, &self.list_state)?;
        let root_list_derived_changes = changed_plan_root_derived_deltas(
            plan,
            &root_derived_values_before_updates,
            &root_list_derived_values_after_updates,
        );
        commit_root_list_derived_values_to_root_state(
            plan,
            &mut self.root_state.root_state,
            &root_list_derived_values_after_updates,
        );
        for (delta, report) in root_list_derived_changes {
            if root_field_set_delta_already_recorded(&step_deltas, &delta) {
                continue;
            }
            let signature = plan_json_delta_signature(&delta)?;
            step_signatures.push(signature.clone());
            self.semantic_delta_signatures.push(signature);
            self.semantic_deltas.push(delta.clone());
            step_deltas.push(delta);
            derived.push(report);
            self.executed_derived_value_count += 1;
        }
        let step_retain_execution =
            materialize_plan_list_retains(plan, &self.root_state.root_state, &self.list_state)?;
        self.executed_list_retain_count += step_retain_execution.executed_count;
        self.executed_list_view_count += step_retain_execution.view_count;
        self.retained_list_row_count += step_retain_execution.retained_row_count;
        let step_bytes_counters = runtime_bytes_storage_counters_snapshot()
            .saturating_delta_since(step_bytes_counter_start);
        let step_report = assemble_plan_root_scenario_step_report(
            &step.id,
            generic_event.source,
            source_id,
            &root_dispatch_report,
            touched_states.len() + indexed_updates.len(),
            derived.len(),
            append_result.appended_row_count,
            list_removes.len(),
            indexed_updates.len(),
            step_retain_execution.executed_count,
            step_retain_execution.view_count,
            step_retain_execution.retained_row_count,
            append_result.source_bind_count,
            remove_result.source_unbind_count,
            derived,
            append_result.report_rows,
            list_removes,
            step_retain_execution.reports,
            JsonValue::Object(step_retain_execution.summary),
            indexed_updates,
            updates,
            JsonValue::Object(touched_states),
            step_signatures,
            step_deltas,
            step_bytes_counters.report_json(),
            step_bytes_counters.no_runtime_byte_copies(),
        );
        self.per_step.push(step_report.step_report);
        Ok(())
    }

    fn apply_live_source_event(
        &mut self,
        plan: &MachinePlan,
        event: LiveSourceEvent,
        sequence: usize,
        host_file_root: Option<&Path>,
    ) -> RuntimeResult<()> {
        let step = event.into_step(sequence);
        self.apply_step(plan, &step, host_file_root)
    }

    fn finish(self, plan: &MachinePlan) -> RuntimeResult<RootScenarioExecution> {
        let plan_hash = plan_sha256(plan)?;
        let bytes_storage_counters = runtime_bytes_storage_counters_snapshot()
            .saturating_delta_since(self.bytes_counter_baseline);
        let state_summary = JsonValue::Object(self.root_state.root_state);
        let list_summary = plan_list_summary(plan, &self.list_state);
        let projection_execution = materialize_plan_list_projections(
            plan,
            state_summary.as_object().unwrap(),
            &self.list_state,
        )?;
        let retain_execution = materialize_plan_list_retains(
            plan,
            state_summary.as_object().unwrap(),
            &self.list_state,
        )?;
        let semantic_deltas = JsonValue::Array(self.semantic_deltas);
        let list_projection_summary = JsonValue::Object(projection_execution.summary);
        let list_view_summary = JsonValue::Object(retain_execution.summary);
        let bytes_storage_counters_report = bytes_storage_counters.report_json();
        let bytes_storage_no_copy = bytes_storage_counters.no_runtime_byte_copies();
        let report_assembly = assemble_plan_root_scenario_report(
            plan,
            self.per_step.len(),
            self.initialized_state_count,
            &self.root_bytes_initialization_core,
            self.executed_update_branch_count,
            self.executed_derived_value_count,
            self.executed_list_append_count,
            self.executed_list_remove_count,
            self.executed_indexed_update_count,
            self.emitted_source_bind_count,
            self.emitted_source_unbind_count,
            self.executed_list_retain_count,
            self.executed_list_view_count,
            self.retained_list_row_count,
            projection_execution.executed_count,
            projection_execution.find_count,
            projection_execution.chunk_count,
            projection_execution.projected_row_count,
            &state_summary,
            &list_summary,
            &list_projection_summary,
            &projection_execution.reports,
            &list_view_summary,
            &retain_execution.reports,
            &self.semantic_delta_signatures,
            &semantic_deltas,
            &self.per_step,
            &self.assertion_checkpoints,
            &bytes_storage_counters_report,
            bytes_storage_no_copy,
        )?;
        Ok(RootScenarioExecution {
            plan_hash,
            state_summary,
            semantic_delta_signatures: self.semantic_delta_signatures,
            semantic_deltas,
            per_step: self.per_step,
            assertion_checkpoints: self.assertion_checkpoints,
            executor_report: report_assembly.executor_report,
        })
    }

    fn snapshot(&self, plan: &MachinePlan) -> RuntimeResult<RootScenarioExecution> {
        self.clone().finish(plan)
    }

    fn state_summary(&mut self, plan: &MachinePlan) -> JsonValue {
        self.document_state_summary(plan, SummaryLimits::state_summary())
    }

    fn document_state_summary(&mut self, plan: &MachinePlan, limits: SummaryLimits) -> JsonValue {
        plan_executor_document_summary_with_limits(
            plan,
            &self.root_state.root_state,
            &mut self.list_state,
            limits,
        )
    }
}

impl PlanExecutorLiveSession {
    fn from_source(
        source_label: &str,
        source_text: &str,
        target_profile: TargetProfile,
    ) -> RuntimeResult<Self> {
        let runtime_plan = cached_runtime_plan_from_source(source_label, source_text)?;
        let compiled =
            compile_source_text_to_machine_plan(source_label, source_text, target_profile)?;
        Self::from_machine_plan(
            compiled.plan,
            runtime_plan.compiled.generic_derived_runtime.clone(),
            None,
        )
    }

    fn from_project(
        source_label: &str,
        units: &[RuntimeSourceUnit],
        target_profile: TargetProfile,
    ) -> RuntimeResult<Self> {
        let runtime_plan = cached_runtime_plan_from_project(source_label, units)?;
        let compiler_units = compiler_source_units_from_runtime_units(units);
        let compiled =
            compile_source_units_to_machine_plan(source_label, &compiler_units, target_profile)?;
        Self::from_machine_plan(
            compiled.plan,
            runtime_plan.compiled.generic_derived_runtime.clone(),
            None,
        )
    }

    fn from_source_path(source_path: &Path, target_profile: TargetProfile) -> RuntimeResult<Self> {
        let source_text = std::fs::read_to_string(source_path)?;
        let runtime_plan =
            cached_runtime_plan_from_source(&source_path.display().to_string(), &source_text)?;
        let compiled = compile_source_path_to_machine_plan(source_path, target_profile)?;
        Self::from_machine_plan(
            compiled.plan,
            runtime_plan.compiled.generic_derived_runtime.clone(),
            source_path.parent().map(Path::to_path_buf),
        )
    }

    fn from_compiled_artifact(artifact: &CompiledArtifact) -> RuntimeResult<Self> {
        Self::from_machine_plan(
            artifact.machine_plan()?,
            artifact.runtime_generic_derived_plan()?,
            None,
        )
    }

    fn from_machine_plan(
        plan: MachinePlan,
        generic_output_plan: RuntimeGenericDerivedPlan,
        host_file_root: Option<PathBuf>,
    ) -> RuntimeResult<Self> {
        let plan = Arc::new(plan);
        let state = PlanExecutorRuntimeState::new(plan.as_ref())?;
        Ok(Self {
            plan,
            generic_output_plan,
            state,
            host_file_root,
            next_step: 1,
        })
    }

    fn apply_source_event(&mut self, event: LiveSourceEvent) -> RuntimeResult<JsonValue> {
        let step_index = self.next_step;
        self.next_step = self.next_step.saturating_add(1);
        let previous_step_count = self.state.per_step.len();
        self.state.apply_live_source_event(
            self.plan.as_ref(),
            event,
            step_index,
            self.host_file_root.as_deref(),
        )?;
        self.state
            .per_step
            .get(previous_step_count)
            .cloned()
            .ok_or_else(|| "PlanExecutor live source event produced no step report".into())
    }

    fn snapshot(&self) -> RuntimeResult<RootScenarioExecution> {
        self.state.snapshot(self.plan.as_ref())
    }

    fn state_summary(&mut self) -> JsonValue {
        self.state.state_summary(self.plan.as_ref())
    }

    fn document_state_summary(&mut self, limits: SummaryLimits) -> JsonValue {
        self.state
            .document_state_summary(self.plan.as_ref(), limits)
    }

    fn canonical_source_path(&self, source: &str) -> Option<String> {
        if self
            .plan
            .source_routes
            .iter()
            .any(|route| route.path == source)
        {
            return Some(source.to_owned());
        }
        runtime_event_source_path_alias(source).filter(|alias| {
            self.plan
                .source_routes
                .iter()
                .any(|route| route.path == *alias)
        })
    }

    fn source_id(&self, source: &str) -> Option<SourceId> {
        let source = self
            .canonical_source_path(source)
            .unwrap_or_else(|| source.to_owned());
        self.plan
            .source_routes
            .iter()
            .find(|route| route.path == source)
            .map(|route| route.source_id)
    }

    fn has_source_path(&self, source: &str) -> bool {
        self.canonical_source_path(source).is_some()
    }

    fn source_payload_has_text(&self, source: &str) -> bool {
        let source = self
            .canonical_source_path(source)
            .unwrap_or_else(|| source.to_owned());
        self.plan
            .source_routes
            .iter()
            .find(|route| route.path == source)
            .is_some_and(|route| {
                route
                    .payload_schema
                    .fields
                    .iter()
                    .any(|field| matches!(field, SourcePayloadField::Text))
            })
    }

    fn document_state_values(&mut self, paths: &[String]) -> JsonValue {
        let mut values = serde_json::Map::new();
        let preview = self.document_state_summary(SummaryLimits::document_preview());
        let mut full: Option<JsonValue> = None;
        for path in paths {
            if path.starts_with('@') {
                continue;
            }
            let value = runtime_value_at_path(&preview, path).cloned().or_else(|| {
                let full_summary = full
                    .get_or_insert_with(|| self.document_state_summary(SummaryLimits::unlimited()));
                runtime_value_at_path(full_summary, path).cloned()
            });
            if let Some(value) = value {
                values.insert(path.clone(), value);
            }
        }
        JsonValue::Object(values)
    }

    fn runtime_value_summaries(
        &mut self,
        paths: &[String],
        max_depth: usize,
        max_fields: usize,
        max_list_items: usize,
    ) -> JsonValue {
        let mut values = serde_json::Map::new();
        let preview = self.document_state_summary(SummaryLimits::document_preview());
        let mut full: Option<JsonValue> = None;
        for path in paths {
            let value = runtime_value_at_path(&preview, path)
                .or_else(|| {
                    let full_summary = full.get_or_insert_with(|| {
                        self.document_state_summary(SummaryLimits::unlimited())
                    });
                    runtime_value_at_path(full_summary, path)
                })
                .map(|value| {
                    runtime_json_value_summary(value, 0, max_depth, max_fields, max_list_items)
                })
                .unwrap_or_else(|| json!({"kind": "missing"}));
            values.insert(path.clone(), value);
        }
        JsonValue::Object(values)
    }

    fn finish(self) -> RuntimeResult<RootScenarioExecution> {
        self.state.finish(self.plan.as_ref())
    }

    fn provenance_report(&self) -> JsonValue {
        json!({
            "engine": "plan_executor",
            "session_kind": "persistent-live",
            "next_step": self.next_step,
            "host_file_root": self.host_file_root.as_ref().map(|path| path.display().to_string()),
            "runtime_ast_eval_count": 0,
            "executable_string_path_count": 0,
            "unknown_plan_op_count": 0,
            "output_root_evaluator": "plan_executor_generic_output_program",
            "output_root_count": self.generic_output_plan.output_roots.len(),
            "generic_fallback_enabled": false,
        })
    }

    fn world_scene_output(&self) -> RuntimeResult<RuntimeWorldSceneOutput> {
        let mut evaluator = PlanExecutorOutputEvaluator::new(
            self.plan.as_ref(),
            &self.generic_output_plan,
            &self.state.root_state.root_state,
            &self.state.list_state,
        );
        evaluator.world_scene_output()
    }

    fn solid_model_output(&self) -> RuntimeResult<RuntimeSolidModelOutput> {
        let mut evaluator = PlanExecutorOutputEvaluator::new(
            self.plan.as_ref(),
            &self.generic_output_plan,
            &self.state.root_state.root_state,
            &self.state.list_state,
        );
        evaluator.solid_model_output()
    }
}

struct PlanExecutorOutputEvaluator<'a> {
    plan: &'a MachinePlan,
    generic_output_plan: &'a RuntimeGenericDerivedPlan,
    root_state: &'a serde_json::Map<String, JsonValue>,
    list_state: &'a BTreeMap<usize, Vec<PlanListRowState>>,
}

impl<'a> PlanExecutorOutputEvaluator<'a> {
    fn new(
        plan: &'a MachinePlan,
        generic_output_plan: &'a RuntimeGenericDerivedPlan,
        root_state: &'a serde_json::Map<String, JsonValue>,
        list_state: &'a BTreeMap<usize, Vec<PlanListRowState>>,
    ) -> Self {
        Self {
            plan,
            generic_output_plan,
            root_state,
            list_state,
        }
    }

    fn world_scene_output(&mut self) -> RuntimeResult<RuntimeWorldSceneOutput> {
        let mut frame = GenericEvalFrame::root();
        let output = self
            .generic_output_plan
            .output_root_plan("world")
            .ok_or("PlanExecutor world output requires a top-level `world:` value")?
            .clone();
        if output.output_kind != "world"
            || !output.generic_output_port
            || !output.typed_contract_known
        {
            return Err(format!(
                "PlanExecutor world output root has unsupported contract kind={} generic={} typed={}",
                output.output_kind, output.generic_output_port, output.typed_contract_known
            )
            .into());
        }
        let statement = output.statement.as_ref().ok_or_else(|| {
            output
                .unsupported_reason
                .clone()
                .unwrap_or_else(|| "PlanExecutor world output root is not executable".to_owned())
        })?;
        let value = self.eval_statement(statement, &mut frame)?;
        let scene = lower_world_scene_from_boon_value(&value)?;
        Ok(RuntimeWorldSceneOutput {
            output_root: "world".to_owned(),
            scene,
            read_count: frame.reads.len(),
        })
    }

    fn solid_model_output(&mut self) -> RuntimeResult<RuntimeSolidModelOutput> {
        let mut frame = GenericEvalFrame::root();
        let output = self
            .generic_output_plan
            .output_root_plan("manufacturing")
            .ok_or("PlanExecutor solid model output requires a top-level `manufacturing:` value")?
            .clone();
        if output.output_kind != "manufacturing"
            || !output.generic_output_port
            || !output.typed_contract_known
        {
            return Err(format!(
                "PlanExecutor manufacturing output root has unsupported contract kind={} generic={} typed={}",
                output.output_kind, output.generic_output_port, output.typed_contract_known
            )
            .into());
        }
        let statement = output.statement.as_ref().ok_or_else(|| {
            output.unsupported_reason.clone().unwrap_or_else(|| {
                "PlanExecutor manufacturing output root is not executable".to_owned()
            })
        })?;
        let value = self.eval_statement(statement, &mut frame)?;
        let value = self.resolve_solid_model_root_refs(value, &mut frame)?;
        let bundle = lower_solid_model_from_boon_value(&value)?;
        Ok(RuntimeSolidModelOutput {
            output_root: "manufacturing".to_owned(),
            bundle,
            read_count: frame.reads.len(),
        })
    }

    fn eval_statement(
        &mut self,
        statement: &RuntimeGenericStatement,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        frame.consume_budget()?;
        match statement {
            RuntimeGenericStatement::Empty => Ok(BoonValue::Empty),
            RuntimeGenericStatement::Expr(expr) => self.eval_expr(expr, frame),
            RuntimeGenericStatement::Binding { name, value } => {
                let value = self.eval_statement(value, frame)?;
                frame.env.insert(name.clone(), value.clone());
                Ok(value)
            }
            RuntimeGenericStatement::ExprWithChildren { expr, children } => {
                self.eval_expr_with_children(expr, children, frame)
            }
            RuntimeGenericStatement::Block(statements) => {
                self.eval_statement_block(statements, frame)
            }
            RuntimeGenericStatement::List(statements) => {
                let mut values = Vec::new();
                for statement in statements {
                    if self.statement_is_pipe_continuation(statement) {
                        continue;
                    }
                    let value = self.eval_statement(statement, frame)?;
                    if !matches!(value, BoonValue::Empty) {
                        values.push(value);
                    }
                }
                Ok(BoonValue::List(values))
            }
            RuntimeGenericStatement::Record(fields) => {
                let mut record = BTreeMap::new();
                for field in fields {
                    record.insert(
                        field.name.clone(),
                        self.eval_statement(&field.value, frame)?,
                    );
                }
                Ok(BoonValue::Record(record))
            }
            RuntimeGenericStatement::Latest(statements) => {
                for statement in statements {
                    let value = self.eval_statement(statement, frame)?;
                    if !matches!(value, BoonValue::Empty | BoonValue::Error(_)) {
                        return Ok(value);
                    }
                }
                Ok(BoonValue::Empty)
            }
        }
    }

    fn eval_statement_block(
        &mut self,
        statements: &[RuntimeGenericStatement],
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        let mut last = BoonValue::Empty;
        for statement in statements {
            if self.statement_is_pipe_continuation(statement) {
                last = self.eval_pipe_continuation_statement(statement, last, frame)?;
            } else {
                last = self.eval_statement(statement, frame)?;
            }
        }
        Ok(last)
    }

    fn eval_expr_with_children(
        &mut self,
        expr: &RuntimeGenericExpr,
        children: &[RuntimeGenericStatement],
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        match expr {
            RuntimeGenericExpr::Identifier(name) if name == "BLOCK" => {
                self.eval_statement_block(children, frame)
            }
            RuntimeGenericExpr::Call { function, args }
                if runtime_generic_constructor_accepts_children(function) =>
            {
                let value = self.eval_call(function, args, None, frame)?;
                self.eval_constructor_children(value, children, frame)
            }
            _ => self.eval_expr(expr, frame),
        }
    }

    fn eval_constructor_children(
        &mut self,
        value: BoonValue,
        children: &[RuntimeGenericStatement],
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        let BoonValue::Record(mut record) = value else {
            return Ok(value);
        };
        for child in children {
            if self.statement_is_pipe_continuation(child) {
                continue;
            }
            match child {
                RuntimeGenericStatement::Binding { name, value } => {
                    record.insert(name.clone(), self.eval_statement(value, frame)?);
                }
                _ => {
                    let value = self.eval_statement(child, frame)?;
                    if !matches!(value, BoonValue::Empty) {
                        record.insert(format!("child_{}", record.len()), value);
                    }
                }
            }
        }
        Ok(BoonValue::Record(record))
    }

    fn eval_expr(
        &mut self,
        expr: &RuntimeGenericExpr,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        frame.consume_budget()?;
        match expr {
            RuntimeGenericExpr::Identifier(name) => self.eval_identifier(name, frame),
            RuntimeGenericExpr::Path(parts) => self.eval_path(parts, frame),
            RuntimeGenericExpr::Text(value) => Ok(BoonValue::Text(value.clone())),
            RuntimeGenericExpr::Number(value) => Ok(BoonValue::Number(*value)),
            RuntimeGenericExpr::NaN => Ok(BoonValue::NaN),
            RuntimeGenericExpr::Bool(value) => Ok(BoonValue::Bool(*value)),
            RuntimeGenericExpr::Enum(value) => Ok(BoonValue::Enum(value.clone())),
            RuntimeGenericExpr::TaggedObject { tag, fields } => {
                let mut body = Vec::new();
                for field in fields {
                    if field.spread {
                        continue;
                    }
                    let value = self.eval_expr(&field.value, frame)?;
                    body.push(format!("{}:{}", field.name, boon_value_scalar_text(&value)));
                }
                Ok(BoonValue::Text(format!("{tag}[{}]", body.join(","))))
            }
            RuntimeGenericExpr::Call { function, args } => {
                self.eval_call(function, args, None, frame)
            }
            RuntimeGenericExpr::Pipe { input, op, args } => {
                let input = if matches!(input.as_ref(), RuntimeGenericExpr::Delimiter) {
                    BoonValue::Empty
                } else {
                    self.eval_expr(input, frame)?
                };
                self.eval_call(op, args, Some(input), frame)
            }
            RuntimeGenericExpr::Infix { left, op, right } => {
                let left = self.eval_expr(left, frame)?;
                let right = self.eval_expr(right, frame)?;
                Ok(generic_infix_value(left, op, right))
            }
            RuntimeGenericExpr::Record(fields) => self.eval_record_expr(fields, frame),
            RuntimeGenericExpr::List(items) => {
                let mut values = Vec::with_capacity(items.len());
                for item in items {
                    values.push(self.eval_expr(item, frame)?);
                }
                Ok(BoonValue::List(values))
            }
            RuntimeGenericExpr::Bytes { size, items } => {
                let mut bytes = Vec::with_capacity(items.len());
                for item in items {
                    push_bytes_constructor_value(&mut bytes, self.eval_expr(item, frame)?)?;
                }
                finish_bytes_constructor(size, items.len(), bytes)
            }
            RuntimeGenericExpr::Then { input, output } => {
                let input = self.eval_expr(input, frame)?;
                if matches!(input, BoonValue::Empty | BoonValue::Error(_)) {
                    return Ok(BoonValue::Empty);
                }
                output
                    .as_deref()
                    .map(|output| self.eval_expr(output, frame))
                    .unwrap_or(Ok(input))
            }
            RuntimeGenericExpr::When { .. }
            | RuntimeGenericExpr::MatchArm { .. }
            | RuntimeGenericExpr::Delimiter => Ok(BoonValue::Empty),
        }
    }

    fn eval_record_expr(
        &mut self,
        fields: &[RuntimeGenericRecordExprField],
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        let mut record = BTreeMap::new();
        for field in fields {
            let value = self.eval_expr(&field.value, frame)?;
            if field.spread {
                match value {
                    BoonValue::Record(fields) => record.extend(fields),
                    BoonValue::RecordColumns(columns) => {
                        record.extend(boon_record_from_value_columns(&columns));
                    }
                    BoonValue::Empty => {}
                    _ => return Ok(BoonValue::Error("type_error".to_owned())),
                }
            } else {
                record.insert(field.name.clone(), value);
            }
        }
        Ok(BoonValue::Record(record))
    }

    fn eval_call(
        &mut self,
        function: &str,
        args: &[RuntimeGenericArg],
        input: Option<BoonValue>,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        if is_generic_render_constructor(function)
            || is_generic_world_constructor(function)
            || is_generic_solid_constructor(function)
            || is_light_constructor(function)
        {
            return self.eval_constructor(function, args, input, frame);
        }
        if bytes_runtime_builtin(function) {
            let args = args
                .iter()
                .map(|arg| {
                    Ok(EvaluatedCallArg {
                        name: arg.name.clone(),
                        value: self.eval_expr(&arg.value, frame)?,
                    })
                })
                .collect::<RuntimeResult<Vec<_>>>()?;
            return eval_bytes_builtin(function, input, &args);
        }
        if let Some(definition) = self.generic_output_plan.function(function).cloned() {
            return self.eval_user_function(&definition, args, input, frame);
        }
        match function {
            "SOURCE" => self.call_input_or_first(input, args, frame),
            "Text/empty" => Ok(BoonValue::Text(String::new())),
            "Text/concat" => {
                let left = self.call_input_or_first(input, args, frame)?;
                let right = self.named_or_positional_arg_value(args, "with", 0, frame)?;
                let separator = self
                    .named_arg_value(args, "separator", frame)
                    .map(BoonValue::into_text_or_default)
                    .unwrap_or_default();
                Ok(BoonValue::Text(format!(
                    "{}{}{}",
                    left.into_text_or_default(),
                    separator,
                    right.into_text_or_default()
                )))
            }
            "List/range" => {
                let from = self
                    .named_arg_value(args, "from", frame)?
                    .number()
                    .unwrap_or(0);
                let to = self
                    .named_arg_value(args, "to", frame)?
                    .number()
                    .unwrap_or(-1);
                Ok(BoonValue::List(if from <= to {
                    (from..=to).map(BoonValue::Number).collect()
                } else {
                    Vec::new()
                }))
            }
            _ => Ok(BoonValue::Error("parse_error".to_owned())),
        }
    }

    fn eval_constructor(
        &mut self,
        function: &str,
        args: &[RuntimeGenericArg],
        input: Option<BoonValue>,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        let mut record = BTreeMap::new();
        record.insert(
            "kind".to_owned(),
            BoonValue::Text(generic_constructor_kind(function).to_owned()),
        );
        record.insert(
            "constructor".to_owned(),
            BoonValue::Text(function.to_owned()),
        );
        if let Some(input) = input {
            record.insert("input".to_owned(), input);
        }
        for (index, arg) in args.iter().enumerate() {
            let value = self.eval_expr(&arg.value, frame)?;
            let name = arg.name.clone().unwrap_or_else(|| format!("arg_{index}"));
            record.insert(name, value);
        }
        Ok(BoonValue::Record(record))
    }

    fn eval_user_function(
        &mut self,
        definition: &RuntimeGenericFunction,
        args: &[RuntimeGenericArg],
        input: Option<BoonValue>,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        if frame.call_depth > 128 {
            return Err(format!(
                "generic output function `{}` call budget exhausted",
                definition.name
            )
            .into());
        }
        let mut child = frame.child();
        child.call_depth += 1;
        if let Some(input) = input
            && let Some(first) = definition.args.first()
        {
            child.env.insert(first.clone(), input);
        }
        for (position, arg) in args.iter().enumerate() {
            let value = self.eval_expr(&arg.value, frame)?;
            let name = arg
                .name
                .clone()
                .or_else(|| definition.args.get(position).cloned())
                .ok_or_else(|| {
                    format!(
                        "generic output function `{}` has too many arguments",
                        definition.name
                    )
                })?;
            child.env.insert(name, value);
        }
        let value = self.eval_statement(&definition.statement, &mut child)?;
        frame.reads.extend(child.reads);
        Ok(value)
    }

    fn eval_identifier(
        &mut self,
        name: &str,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        if let Some(value) = frame.env.get(name) {
            return Ok(value.clone());
        }
        if let Some(value) = self.root_value(name) {
            frame.reads.insert(GenericReadKey::Root {
                field: name.to_owned(),
            });
            return Ok(value);
        }
        if let Some(value) = self.root_derived_boon_value(name, frame)? {
            return Ok(value);
        }
        if let Some(value) = self.list_value(name, frame) {
            return Ok(value);
        }
        Ok(BoonValue::Enum(name.to_owned()))
    }

    fn eval_path(
        &mut self,
        parts: &[String],
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        let Some((first, rest)) = parts.split_first() else {
            return Ok(BoonValue::Empty);
        };
        let mut value = self.eval_identifier(first, frame)?;
        for part in rest {
            value = match value {
                BoonValue::Record(fields) => fields.get(part).cloned().unwrap_or(BoonValue::Empty),
                BoonValue::RecordColumns(columns) => columns
                    .value_ref_id(&FieldSlotId::from_path(part))
                    .map(field_ref_to_boon)
                    .unwrap_or(BoonValue::Empty),
                _ => BoonValue::Empty,
            };
        }
        Ok(value)
    }

    fn root_value(&self, path: &str) -> Option<BoonValue> {
        if let Some(value) = self.root_state.get(path) {
            return Some(json_to_boon_value(value));
        }
        let root = JsonValue::Object(self.root_state.clone());
        runtime_value_at_path(&root, path).map(json_to_boon_value)
    }

    fn root_derived_boon_value(
        &mut self,
        path: &str,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<Option<BoonValue>> {
        if frame.root_stack.iter().any(|active| active == path) {
            return Ok(Some(BoonValue::Error("cycle".to_owned())));
        }
        let Some(plan) = self.generic_output_plan.root_field_plan(path).cloned() else {
            return Ok(None);
        };
        let Some(statement) = plan.statement else {
            return Err(plan
                .unsupported_reason
                .unwrap_or_else(|| {
                    format!("PlanExecutor output root field `{path}` is not executable")
                })
                .into());
        };
        frame.root_stack.push(path.to_owned());
        let value = self.eval_statement(&statement, frame)?;
        frame.root_stack.pop();
        Ok(Some(value))
    }

    fn list_value(&self, name: &str, frame: &mut GenericEvalFrame) -> Option<BoonValue> {
        let list_id = self.plan.debug_map.list_slots.iter().find_map(|entry| {
            if entry.label != name {
                return None;
            }
            entry
                .id
                .parse::<usize>()
                .ok()
                .or_else(|| entry.id.rsplit(':').next()?.parse::<usize>().ok())
        })?;
        let rows = self.list_state.get(&list_id)?;
        frame.reads.insert(GenericReadKey::ListColumn {
            list: name.to_owned(),
            field: "*".to_owned(),
        });
        Some(BoonValue::List(
            rows.iter()
                .map(|row| {
                    BoonValue::Record(
                        row.fields
                            .iter()
                            .map(|(field, value)| (field.clone(), json_to_boon_value(value)))
                            .collect(),
                    )
                })
                .collect(),
        ))
    }

    fn resolve_solid_model_root_refs(
        &mut self,
        value: BoonValue,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        match value {
            BoonValue::Record(mut fields) => {
                for key in ["geometry", "base", "child"] {
                    if let Some(referenced) =
                        fields.get(key).and_then(solid_model_structural_ref_name)
                        && let Some(resolved) = self.root_derived_boon_value(&referenced, frame)?
                    {
                        fields.insert(
                            key.to_owned(),
                            self.resolve_solid_model_root_refs(resolved, frame)?,
                        );
                    }
                }
                if let Some(BoonValue::List(values)) = fields.remove("tools") {
                    let values = values
                        .into_iter()
                        .map(|value| self.resolve_solid_model_root_refs(value, frame))
                        .collect::<RuntimeResult<Vec<_>>>()?;
                    fields.insert("tools".to_owned(), BoonValue::List(values));
                }
                Ok(BoonValue::Record(fields))
            }
            BoonValue::List(values) => Ok(BoonValue::List(
                values
                    .into_iter()
                    .map(|value| self.resolve_solid_model_root_refs(value, frame))
                    .collect::<RuntimeResult<Vec<_>>>()?,
            )),
            other => Ok(other),
        }
    }

    fn call_input_or_first(
        &mut self,
        input: Option<BoonValue>,
        args: &[RuntimeGenericArg],
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        match input {
            Some(value) => Ok(value),
            None => args
                .first()
                .ok_or_else(|| "generic output call requires an input argument".into())
                .and_then(|arg| self.eval_expr(&arg.value, frame)),
        }
    }

    fn named_arg_value(
        &mut self,
        args: &[RuntimeGenericArg],
        name: &str,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        let arg = args
            .iter()
            .find(|arg| arg.name.as_deref() == Some(name))
            .ok_or_else(|| format!("generic output call requires `{name}`"))?;
        self.eval_expr(&arg.value, frame)
    }

    fn named_or_positional_arg_value(
        &mut self,
        args: &[RuntimeGenericArg],
        name: &str,
        position: usize,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        if let Some(arg) = args.iter().find(|arg| arg.name.as_deref() == Some(name)) {
            return self.eval_expr(&arg.value, frame);
        }
        let arg = args
            .iter()
            .filter(|arg| arg.name.is_none())
            .nth(position)
            .ok_or_else(|| format!("generic output call requires `{name}`"))?;
        self.eval_expr(&arg.value, frame)
    }

    fn statement_is_pipe_continuation(&self, statement: &RuntimeGenericStatement) -> bool {
        match statement {
            RuntimeGenericStatement::Expr(expr)
            | RuntimeGenericStatement::ExprWithChildren { expr, .. } => {
                runtime_generic_expr_is_pipe_continuation(expr)
            }
            _ => false,
        }
    }

    fn eval_pipe_continuation_statement(
        &mut self,
        statement: &RuntimeGenericStatement,
        input: BoonValue,
        frame: &mut GenericEvalFrame,
    ) -> RuntimeResult<BoonValue> {
        match statement {
            RuntimeGenericStatement::Expr(RuntimeGenericExpr::Pipe { op, args, .. })
            | RuntimeGenericStatement::ExprWithChildren {
                expr: RuntimeGenericExpr::Pipe { op, args, .. },
                ..
            } => self.eval_call(op, args, Some(input), frame),
            _ => Ok(input),
        }
    }
}

fn plan_executor_step_report_to_live_turn_output(
    step_report: &JsonValue,
    apply_step_ms: f64,
) -> RuntimeResult<LiveTurnOutput> {
    let semantic_deltas = step_report
        .get("semantic_deltas")
        .and_then(JsonValue::as_array)
        .map(|deltas| {
            deltas
                .iter()
                .map(plan_json_semantic_delta_to_typed)
                .collect::<RuntimeResult<Vec<_>>>()
        })
        .transpose()?
        .unwrap_or_default();
    let dirty_key_count = step_report
        .get("touched_state_summary")
        .and_then(JsonValue::as_object)
        .map_or(0, serde_json::Map::len);
    let executed_update_branch_count = step_report
        .get("executed_update_branch_count")
        .and_then(JsonValue::as_u64)
        .unwrap_or(0) as usize;
    let executed_indexed_update_count = step_report
        .get("executed_indexed_update_count")
        .and_then(JsonValue::as_u64)
        .unwrap_or(0) as usize;
    let executed_derived_value_count = step_report
        .get("executed_derived_value_count")
        .and_then(JsonValue::as_u64)
        .unwrap_or(0) as usize;
    Ok(LiveTurnOutput {
        semantic_deltas,
        render_patches: Vec::new(),
        apply_step_ms,
        runtime_step_profile: LiveRuntimeStepProfile::default(),
        dirty_key_count,
        recomputed_field_count: executed_update_branch_count
            .saturating_add(executed_indexed_update_count)
            .saturating_add(executed_derived_value_count),
        recompute_candidate_count: executed_update_branch_count
            .saturating_add(executed_indexed_update_count),
        list_scan_counters: LiveRuntimeListScanCounters::default(),
        source_route_scan_summary: LiveRuntimeSourceRouteScanSummary::default(),
        root_materialization_stats: LiveRuntimeRootMaterializationStats::default(),
        function_call_stats: LiveRuntimeFunctionCallStats::default(),
        recompute_candidate_samples: Vec::new(),
        recomputed_field_samples: Vec::new(),
    })
}

fn plan_json_semantic_delta_to_typed(delta: &JsonValue) -> RuntimeResult<SemanticDelta<'static>> {
    let object = delta
        .as_object()
        .ok_or("PlanExecutor semantic delta must be a JSON object")?;
    let kind = object
        .get("kind")
        .and_then(JsonValue::as_str)
        .ok_or("PlanExecutor semantic delta is missing `kind`")?;
    Ok(SemanticDelta {
        kind: plan_semantic_delta_kind(kind)?,
        list_id: plan_optional_cow_string(object.get("list_id")),
        key: object.get("key").and_then(JsonValue::as_u64),
        generation: object.get("generation").and_then(JsonValue::as_u64),
        source_id: object.get("source_id").and_then(JsonValue::as_u64),
        bind_epoch: object.get("bind_epoch").and_then(JsonValue::as_u64),
        field_path: plan_optional_cow_string(object.get("field_path")),
        value: plan_json_protocol_value(
            object
                .get("value")
                .ok_or("PlanExecutor semantic delta is missing `value`")?,
        ),
    })
}

fn plan_semantic_delta_kind(kind: &str) -> RuntimeResult<&'static str> {
    match kind {
        "FieldSet" => Ok("FieldSet"),
        "ListInsert" => Ok("ListInsert"),
        "ListRemove" => Ok("ListRemove"),
        "ListMove" => Ok("ListMove"),
        "SourceBind" => Ok("SourceBind"),
        "SourceUnbind" => Ok("SourceUnbind"),
        other => Err(format!("unsupported PlanExecutor semantic delta kind `{other}`").into()),
    }
}

fn plan_optional_cow_string(value: Option<&JsonValue>) -> Option<Cow<'static, str>> {
    value
        .and_then(JsonValue::as_str)
        .map(|value| Cow::Owned(value.to_owned()))
}

fn plan_json_protocol_value(value: &JsonValue) -> ProtocolValue<'static> {
    match value {
        JsonValue::Null => ProtocolValue::Null,
        JsonValue::Bool(value) => ProtocolValue::Bool(*value),
        JsonValue::String(value) => ProtocolValue::Text(Cow::Owned(value.clone())),
        JsonValue::Number(value) => value
            .as_i64()
            .map(ProtocolValue::NumberText)
            .unwrap_or_else(|| ProtocolValue::Text(Cow::Owned(value.to_string()))),
        JsonValue::Array(_) => ProtocolValue::Bytes(value.clone()),
        JsonValue::Object(object) => {
            if let Some(checked) = object.get("checked").and_then(JsonValue::as_bool) {
                return ProtocolValue::CheckedProperty(checked);
            }
            if let (Some(source_path), Some(source_id), Some(bind_epoch)) = (
                object.get("source_path").and_then(JsonValue::as_str),
                object.get("source_id").and_then(JsonValue::as_u64),
                object.get("bind_epoch").and_then(JsonValue::as_u64),
            ) {
                return ProtocolValue::SourceBinding {
                    source_path: Cow::Owned(source_path.to_owned()),
                    source_id,
                    bind_epoch,
                };
            }
            ProtocolValue::Bytes(value.clone())
        }
    }
}

pub fn execute_machine_plan_initial_state(
    plan: &MachinePlan,
) -> RuntimeResult<PlanInitialStateOutput> {
    let output = execute_machine_plan_initial_state_inner(plan)?;
    Ok(PlanInitialStateOutput {
        plan_hash: output.plan_hash,
        state_summary: output.state_summary,
        report: output.executor_report,
    })
}

fn execute_machine_plan_initial_state_inner(
    plan: &MachinePlan,
) -> RuntimeResult<InitialStateExecution> {
    let core_execution = execute_plan_initial_state_core(plan)?;
    let initialized_state_count = core_execution.initialized_state_count;
    let source_route_metadata_count = core_execution.source_route_metadata_count;
    let mut list_state = plan_initial_list_state(plan)?;
    let plan_hash = core_execution.plan_hash;
    let state_summary = core_execution.state_summary;
    refresh_plan_initial_list_state_with_root_context(
        plan,
        state_summary.as_object().unwrap(),
        &mut list_state,
    )?;
    let list_summary = plan_list_summary(plan, &list_state);
    let projection_execution =
        materialize_plan_list_projections(plan, state_summary.as_object().unwrap(), &list_state)?;
    let retain_execution =
        materialize_plan_list_retains(plan, state_summary.as_object().unwrap(), &list_state)?;
    let list_projection_summary = JsonValue::Object(projection_execution.summary);
    let list_view_summary = JsonValue::Object(retain_execution.summary);
    let report_assembly = assemble_plan_initial_state_report(
        plan,
        initialized_state_count,
        source_route_metadata_count,
        projection_execution.executed_count,
        projection_execution.find_count,
        projection_execution.chunk_count,
        projection_execution.projected_row_count,
        retain_execution.executed_count,
        retain_execution.view_count,
        retain_execution.retained_row_count,
        &state_summary,
        &core_execution.executor_report,
        &list_summary,
        &list_projection_summary,
        &projection_execution.reports,
        &list_view_summary,
        &retain_execution.reports,
    );
    Ok(InitialStateExecution {
        plan_hash,
        state_summary: state_summary.clone(),
        executor_report: report_assembly.executor_report,
    })
}

fn execute_machine_plan_root_scenario_inner(
    plan: &MachinePlan,
    selected_steps: &[&ScenarioStep],
    host_file_root: Option<&Path>,
) -> RuntimeResult<RootScenarioExecution> {
    let _bytes_counter_guard = runtime_bytes_storage_counter_measurement_lock()
        .lock()
        .unwrap_or_else(|poisoned| poisoned.into_inner());
    let verification = verify_plan(plan)?;
    if verification.status != "pass" {
        return Err(format!(
            "MachinePlan verification failed with {} error(s)",
            verification.error_count
        )
        .into());
    }
    let mut runtime = PlanExecutorRuntimeState::new(plan)?;
    for step in selected_steps {
        runtime.apply_step(plan, step, host_file_root)?;
    }
    runtime.finish(plan)
}

fn assert_plan_executor_scenario_checkpoint(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
    step: &ScenarioStep,
) -> RuntimeResult<JsonValue> {
    let mut checkpoint_list_state = list_state.clone();
    if step.expect_cell.is_some() || step.expect_error.is_some() {
        let _ = refresh_all_indexed_derived_fields(plan, &mut checkpoint_list_state)?;
    }
    let list_state = plan_executor_list_state_for_materialization(&checkpoint_list_state);
    let report = assert_plan_scenario_checkpoint(
        plan,
        root_state,
        &list_state,
        PlanExecutorScenarioCheckpointInput {
            step_id: step.id.clone(),
            source_intent_exemption: step.source_intent_exemption.clone(),
            semantic_delta_expectation_count: step.expect_semantic_delta_contains.len(),
            render_delta_expectation_count: step.expect_render_delta_contains.len(),
            expect_titles: step.expect_titles.clone(),
            expect_visible_titles: step.expect_visible_titles.clone(),
            expect_completed_titles: step.expect_completed_titles.clone(),
            expect_active_count: step.expect_active_count,
            expect_completed_count: step.expect_completed_count,
            expect_filter: step.expect_filter.clone(),
            expect_new_text: step.expect_new_text.clone(),
            expect_editing_title: step.expect_editing_title.clone(),
            expect_edit_text: step.expect_edit_text.clone(),
            expect_no_editing: step.expect_no_editing,
            expect_cell: step.expect_cell.as_ref().map(|expect| {
                PlanExecutorScenarioCheckpointCellExpectation {
                    address: expect.address.clone(),
                    value: expect.value.clone(),
                    formula: expect.formula.clone(),
                    editing_text: expect.editing_text.clone(),
                    editing: expect.editing,
                }
            }),
            expect_error: step.expect_error.as_ref().map(|expect| {
                PlanExecutorScenarioCheckpointErrorExpectation {
                    address: expect.address.clone(),
                    error: expect.error.clone(),
                }
            }),
            expect_recomputed_present: step.expect_recomputed.is_some(),
            expect_root_text: step.expect_root_text.clone(),
        },
    )?;
    Ok(report.report)
}

