fn plan_executor_document_summary_with_limits(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    limits: SummaryLimits,
) -> JsonValue {
    let summary_root_state = plan_executor_summary_root_state(plan, root_state);
    let mut root = plan_executor_nested_root_summary(&summary_root_state);
    let mut materialization = Vec::new();
    plan_executor_insert_direct_list_summaries(
        plan,
        &summary_root_state,
        list_state,
        limits,
        &mut root,
        &mut materialization,
    );
    plan_executor_insert_root_row_expression_summaries(
        plan,
        &summary_root_state,
        list_state,
        limits,
        &mut root,
        &mut materialization,
    );
    plan_executor_insert_projection_summaries(
        plan,
        &summary_root_state,
        list_state,
        limits,
        &mut root,
        &mut materialization,
    );
    plan_executor_insert_retain_summaries(
        plan,
        &summary_root_state,
        list_state,
        limits,
        &mut root,
        &mut materialization,
    );
    root.insert(
        "source_binding_count".to_owned(),
        json!(plan_executor_source_binding_count(plan, list_state)),
    );
    if !materialization.is_empty() {
        root.insert(
            "__boon_materialization".to_owned(),
            JsonValue::Array(materialization),
        );
    }
    JsonValue::Object(root)
}

fn plan_executor_insert_root_row_expression_summaries(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
    limits: SummaryLimits,
    root: &mut serde_json::Map<String, JsonValue>,
    materialization: &mut Vec<JsonValue>,
) {
    let root_eval_row = plan_executor_root_eval_row(root_state);
    for op in plan
        .regions
        .iter()
        .filter(|region| region.kind == RegionKind::DerivedEvaluation)
        .flat_map(|region| region.ops.iter())
    {
        if op.indexed {
            continue;
        }
        let Some(ValueRef::Field(output_id)) = op.output else {
            continue;
        };
        let PlanOpKind::DerivedValue {
            derived_kind,
            expression: Some(PlanDerivedExpression::RowExpression { expression }),
            ..
        } = &op.kind
        else {
            continue;
        };
        if !matches!(
            derived_kind,
            boon_plan::PlanDerivedKind::Pure | boon_plan::PlanDerivedKind::ListView
        ) {
            continue;
        }
        let target = plan_derived_field_label(plan, output_id.0);
        let value = if let Some(value) = root_state.get(&target).cloned() {
            value
        } else {
            let Ok(value) = eval_plan_row_expression(plan, list_state, &root_eval_row, expression)
            else {
                continue;
            };
            value
        };
        let value = plan_executor_document_summary_value(value);
        if let Some(rows) = value.as_array() {
            let row_count = rows.len();
            let row_end = limits
                .list_rows
                .map_or(row_count, |limit| {
                    limits.list_row_start.saturating_add(limit)
                })
                .min(row_count);
            let windowed = rows
                .get(limits.list_row_start..row_end)
                .unwrap_or(&[])
                .to_vec();
            materialization.push(materialization_report_for_rows(
                &target,
                row_count,
                limits.list_row_start,
                &windowed,
            ));
            let value = JsonValue::Array(windowed);
            insert_nested_json(root, &target, value.clone());
            root.entry(row_field_name(&target).to_owned())
                .or_insert(value);
        } else {
            insert_nested_json(root, &target, value.clone());
            root.entry(row_field_name(&target).to_owned())
                .or_insert(value);
        }
    }
}

fn plan_executor_root_eval_row(
    root_state: &serde_json::Map<String, JsonValue>,
) -> PlanListRowState {
    let mut fields = BTreeMap::new();
    for (path, value) in root_state {
        fields.insert(path.clone(), value.clone());
        fields
            .entry(local_field_name(path).to_owned())
            .or_insert_with(|| value.clone());
    }
    PlanListRowState {
        key: 0,
        generation: 0,
        fields,
        private_bytes: BTreeMap::new(),
        fixed_bytes_banks: BTreeMap::new(),
    }
}

fn plan_executor_document_summary_value(value: JsonValue) -> JsonValue {
    match value {
        JsonValue::Array(items) => JsonValue::Array(
            items
                .into_iter()
                .map(plan_executor_document_summary_value)
                .collect(),
        ),
        JsonValue::Object(object) => {
            let mut output = serde_json::Map::new();
            for (field, value) in object {
                insert_nested_json(
                    &mut output,
                    &field,
                    plan_executor_document_summary_value(value),
                );
            }
            JsonValue::Object(output)
        }
        value => value,
    }
}

fn plan_executor_summary_root_state(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
) -> serde_json::Map<String, JsonValue> {
    let mut summary = root_state.clone();
    if let Ok(derived_values) = evaluate_plan_initial_root_derived_values_partial(plan, &summary) {
        let source_event_fields = plan_source_event_transform_fields(plan);
        for (field_id, value) in derived_values {
            let field_path = plan_derived_field_label(plan, field_id.0);
            if source_event_fields.contains(&field_id) && summary.contains_key(&field_path) {
                continue;
            }
            summary.insert(field_path, value);
        }
    }
    summary
}

fn plan_source_event_transform_fields(plan: &MachinePlan) -> BTreeSet<FieldId> {
    plan.regions
        .iter()
        .filter(|region| region.kind == RegionKind::DerivedEvaluation)
        .flat_map(|region| region.ops.iter())
        .filter_map(|op| {
            let PlanOpKind::DerivedValue {
                derived_kind: boon_plan::PlanDerivedKind::SourceEventTransform,
                ..
            } = &op.kind
            else {
                return None;
            };
            let Some(ValueRef::Field(field_id)) = op.output else {
                return None;
            };
            Some(field_id)
        })
        .collect()
}

fn refresh_plan_initial_list_state_with_root_context(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
) -> RuntimeResult<()> {
    let summary_root_state = plan_executor_summary_root_state(plan, root_state);
    refresh_plan_startup_list_row_fields_for_all_lists_with(
        plan,
        list_state,
        |plan, list_state, row, expression| {
            let row = plan_executor_row_with_root_values(plan, row, &summary_root_state);
            eval_plan_row_expression(plan, list_state, &row, expression)
        },
    )?;
    Ok(())
}

fn plan_executor_nested_root_summary(
    root_state: &serde_json::Map<String, JsonValue>,
) -> serde_json::Map<String, JsonValue> {
    let mut root = serde_json::Map::new();
    for (path, value) in root_state {
        insert_nested_json(&mut root, path, value.clone());
        root.entry(row_field_name(path).to_owned())
            .or_insert_with(|| value.clone());
    }
    root
}

fn plan_executor_insert_direct_list_summaries(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    limits: SummaryLimits,
    root: &mut serde_json::Map<String, JsonValue>,
    materialization: &mut Vec<JsonValue>,
) {
    let list_ids = list_state.keys().copied().collect::<Vec<_>>();
    for list_id in list_ids {
        let list = plan_list_label(plan, list_id);
        let row_count = list_state.get(&list_id).map(Vec::len).unwrap_or_default();
        let row_end = limits
            .list_rows
            .map_or(row_count, |limit| {
                limits.list_row_start.saturating_add(limit)
            })
            .min(row_count);
        let mut visible_rows = Vec::with_capacity(row_end.saturating_sub(limits.list_row_start));
        for row_index in limits.list_row_start..row_end {
            plan_executor_refresh_summary_row_current(
                plan, root_state, list_state, list_id, row_index,
            );
            if let Some(row) = list_state
                .get(&list_id)
                .and_then(|rows| rows.get(row_index))
            {
                visible_rows.push(plan_executor_row_document_json(plan, list_id, row));
            }
        }
        materialization.push(materialization_report_for_rows(
            &list,
            row_count,
            limits.list_row_start,
            &visible_rows,
        ));
        let value = JsonValue::Array(visible_rows);
        if let Some(store) = root
            .get_mut("store")
            .and_then(serde_json::Value::as_object_mut)
        {
            store.entry(list.clone()).or_insert(value.clone());
        }
        root.entry(list).or_insert(value);
    }
}

fn plan_executor_insert_projection_summaries(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    limits: SummaryLimits,
    root: &mut serde_json::Map<String, JsonValue>,
    materialization: &mut Vec<JsonValue>,
) {
    for op in plan
        .regions
        .iter()
        .filter(|region| region.kind == RegionKind::ListProjections)
        .flat_map(|region| region.ops.iter())
    {
        let PlanOpKind::ListProjection { projection } = &op.kind else {
            continue;
        };
        let Some(ValueRef::Field(target_field_id)) = op.output else {
            continue;
        };
        let target = plan_derived_field_label(plan, target_field_id.0);
        match projection {
            PlanListProjection::Find {
                source_list,
                field,
                value,
            } => {
                let selector = plan_executor_projection_selector_value(plan, root_state, value);
                let rows = list_state
                    .get(&source_list.0)
                    .map(Vec::as_slice)
                    .unwrap_or(&[]);
                let row_index = rows
                    .iter()
                    .position(|row| row_json_values_equal(row.fields.get(field), &selector));
                let projected = row_index
                    .and_then(|row_index| {
                        plan_executor_refresh_summary_row_current(
                            plan,
                            root_state,
                            list_state,
                            source_list.0,
                            row_index,
                        );
                        list_state
                            .get(&source_list.0)
                            .and_then(|rows| rows.get(row_index))
                            .map(|row| plan_executor_row_document_json(plan, source_list.0, row))
                    })
                    .unwrap_or(JsonValue::Null);
                insert_nested_json(root, &target, projected.clone());
                root.entry(row_field_name(&target).to_owned())
                    .or_insert(projected);
            }
            PlanListProjection::Chunk {
                source_list,
                size,
                item_field,
                label_field,
            } => {
                let source_row_count = list_state
                    .get(&source_list.0)
                    .map(Vec::len)
                    .unwrap_or_default();
                let value = plan_executor_windowed_chunk_projection(
                    plan,
                    root_state,
                    source_list.0,
                    list_state,
                    *size,
                    item_field,
                    label_field,
                    limits,
                );
                materialization.push(materialization_report_for_chunk(
                    &target,
                    source_row_count,
                    limits.chunk_row_start,
                    limits.chunk_column_start,
                    &value,
                ));
                insert_nested_json(root, &target, JsonValue::Array(value));
            }
            PlanListProjection::Unknown { .. } => {}
        }
    }
}

fn plan_executor_insert_retain_summaries(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    limits: SummaryLimits,
    root: &mut serde_json::Map<String, JsonValue>,
    materialization: &mut Vec<JsonValue>,
) {
    let Ok(retain_execution) = materialize_plan_list_retains(plan, root_state, list_state) else {
        return;
    };
    for (target, summary) in retain_execution.summary {
        let source_list_id = summary
            .get("source_list_id")
            .and_then(JsonValue::as_u64)
            .map(|value| value as usize);
        let all_rows = summary
            .get("rows")
            .and_then(JsonValue::as_array)
            .cloned()
            .unwrap_or_default()
            .into_iter()
            .map(|row| plan_executor_retained_row_document_json(plan, source_list_id, &row))
            .collect::<Vec<_>>();
        let row_end = limits
            .list_rows
            .map_or(all_rows.len(), |limit| {
                limits.list_row_start.saturating_add(limit)
            })
            .min(all_rows.len());
        let rows = all_rows
            .get(limits.list_row_start..row_end)
            .unwrap_or(&[])
            .to_vec();
        materialization.push(materialization_report_for_rows(
            &target,
            all_rows.len(),
            limits.list_row_start,
            &rows,
        ));
        let value = JsonValue::Array(rows);
        insert_nested_json(root, &target, value.clone());
        root.entry(row_field_name(&target).to_owned())
            .or_insert(value);
    }
}

fn plan_executor_windowed_chunk_projection(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_id: usize,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    columns: usize,
    item_field: &str,
    label_field: &str,
    limits: SummaryLimits,
) -> Vec<JsonValue> {
    if columns == 0 {
        return Vec::new();
    }
    let row_count = list_state.get(&list_id).map(Vec::len).unwrap_or_default();
    let total_rows = row_count.div_ceil(columns);
    let row_end = limits
        .chunk_rows
        .map_or(total_rows, |limit| {
            limits.chunk_row_start.saturating_add(limit)
        })
        .min(total_rows);
    let projected_columns = limits.chunk_columns.map_or_else(
        || columns.saturating_sub(limits.chunk_column_start),
        |limit| columns.saturating_sub(limits.chunk_column_start).min(limit),
    );
    let mut projected_rows = Vec::with_capacity(row_end.saturating_sub(limits.chunk_row_start));
    for row in limits.chunk_row_start..row_end {
        let mut row_object = serde_json::Map::new();
        row_object.insert(label_field.to_owned(), json!(row.to_string()));
        row_object.insert("index".to_owned(), json!(row));
        let mut cells = Vec::with_capacity(projected_columns);
        for column_offset in 0..projected_columns {
            let column = limits.chunk_column_start.saturating_add(column_offset);
            let index = row.saturating_mul(columns).saturating_add(column);
            if index >= row_count {
                break;
            }
            plan_executor_refresh_summary_row_current(plan, root_state, list_state, list_id, index);
            if let Some(cell) = list_state.get(&list_id).and_then(|rows| rows.get(index)) {
                cells.push(plan_executor_row_document_json(plan, list_id, cell));
            }
        }
        row_object.insert(item_field.to_owned(), JsonValue::Array(cells));
        projected_rows.push(JsonValue::Object(row_object));
    }
    projected_rows
}

fn plan_executor_refresh_summary_row_current(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    list_id: usize,
    row_index: usize,
) {
    let Some(list_slot) = plan
        .storage_layout
        .list_slots
        .iter()
        .find(|slot| slot.list_id.0 == list_id)
        .cloned()
    else {
        return;
    };
    let list_label = plan_list_label(plan, list_id);
    refresh_indexed_derived_fields_for_row_with_options(
        plan,
        &list_slot,
        &list_label,
        list_state,
        row_index,
        IndexedDerivedRefreshOptions {
            suppress_recursive_cycle_values: false,
            sort_cycle_error_first: true,
            evaluate_demand_current_ops: true,
            emit_demand_current_deltas: false,
            changed_root_states: None,
            root_state: Some(root_state),
        },
    )
    .expect("PlanExecutor document summary currentness refresh failed");
}

fn plan_executor_row_document_json(
    plan: &MachinePlan,
    list_id: usize,
    row: &PlanListRowState,
) -> JsonValue {
    let mut object = plan_executor_row_fields_document_object(&row.fields);
    object.insert(
        "$boon".to_owned(),
        json!({
            "row_key": row.key,
            "generation": row.generation,
        }),
    );
    plan_executor_insert_row_source_bindings(plan, list_id, row.key, row.generation, &mut object);
    JsonValue::Object(object)
}

fn plan_executor_row_fields_document_object(
    fields: &BTreeMap<String, JsonValue>,
) -> serde_json::Map<String, JsonValue> {
    let mut object = serde_json::Map::new();
    for (field, value) in fields {
        insert_nested_json(&mut object, field, value.clone());
    }
    object
}

fn plan_executor_row_with_root_values(
    plan: &MachinePlan,
    row: &PlanListRowState,
    root_state: &serde_json::Map<String, JsonValue>,
) -> PlanListRowState {
    let mut row = row.clone();
    for entry in &plan.debug_map.derived_values {
        if entry.label.starts_with("row.") {
            continue;
        }
        let local_name = local_field_name(&entry.label);
        let Some(value) = root_state
            .get(&entry.label)
            .or_else(|| root_state.get(&local_name))
            .cloned()
        else {
            continue;
        };
        row.fields.entry(local_name).or_insert(value);
    }
    row
}

fn plan_executor_retained_row_document_json(
    plan: &MachinePlan,
    source_list_id: Option<usize>,
    row: &JsonValue,
) -> JsonValue {
    let Some(object) = row.as_object() else {
        return JsonValue::Null;
    };
    let flat_output = object
        .get("fields")
        .and_then(JsonValue::as_object)
        .cloned()
        .unwrap_or_default();
    let fields = flat_output
        .into_iter()
        .collect::<BTreeMap<String, JsonValue>>();
    let mut output = plan_executor_row_fields_document_object(&fields);
    if let (Some(key), Some(generation)) = (
        object.get("key").and_then(JsonValue::as_u64),
        object.get("generation").and_then(JsonValue::as_u64),
    ) {
        if let Some(list_id) = source_list_id.or_else(|| {
            object
                .get("source_list_id")
                .and_then(JsonValue::as_u64)
                .map(|value| value as usize)
        }) {
            plan_executor_insert_row_source_bindings(plan, list_id, key, generation, &mut output);
        }
        output.insert(
            "$boon".to_owned(),
            json!({
                "row_key": key,
                "generation": generation,
            }),
        );
    }
    JsonValue::Object(output)
}

fn plan_executor_insert_row_source_bindings(
    plan: &MachinePlan,
    list_id: usize,
    key: u64,
    generation: u64,
    row: &mut serde_json::Map<String, JsonValue>,
) {
    let Some(list_slot) = plan
        .storage_layout
        .list_slots
        .iter()
        .find(|slot| slot.list_id.0 == list_id)
    else {
        return;
    };
    let list_label = plan_list_label(plan, list_id);
    for route in row_scoped_source_routes(plan, list_slot) {
        let Some(binding_id) = plan_row_source_binding_id(plan, list_slot, key, route.source_id)
        else {
            continue;
        };
        let local_path = plan_executor_row_local_source_path(&route.path);
        let binding = SourceBinding {
            list_id: list_label.clone(),
            key,
            generation,
            source_id: binding_id,
            bind_epoch: binding_id,
            source_path: route.path.clone(),
        };
        insert_nested_json(row, &local_path, source_binding_summary_json(&binding));
    }
}

fn plan_executor_row_local_source_path(path: &str) -> String {
    path.split_once(".sources.")
        .map(|(_, suffix)| format!("sources.{suffix}"))
        .unwrap_or_else(|| path.to_owned())
}

fn plan_executor_projection_selector_value(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    value: &ValueRef,
) -> JsonValue {
    match value {
        ValueRef::State(state_id) => root_state
            .get(&plan_state_label(plan, state_id.0))
            .cloned()
            .unwrap_or(JsonValue::Null),
        ValueRef::Constant(constant_id) => plan
            .constants
            .iter()
            .find(|constant| constant.id == *constant_id)
            .and_then(|constant| {
                plan_executor_constant_value_json_value(
                    &constant.value,
                    &format!("plan constant {}", constant.id.0),
                )
                .ok()
            })
            .unwrap_or(JsonValue::Null),
        ValueRef::Field(field_id) => root_state
            .get(&plan_field_label(plan, field_id.0))
            .cloned()
            .unwrap_or(JsonValue::Null),
        _ => JsonValue::Null,
    }
}

fn plan_executor_source_binding_count(
    plan: &MachinePlan,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
) -> usize {
    list_state
        .iter()
        .map(|(list_id, rows)| {
            plan.storage_layout
                .list_slots
                .iter()
                .find(|slot| slot.list_id.0 == *list_id)
                .map(|slot| {
                    rows.len()
                        .saturating_mul(row_scoped_source_routes(plan, slot).len())
                })
                .unwrap_or(0)
        })
        .sum()
}

fn plan_executor_list_state_for_materialization(
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
) -> BTreeMap<usize, Vec<boon_plan_executor::PlanExecutorListRow>> {
    plan_list_row_state_public_rows(list_state)
}

fn root_pure_number_compare_values(
    plan: &MachinePlan,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
) -> RuntimeResult<BTreeMap<usize, JsonValue>> {
    let executor_rows = plan_executor_list_state_for_materialization(list_state);
    Ok(evaluate_root_pure_number_compare_values_core(
        plan,
        &executor_rows,
    )?)
}

fn plan_executor_root_derived_values(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
) -> RuntimeResult<BTreeMap<usize, JsonValue>> {
    let mut values = root_pure_number_compare_values(plan, list_state)?;
    if let Ok(root_values) = evaluate_plan_root_row_expression_derived_values(plan, root_state) {
        for (field_id, value) in root_values {
            values.insert(field_id.0, value);
        }
    }
    Ok(values)
}

fn refresh_plan_root_row_expression_derived_values_in_state(
    plan: &MachinePlan,
    root_state: &mut serde_json::Map<String, JsonValue>,
) {
    if let Ok(root_values) = evaluate_plan_root_row_expression_derived_values(plan, root_state) {
        for (field_id, value) in root_values {
            root_state.insert(plan_derived_field_label(plan, field_id.0), value);
        }
    }
}

fn commit_root_list_derived_values_to_root_state(
    plan: &MachinePlan,
    root_state: &mut serde_json::Map<String, JsonValue>,
    values: &BTreeMap<usize, JsonValue>,
) {
    for (field_id, value) in values {
        root_state.insert(plan_derived_field_label(plan, *field_id), value.clone());
    }
}

fn root_field_set_delta_already_recorded(recorded: &[JsonValue], candidate: &JsonValue) -> bool {
    let candidate_kind = candidate.get("kind").and_then(JsonValue::as_str);
    if candidate_kind != Some("FieldSet") {
        return false;
    }
    let candidate_field = candidate.get("field_path").and_then(JsonValue::as_str);
    let candidate_value = candidate.get("value");
    recorded.iter().any(|delta| {
        delta.get("kind").and_then(JsonValue::as_str) == candidate_kind
            && delta.get("list_id").is_some_and(JsonValue::is_null)
            && delta.get("key").is_some_and(JsonValue::is_null)
            && delta.get("generation").is_some_and(JsonValue::is_null)
            && delta.get("field_path").and_then(JsonValue::as_str) == candidate_field
            && delta.get("value") == candidate_value
    })
}

fn execute_indexed_update_branch(
    plan: &MachinePlan,
    op: &boon_plan::PlanOp,
    source_id: SourceId,
    source_route_slot: &boon_plan::SourceRoute,
    event: &GenericSourceEvent<'_>,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    row_resolution_cache: &mut BTreeMap<(usize, usize), usize>,
    root_derived_values: &BTreeMap<usize, JsonValue>,
    host_file_root: Option<&Path>,
) -> RuntimeResult<IndexedUpdateBranchExecution> {
    if op.unresolved_executable_ref_count != 0 {
        return Err(format!(
            "selected indexed update branch {} has {} unresolved executable refs",
            op.id.0, op.unresolved_executable_ref_count
        )
        .into());
    }
    let source_guard = match &op.kind {
        PlanOpKind::UpdateBranch { source_guard, .. } => source_guard,
        _ => {
            return Err(format!(
                "CPU root-scenario PlanExecutor indexed update branch {} is not an update branch",
                op.id.0
            )
            .into());
        }
    };
    let root_json_event = root_json_source_event_from_generic(event);
    if !plan_executor_source_guard_matches(source_guard, source_id, &root_json_event)? {
        return Ok(IndexedUpdateBranchExecution {
            semantic_deltas: Vec::new(),
            report_rows: Vec::new(),
            updated_row_count: 0,
        });
    }
    let Some(ValueRef::State(output_state_id)) = op.output else {
        return Err(format!(
            "CPU root-scenario PlanExecutor indexed update branch {} does not target a state slot",
            op.id.0
        )
        .into());
    };
    let output_slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == output_state_id)
        .ok_or_else(|| format!("indexed update branch {} targets missing state", op.id.0))?;
    if !output_slot.indexed {
        return Err(format!(
            "indexed update branch {} targets non-indexed state {}",
            op.id.0, output_state_id.0
        )
        .into());
    }
    let scope_id = output_slot
        .scope_id
        .ok_or_else(|| format!("indexed update branch {} has no row scope", op.id.0))?;
    if source_route_slot.scoped && source_route_slot.scope_id != Some(scope_id) {
        return Err(format!(
            "indexed update branch {} source scope {:?} does not match output scope {:?}",
            op.id.0, source_route_slot.scope_id, output_slot.scope_id
        )
        .into());
    }
    let list_slot = plan
        .storage_layout
        .list_slots
        .iter()
        .find(|slot| slot.scope_id == Some(scope_id))
        .ok_or_else(|| {
            format!(
                "indexed update branch {} has no list slot for scope",
                op.id.0
            )
        })?;
    let list_label = plan_list_label(plan, list_slot.list_id.0);
    if let Some(event_list) = event.list_id
        && event_list != list_label
    {
        return Err(format!(
            "scoped source `{}` targeted list `{event_list}`, expected `{list_label}`",
            event.source
        )
        .into());
    }
    let cache_key = (list_slot.list_id.0, source_id.0);
    let row_index = if let Some(row_index) = row_resolution_cache.get(&cache_key) {
        *row_index
    } else {
        let row_index =
            resolve_plan_row_index(plan, source_route_slot, event, list_slot, list_state)?;
        row_resolution_cache.insert(cache_key, row_index);
        row_index
    };
    let source_transform_deltas = apply_indexed_source_event_transforms_for_row(
        plan,
        source_id,
        list_slot,
        &list_label,
        list_state,
        row_index,
    )?;
    let _pre_read_currentness_deltas = refresh_indexed_derived_fields_for_row_with_options(
        plan,
        list_slot,
        &list_label,
        list_state,
        row_index,
        IndexedDerivedRefreshOptions {
            suppress_recursive_cycle_values: false,
            sort_cycle_error_first: true,
            evaluate_demand_current_ops: true,
            emit_demand_current_deltas: false,
            changed_root_states: None,
            root_state: None,
        },
    )?;
    let rows = list_state
        .get_mut(&list_slot.list_id.0)
        .ok_or_else(|| format!("list state missing list {}", list_slot.list_id.0))?;
    let row = rows
        .get_mut(row_index)
        .ok_or_else(|| format!("row index {row_index} missing in `{list_label}`"))?;
    let report_source_payload_field = match &op.kind {
        PlanOpKind::UpdateBranch {
            source_payload_field,
            ..
        } => source_payload_field
            .as_ref()
            .map(serde_json::to_value)
            .transpose()?
            .unwrap_or(JsonValue::Null),
        _ => JsonValue::Null,
    };
    let mut bytes_access = JsonValue::Null;
    let mut bytes_storage = JsonValue::Null;
    let mut host_effect = JsonValue::Null;
    let mut executor_core = JsonValue::Null;
    let root_json_event = root_json_source_event_from_generic(event);
    let json_evaluation = evaluate_plan_indexed_json_update_branch(
        plan,
        op,
        source_id,
        source_route_slot,
        &root_json_event,
        row,
        root_derived_values,
    )?;
    if json_evaluation.supported && json_evaluation.value.is_none() {
        return Ok(IndexedUpdateBranchExecution {
            semantic_deltas: source_transform_deltas,
            report_rows: Vec::new(),
            updated_row_count: 0,
        });
    }
    let (value, bytes_value, expression_kind, update_constant_id, update_constant_value) =
        if json_evaluation.supported {
            (
                json_evaluation.value.ok_or_else(|| {
                    format!(
                        "indexed JSON update branch {} reported supported without a value",
                        op.id.0
                    )
                })?,
                None,
                json_evaluation.expression_kind.ok_or_else(|| {
                    format!(
                        "indexed JSON update branch {} reported supported without expression kind",
                        op.id.0
                    )
                })?,
                json_evaluation.update_constant_id,
                json_evaluation.update_constant_value,
            )
        } else {
            match &op.kind {
                PlanOpKind::UpdateBranch {
                    expression_kind: PlanExpressionKind::SourcePayload,
                    source_payload_field: Some(source_payload_field),
                    update_constant_id: None,
                    ..
                } => {
                    if !source_route_slot
                        .payload_schema
                        .fields
                        .contains(source_payload_field)
                    {
                        return Err(format!(
                    "indexed SourcePayload update branch {} reads payload field {:?}, but route schema is {:?}",
                    op.id.0, source_payload_field, source_route_slot.payload_schema.fields
                )
                .into());
                    }
                    let typed_payload_ref_present = op.inputs.iter().any(|input| {
                        matches!(
                            input,
                            ValueRef::SourcePayload {
                                source_id: input_source_id,
                                field
                            } if *input_source_id == source_id && field == source_payload_field
                        )
                    });
                    if !typed_payload_ref_present {
                        return Err(format!(
                    "indexed SourcePayload update branch {} is missing typed SourcePayload input",
                    op.id.0
                )
                .into());
                    }
                    let (value, runtime_bytes_value) = generic_source_payload_value_for_output(
                        plan,
                        output_state_id,
                        event,
                        source_payload_field,
                        op.id.0,
                    )?;
                    if let Some(bytes) = runtime_bytes_value.as_ref() {
                        bytes_storage = json!({
                            "storage": if plan_indexed_state_has_fixed_byte_bank(plan, output_state_id) {
                                "indexed_fixed_byte_bank"
                            } else {
                                "indexed_row_private_bytes"
                            },
                            "output_state_id": output_state_id.0,
                            "byte_bank_declared": plan_indexed_state_has_fixed_byte_bank(plan, output_state_id),
                            "byte_bank_used": plan_indexed_state_has_fixed_byte_bank(plan, output_state_id),
                            "byte_len": bytes.byte_len,
                        });
                    }
                    let bytes_value = runtime_bytes_value
                        .map(runtime_source_payload_bytes_to_plan_executor_bytes)
                        .transpose()?;
                    (
                        value,
                        bytes_value,
                        "source_payload",
                        JsonValue::Null,
                        JsonValue::Null,
                    )
                }
                PlanOpKind::UpdateBranch {
                    expression_kind: PlanExpressionKind::Const,
                    source_payload_field: None,
                    update_constant_id: Some(update_constant_id),
                    ..
                } => {
                    let constant = plan
                        .constants
                        .iter()
                        .find(|constant| constant.id == *update_constant_id)
                        .ok_or_else(|| {
                            format!("missing update constant {}", update_constant_id.0)
                        })?;
                    let value = plan_executor_constant_json_value(constant)?;
                    let bytes_value = plan_constant_executor_bytes_for_output(
                        plan,
                        output_state_id,
                        constant,
                        op.id.0,
                    )?;
                    (
                        value,
                        bytes_value,
                        "const",
                        json!(update_constant_id.0),
                        plan_executor_constant_json_value(constant)?,
                    )
                }
                PlanOpKind::UpdateBranch {
                    expression_kind:
                        PlanExpressionKind::BytesSet
                        | PlanExpressionKind::BytesSlice
                        | PlanExpressionKind::BytesTake
                        | PlanExpressionKind::BytesDrop
                        | PlanExpressionKind::BytesZeros
                        | PlanExpressionKind::BytesConcat
                        | PlanExpressionKind::BytesWriteUnsigned
                        | PlanExpressionKind::BytesWriteSigned
                        | PlanExpressionKind::TextToBytes
                        | PlanExpressionKind::BytesFromHex
                        | PlanExpressionKind::BytesFromBase64
                        | PlanExpressionKind::FileWriteBytes,
                    source_payload_field: None,
                    update_constant_id: None,
                    ..
                } => {
                    let evaluation = evaluate_indexed_bytes_write_update_for_runtime(
                        plan,
                        op,
                        row,
                        host_file_root,
                    )?;
                    bytes_access = evaluation.bytes_access;
                    bytes_storage = evaluation.bytes_storage;
                    host_effect = evaluation.host_effect;
                    executor_core = evaluation.executor_report;
                    (
                        evaluation.value.ok_or_else(|| {
                            format!(
                                "indexed BYTES write branch {} reported supported without a value",
                                op.id.0
                            )
                        })?,
                        evaluation.bytes,
                        evaluation.expression_kind.ok_or_else(|| {
                            format!(
                                "indexed BYTES write branch {} reported supported without expression kind",
                                op.id.0
                            )
                        })?,
                        evaluation.update_constant_id,
                        evaluation.update_constant_value,
                    )
                }
                PlanOpKind::UpdateBranch {
                    expression_kind:
                        PlanExpressionKind::BytesLength
                        | PlanExpressionKind::BytesIsEmpty
                        | PlanExpressionKind::BytesGet
                        | PlanExpressionKind::BytesToHex
                        | PlanExpressionKind::BytesToBase64
                        | PlanExpressionKind::BytesToText
                        | PlanExpressionKind::BytesReadUnsigned
                        | PlanExpressionKind::BytesReadSigned
                        | PlanExpressionKind::BytesEqual
                        | PlanExpressionKind::BytesFind
                        | PlanExpressionKind::BytesStartsWith
                        | PlanExpressionKind::BytesEndsWith
                        | PlanExpressionKind::FileReadBytes,
                    source_payload_field: None,
                    ..
                } => {
                    let evaluation = evaluate_indexed_bytes_read_update_for_runtime(
                        plan,
                        op,
                        row,
                        host_file_root,
                    )?;
                    bytes_access = evaluation.bytes_access;
                    executor_core = evaluation.executor_report;
                    if let Some(bytes) = evaluation.bytes.as_ref() {
                        bytes_storage = json!({
                            "storage": if plan_indexed_state_has_fixed_byte_bank(plan, output_state_id) {
                                "indexed_fixed_byte_bank"
                            } else {
                                "indexed_row_private_bytes"
                            },
                            "output_state_id": output_state_id.0,
                            "byte_bank_declared": plan_indexed_state_has_fixed_byte_bank(plan, output_state_id),
                            "byte_bank_used": plan_indexed_state_has_fixed_byte_bank(plan, output_state_id),
                            "byte_len": bytes.byte_len(),
                        });
                    }
                    (
                        evaluation.value.ok_or_else(|| {
                            format!(
                                "indexed BYTES read branch {} reported supported without a value",
                                op.id.0
                            )
                        })?,
                        evaluation.bytes,
                        evaluation.expression_kind.ok_or_else(|| {
                            format!(
                                "indexed BYTES read branch {} reported supported without expression kind",
                                op.id.0
                            )
                        })?,
                        evaluation.update_constant_id,
                        evaluation.update_constant_value,
                    )
                }
                _ => {
                    return Err(format!(
                        "CPU root-scenario PlanExecutor does not support indexed update branch {} kind {:?}: {}",
                        op.id.0,
                        op.kind,
                        json_evaluation
                            .unsupported_reason
                            .unwrap_or_else(|| "unsupported indexed JSON update branch".to_owned())
            )
            .into());
                }
            }
        };
    let output_name = local_field_name(&plan_state_label(plan, output_state_id.0));
    let changed = row.fields.get(&output_name) != Some(&value);
    row.fields.insert(output_name.clone(), value.clone());
    if let Some(bytes) = bytes_value {
        if let Some(expected_len) = plan_indexed_fixed_byte_bank_len(plan, output_state_id)? {
            let inline_bytes = bytes.inline_bytes();
            if inline_bytes.len() != expected_len {
                return Err(format!(
                    "indexed update branch {} fixed byte bank `{output_name}` expected {expected_len} byte(s), got {}",
                    op.id.0,
                    inline_bytes.len()
                )
                .into());
            }
            row.fixed_bytes_banks
                .insert(output_name.clone(), inline_bytes.to_vec());
        } else {
            row.fixed_bytes_banks.remove(&output_name);
        }
        row.private_bytes.insert(output_name.clone(), bytes);
    } else {
        row.private_bytes.remove(&output_name);
        row.fixed_bytes_banks.remove(&output_name);
    }
    let _ = row;
    let derived_deltas = if indexed_state_feeds_indexed_derived_expression(plan, output_state_id) {
        if changed {
            refresh_indexed_derived_fields_after_state_change(
                plan,
                list_slot,
                &plan_list_label(plan, list_slot.list_id.0),
                list_state,
                row_index,
            )?
        } else {
            refresh_indexed_derived_fields_for_row_with_options(
                plan,
                list_slot,
                &plan_list_label(plan, list_slot.list_id.0),
                list_state,
                row_index,
                IndexedDerivedRefreshOptions {
                    suppress_recursive_cycle_values: false,
                    sort_cycle_error_first: true,
                    evaluate_demand_current_ops: true,
                    emit_demand_current_deltas: false,
                    changed_root_states: None,
                    root_state: None,
                },
            )?
        }
    } else if changed && source_has_later_indexed_state_feeding_derived(plan, source_id, op.id.0) {
        stale_empty_text_indexed_derived_deltas(
            plan,
            list_slot,
            &plan_list_label(plan, list_slot.list_id.0),
            list_state,
            row_index,
            source_id,
            op.id.0,
        )?
    } else {
        Vec::new()
    };
    let row = list_state
        .get(&list_slot.list_id.0)
        .and_then(|rows| rows.get(row_index))
        .ok_or_else(|| format!("row index {row_index} missing in `{list_label}` after refresh"))?;
    let source_binding_id = plan_row_source_binding_id(plan, list_slot, row.key, source_id);
    let mut semantic_deltas = Vec::new();
    let emit_semantic_delta =
        changed || expression_kind == "read_path" || !source_route_slot.scoped || op.indexed;
    if emit_semantic_delta {
        semantic_deltas.push(json!({
            "kind": "FieldSet",
            "list_id": list_label,
            "key": row.key,
            "generation": row.generation,
            "source_id": null,
            "bind_epoch": null,
            "field_path": output_name,
            "value": value,
        }));
    }
    semantic_deltas.extend(source_transform_deltas);
    semantic_deltas.extend(derived_deltas);
    Ok(IndexedUpdateBranchExecution {
        semantic_deltas,
        report_rows: vec![json!({
            "source_id": source_id.0,
            "source": event.source,
            "target_state": plan_state_label(plan, output_state_id.0),
            "target_state_id": output_state_id.0,
            "update_op_id": op.id.0,
            "candidate_update_op_ids": [op.id.0],
            "expression_kind": expression_kind,
            "source_payload_field": report_source_payload_field,
            "update_constant_id": update_constant_id,
            "update_constant_value": update_constant_value,
            "bytes_access": bytes_access,
            "bytes_storage": bytes_storage,
            "host_effect": host_effect,
            "executor_core": executor_core,
            "selected_op_indexed": true,
            "selected_op_unresolved_executable_ref_count": 0,
            "list_id": list_slot.list_id.0,
            "list": plan_list_label(plan, list_slot.list_id.0),
            "row_index": row_index,
            "key": row.key,
            "generation": row.generation,
            "source_binding_id": source_binding_id,
            "bind_epoch": source_binding_id,
            "row_resolution": row_resolution_report(
                event,
                row_index,
                row,
                source_binding_id,
                source_route_slot.payload_schema.row_lookup_field_name()
            ),
            "field_path": output_name,
            "value": value,
            "changed": changed,
            "row_fields": plan_executor_list_row_report_fields(row)?,
        })],
        updated_row_count: 1,
    })
}

fn generic_source_payload_json_value(
    event: &GenericSourceEvent<'_>,
    field: &SourcePayloadField,
) -> RuntimeResult<JsonValue> {
    match field {
        SourcePayloadField::Text => event
            .text
            .map(|value| JsonValue::String(value.to_owned()))
            .ok_or_else(|| "source event is missing text payload".into()),
        SourcePayloadField::Key => event
            .key
            .map(|value| JsonValue::String(value.to_owned()))
            .ok_or_else(|| "source event is missing key payload".into()),
        SourcePayloadField::Address => event
            .address
            .map(|value| JsonValue::String(value.to_owned()))
            .ok_or_else(|| "source event is missing address payload".into()),
        SourcePayloadField::Bytes => {
            generic_source_payload_runtime_bytes(event, field).map(|bytes| bytes.report_json())
        }
        SourcePayloadField::Named(name) => event
            .payload
            .get(name)
            .map(|value| JsonValue::String((*value).to_owned()))
            .ok_or_else(|| format!("source event is missing `{name}` payload").into()),
    }
}

fn generic_source_payload_value_for_output(
    plan: &MachinePlan,
    output_state_id: StateId,
    event: &GenericSourceEvent<'_>,
    field: &SourcePayloadField,
    op_id: usize,
) -> RuntimeResult<(JsonValue, Option<RuntimeBytes>)> {
    let slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == output_state_id)
        .ok_or_else(|| {
            format!(
                "indexed source-payload update branch {op_id} targets missing state {}",
                output_state_id.0
            )
        })?;
    match field {
        SourcePayloadField::Bytes => {
            let bytes = generic_source_payload_runtime_bytes(event, field)?;
            let boon_plan::PlanValueType::Bytes { fixed_len } = &slot.value_type else {
                return Err(format!(
                    "indexed source-payload update branch {op_id} reads BYTES payload but output state `{}` is not BYTES",
                    plan_state_label(plan, output_state_id.0)
                )
                .into());
            };
            if let Some(expected_len) = *fixed_len
                && expected_len != bytes.byte_len
            {
                return Err(format!(
                    "indexed source-payload update branch {op_id} BYTES payload has byte_len {} but output fixed_len {expected_len}",
                    bytes.byte_len
                )
                .into());
            }
            Ok((bytes.report_json(), Some(bytes)))
        }
        SourcePayloadField::Address
        | SourcePayloadField::Key
        | SourcePayloadField::Named(_)
        | SourcePayloadField::Text => {
            if slot.value_type != boon_plan::PlanValueType::Text {
                return Err(format!(
                    "indexed source-payload update branch {op_id} reads text payload but output state `{}` is not TEXT",
                    plan_state_label(plan, output_state_id.0)
                )
                .into());
            }
            Ok((generic_source_payload_json_value(event, field)?, None))
        }
    }
}

fn indexed_row_state_text(
    plan: &MachinePlan,
    row: &PlanListRowState,
    state_id: StateId,
    op_id: usize,
    role: &str,
) -> RuntimeResult<String> {
    let label = plan_state_label(plan, state_id.0);
    let field_name = local_field_name(&label);
    let value = row.fields.get(&field_name).ok_or_else(|| {
        format!("indexed update branch {op_id} {role} row field `{field_name}` is missing")
    })?;
    value.as_str().map(str::to_owned).ok_or_else(|| {
        format!(
            "indexed update branch {op_id} {role} state `{label}` row field `{field_name}` is not TEXT"
        )
        .into()
    })
}

fn indexed_row_field_text(
    plan: &MachinePlan,
    row: &PlanListRowState,
    field_id: FieldId,
    op_id: usize,
    role: &str,
) -> RuntimeResult<String> {
    let label = plan_field_label(plan, field_id.0);
    let field_name = local_field_name(&label);
    let value = row.fields.get(&field_name).ok_or_else(|| {
        format!("indexed update branch {op_id} {role} row field `{field_name}` is missing")
    })?;
    value.as_str().map(str::to_owned).ok_or_else(|| {
        format!(
            "indexed update branch {op_id} {role} field `{label}` row field `{field_name}` is not TEXT"
        )
        .into()
    })
}

fn indexed_row_state_inline_bytes(
    plan: &MachinePlan,
    row: &PlanListRowState,
    state_id: StateId,
    op_id: usize,
) -> RuntimeResult<Bytes> {
    let label = plan_state_label(plan, state_id.0);
    let field_name = local_field_name(&label);
    let public_value = row.fields.get(&field_name).ok_or_else(|| {
        format!("indexed update branch {op_id} row field `{field_name}` is missing")
    })?;
    if public_value.get("$boon_type").and_then(JsonValue::as_str) != Some("BYTES") {
        return Err(format!(
            "indexed update branch {op_id} input row field `{field_name}` is not BYTES"
        )
        .into());
    }
    let executor_bytes = row.private_bytes.get(&field_name).ok_or_else(|| {
        format!(
            "indexed update branch {op_id} input row field `{field_name}` has no private BYTES state"
        )
    })?;
    if &executor_bytes.report_json() != public_value {
        return Err(format!(
            "indexed update branch {op_id} bytes row field `{field_name}` public summary does not match private byte state"
        )
        .into());
    }
    Ok(Bytes::copy_from_slice(executor_bytes.inline_bytes()))
}

fn indexed_row_state_bytes_view<'a>(
    plan: &MachinePlan,
    row: &'a PlanListRowState,
    state_id: StateId,
    op_id: usize,
) -> RuntimeResult<RootBytesView<'a>> {
    let label = plan_state_label(plan, state_id.0);
    let field_name = local_field_name(&label);
    let public_value = row.fields.get(&field_name).ok_or_else(|| {
        format!("indexed update branch {op_id} row field `{field_name}` is missing")
    })?;
    if public_value.get("$boon_type").and_then(JsonValue::as_str) != Some("BYTES") {
        return Err(format!(
            "indexed update branch {op_id} input row field `{field_name}` is not BYTES"
        )
        .into());
    }
    if let Some(bytes) = row.fixed_bytes_banks.get(&field_name) {
        if root_fixed_bytes_report_json(bytes) != *public_value {
            return Err(format!(
                "indexed update branch {op_id} fixed byte bank `{field_name}` public summary does not match private bank state"
            )
            .into());
        }
        return Ok(RootBytesView {
            bytes: Cow::Borrowed(bytes.as_slice()),
            access_source: "indexed_fixed_byte_bank",
            cow_kind: "borrowed",
        });
    }
    let executor_bytes = row.private_bytes.get(&field_name).ok_or_else(|| {
        format!(
            "indexed update branch {op_id} input row field `{field_name}` has no private BYTES state"
        )
    })?;
    if &executor_bytes.report_json() != public_value {
        return Err(format!(
            "indexed update branch {op_id} bytes row field `{field_name}` public summary does not match private byte state"
        )
        .into());
    }
    Ok(RootBytesView {
        bytes: Cow::Borrowed(executor_bytes.inline_bytes()),
        access_source: "indexed_row_private_bytes",
        cow_kind: "borrowed",
    })
}

fn root_single_state_input(op: &boon_plan::PlanOp) -> RuntimeResult<StateId> {
    let mut inputs = Vec::new();
    for input in &op.inputs {
        if let ValueRef::State(state_id) = input
            && !inputs.contains(state_id)
        {
            inputs.push(*state_id);
        }
    }
    let [input] = inputs.as_slice() else {
        return Err(format!(
            "root update branch {} expected one state input, found {}",
            op.id.0,
            inputs.len()
        )
        .into());
    };
    Ok(*input)
}

fn root_bytes_equal_state_inputs(op: &boon_plan::PlanOp) -> RuntimeResult<(StateId, StateId)> {
    let mut inputs = Vec::new();
    for input in &op.inputs {
        if let ValueRef::State(state_id) = input
            && !inputs.contains(state_id)
        {
            inputs.push(*state_id);
        }
    }
    match inputs.as_slice() {
        [left, right] => Ok((*left, *right)),
        _ => Err(format!(
            "root Bytes/equal update branch {} expected two distinct state inputs, found {}",
            op.id.0,
            inputs.len()
        )
        .into()),
    }
}

fn root_bytes_concat_state_inputs(op: &boon_plan::PlanOp) -> RuntimeResult<(StateId, StateId)> {
    let PlanOpKind::UpdateBranch { ordered_inputs, .. } = &op.kind else {
        return Err(format!(
            "root Bytes/concat update branch {} is not an update branch",
            op.id.0
        )
        .into());
    };
    let [ValueRef::State(left), ValueRef::State(right)] = ordered_inputs.as_slice() else {
        return Err(format!(
            "root Bytes/concat update branch {} expected two ordered state inputs, found {}",
            op.id.0,
            ordered_inputs.len()
        )
        .into());
    };
    if left == right {
        return Err(format!(
            "root Bytes/concat update branch {} expected distinct state inputs",
            op.id.0
        )
        .into());
    }
    if !op.inputs.contains(&ValueRef::State(*left)) || !op.inputs.contains(&ValueRef::State(*right))
    {
        return Err(format!(
            "root Bytes/concat update branch {} ordered inputs are not declared op inputs",
            op.id.0
        )
        .into());
    }
    Ok((*left, *right))
}

fn root_bytes_ordered_state_inputs(
    op: &boon_plan::PlanOp,
    operation: &str,
) -> RuntimeResult<(StateId, StateId)> {
    let PlanOpKind::UpdateBranch { ordered_inputs, .. } = &op.kind else {
        return Err(format!(
            "root {operation} update branch {} is not an update branch",
            op.id.0
        )
        .into());
    };
    let [ValueRef::State(left), ValueRef::State(right)] = ordered_inputs.as_slice() else {
        return Err(format!(
            "root {operation} update branch {} expected two ordered state inputs, found {}",
            op.id.0,
            ordered_inputs.len()
        )
        .into());
    };
    if !op.inputs.contains(&ValueRef::State(*left)) || !op.inputs.contains(&ValueRef::State(*right))
    {
        return Err(format!(
            "root {operation} update branch {} ordered inputs are not declared op inputs",
            op.id.0
        )
        .into());
    }
    Ok((*left, *right))
}

fn root_bytes_set_operands(
    plan: &MachinePlan,
    op: &boon_plan::PlanOp,
) -> RuntimeResult<(StateId, usize, u8, PlanConstantId, PlanConstantId)> {
    let PlanOpKind::UpdateBranch { ordered_inputs, .. } = &op.kind else {
        return Err(format!(
            "root Bytes/set update branch {} is not an update branch",
            op.id.0
        )
        .into());
    };
    let [
        ValueRef::State(input),
        ValueRef::Constant(index_constant_id),
        ValueRef::Constant(value_constant_id),
    ] = ordered_inputs.as_slice()
    else {
        return Err(format!(
            "root Bytes/set update branch {} expected state, index constant, and value constant operands, found {}",
            op.id.0,
            ordered_inputs.len()
        )
        .into());
    };
    if !op.inputs.contains(&ValueRef::State(*input)) {
        return Err(format!(
            "root Bytes/set update branch {} state operand is not declared as an op input",
            op.id.0
        )
        .into());
    }
    let index_constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == *index_constant_id)
        .ok_or_else(|| {
            format!(
                "root Bytes/set update branch {} references missing index constant {}",
                op.id.0, index_constant_id.0
            )
        })?;
    let PlanConstantValue::Number { value: index } = &index_constant.value else {
        return Err(format!(
            "root Bytes/set update branch {} index constant {} is not a number",
            op.id.0, index_constant_id.0
        )
        .into());
    };
    let index = usize::try_from(*index).map_err(|_| {
        format!(
            "root Bytes/set update branch {} index constant {} is negative or too large",
            op.id.0, index_constant_id.0
        )
    })?;
    let value_constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == *value_constant_id)
        .ok_or_else(|| {
            format!(
                "root Bytes/set update branch {} references missing value constant {}",
                op.id.0, value_constant_id.0
            )
        })?;
    let PlanConstantValue::Byte { value } = value_constant.value else {
        return Err(format!(
            "root Bytes/set update branch {} value constant {} is not a BYTE",
            op.id.0, value_constant_id.0
        )
        .into());
    };
    Ok((*input, index, value, *index_constant_id, *value_constant_id))
}

fn indexed_bytes_set_operands(
    plan: &MachinePlan,
    op: &boon_plan::PlanOp,
) -> RuntimeResult<(StateId, usize, u8, PlanConstantId, PlanConstantId)> {
    let PlanOpKind::UpdateBranch { ordered_inputs, .. } = &op.kind else {
        return Err(format!(
            "indexed Bytes/set update branch {} is not an update branch",
            op.id.0
        )
        .into());
    };
    let [
        ValueRef::State(input),
        ValueRef::Constant(index_constant_id),
        ValueRef::Constant(value_constant_id),
    ] = ordered_inputs.as_slice()
    else {
        return Err(format!(
            "indexed Bytes/set update branch {} expected state, index constant, and value constant operands, found {}",
            op.id.0,
            ordered_inputs.len()
        )
        .into());
    };
    if !op.inputs.contains(&ValueRef::State(*input)) {
        return Err(format!(
            "indexed Bytes/set update branch {} state operand is not declared as an op input",
            op.id.0
        )
        .into());
    }
    let index_constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == *index_constant_id)
        .ok_or_else(|| {
            format!(
                "indexed Bytes/set update branch {} references missing index constant {}",
                op.id.0, index_constant_id.0
            )
        })?;
    let PlanConstantValue::Number { value: index } = &index_constant.value else {
        return Err(format!(
            "indexed Bytes/set update branch {} index constant {} is not a number",
            op.id.0, index_constant_id.0
        )
        .into());
    };
    let index = usize::try_from(*index).map_err(|_| {
        format!(
            "indexed Bytes/set update branch {} index constant {} is negative or too large",
            op.id.0, index_constant_id.0
        )
    })?;
    let value_constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == *value_constant_id)
        .ok_or_else(|| {
            format!(
                "indexed Bytes/set update branch {} references missing value constant {}",
                op.id.0, value_constant_id.0
            )
        })?;
    let PlanConstantValue::Byte { value } = value_constant.value else {
        return Err(format!(
            "indexed Bytes/set update branch {} value constant {} is not a BYTE",
            op.id.0, value_constant_id.0
        )
        .into());
    };
    Ok((*input, index, value, *index_constant_id, *value_constant_id))
}

