fn root_usize_number_constant(
    plan: &MachinePlan,
    constant_id: PlanConstantId,
    operation: &str,
    label: &str,
    op: &boon_plan::PlanOp,
) -> RuntimeResult<usize> {
    let constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == constant_id)
        .ok_or_else(|| {
            format!(
                "root {operation} update branch {} references missing {label} constant {}",
                op.id.0, constant_id.0
            )
        })?;
    let PlanConstantValue::Number { value } = &constant.value else {
        return Err(format!(
            "root {operation} update branch {} {label} constant {} is not a number",
            op.id.0, constant_id.0
        )
        .into());
    };
    usize::try_from(*value).map_err(|_| {
        format!(
            "root {operation} update branch {} {label} constant {} is negative or too large",
            op.id.0, constant_id.0
        )
        .into()
    })
}

fn root_usize_number_operand(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    value_ref: &ValueRef,
    operation: &str,
    label: &str,
    op: &boon_plan::PlanOp,
) -> RuntimeResult<(usize, JsonValue)> {
    match value_ref {
        ValueRef::Constant(constant_id) => Ok((
            root_usize_number_constant(plan, *constant_id, operation, label, op)?,
            json!({"kind": "constant", "constant_id": constant_id.0}),
        )),
        ValueRef::State(state_id) => {
            if !op.inputs.contains(&ValueRef::State(*state_id)) {
                return Err(format!(
                    "root {operation} update branch {} {label} state operand {} is not declared as an op input",
                    op.id.0, state_id.0
                )
                .into());
            }
            let state_label = plan_state_label(plan, state_id.0);
            let value = root_state_value(plan, root_state, *state_id, op.id.0)?;
            let number = value.as_i64().ok_or_else(|| {
                format!(
                    "root {operation} update branch {} {label} state `{state_label}` is not NUMBER",
                    op.id.0
                )
            })?;
            let number = usize::try_from(number).map_err(|_| {
                format!(
                    "root {operation} update branch {} {label} state `{state_label}` is negative or too large",
                    op.id.0
                )
            })?;
            Ok((
                number,
                json!({"kind": "state", "state_id": state_id.0, "state": state_label}),
            ))
        }
        other => Err(format!(
            "root {operation} update branch {} {label} operand must be a number constant or NUMBER state, got {other:?}",
            op.id.0
        )
        .into()),
    }
}

fn root_i64_number_constant(
    plan: &MachinePlan,
    constant_id: PlanConstantId,
    operation: &str,
    label: &str,
    op: &boon_plan::PlanOp,
) -> RuntimeResult<i64> {
    let constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == constant_id)
        .ok_or_else(|| {
            format!(
                "root {operation} update branch {} references missing {label} constant {}",
                op.id.0, constant_id.0
            )
        })?;
    let PlanConstantValue::Number { value } = &constant.value else {
        return Err(format!(
            "root {operation} update branch {} {label} constant {} is not a number",
            op.id.0, constant_id.0
        )
        .into());
    };
    Ok(*value)
}

fn root_endian_constant(
    plan: &MachinePlan,
    constant_id: PlanConstantId,
    operation: &str,
    op: &boon_plan::PlanOp,
) -> RuntimeResult<BytesEndian> {
    let constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == constant_id)
        .ok_or_else(|| {
            format!(
                "root {operation} update branch {} references missing endian constant {}",
                op.id.0, constant_id.0
            )
        })?;
    let PlanConstantValue::Text { value } = &constant.value else {
        return Err(format!(
            "root {operation} update branch {} endian constant {} is not TEXT",
            op.id.0, constant_id.0
        )
        .into());
    };
    runtime_bytes_endian(value).ok_or_else(|| {
        format!(
            "root {operation} update branch {} endian constant {} is unsupported: `{value}`",
            op.id.0, constant_id.0
        )
        .into()
    })
}

fn checked_runtime_bytes_slice(
    data: &Bytes,
    offset: usize,
    byte_count: usize,
    out_of_bounds: impl FnOnce(usize, usize) -> String,
    overflow: impl FnOnce() -> String,
) -> RuntimeResult<Bytes> {
    let end = offset.checked_add(byte_count).ok_or_else(overflow)?;
    if data.get(offset..end).is_none() {
        return Err(out_of_bounds(offset, end).into());
    }
    Ok(data.slice(offset..end))
}

fn checked_boon_bytes_slice(
    data: &Bytes,
    offset: usize,
    byte_count: usize,
) -> Result<Bytes, BoonValue> {
    let end = offset
        .checked_add(byte_count)
        .ok_or_else(|| BoonValue::Error("bytes_out_of_bounds".to_owned()))?;
    if data.get(offset..end).is_none() {
        return Err(BoonValue::Error("bytes_out_of_bounds".to_owned()));
    }
    Ok(data.slice(offset..end))
}

fn checked_boon_bytes_drop(data: &Bytes, byte_count: usize) -> Result<Bytes, BoonValue> {
    if data.get(byte_count..).is_none() {
        return Err(BoonValue::Error("bytes_out_of_bounds".to_owned()));
    }
    Ok(data.slice(byte_count..))
}

fn checked_runtime_bytes_drop(
    data: &Bytes,
    byte_count: usize,
    out_of_bounds: impl FnOnce() -> String,
) -> RuntimeResult<Bytes> {
    if data.get(byte_count..).is_none() {
        return Err(out_of_bounds().into());
    }
    Ok(data.slice(byte_count..))
}

fn root_validate_bytes_slice(
    data: &Bytes,
    offset: usize,
    byte_count: usize,
    operation: &str,
    op_id: usize,
    input_label: &str,
) -> RuntimeResult<Bytes> {
    checked_runtime_bytes_slice(
        data,
        offset,
        byte_count,
        |start, end| {
            format!(
                "root {operation} update branch {op_id} byte range {start}..{end} is out of bounds for `{input_label}`"
            )
        },
        || {
            format!(
                "root {operation} update branch {op_id} byte range overflows for `{input_label}`"
            )
        },
    )
}

fn root_checked_bytes_slice(
    data: &Bytes,
    offset: usize,
    byte_count: usize,
    operation: &str,
    op_id: usize,
    input_label: &str,
) -> RuntimeResult<Bytes> {
    root_validate_bytes_slice(data, offset, byte_count, operation, op_id, input_label)
}

fn root_checked_bytes_drop(
    data: &Bytes,
    byte_count: usize,
    operation: &str,
    op_id: usize,
    input_label: &str,
) -> RuntimeResult<Bytes> {
    checked_runtime_bytes_drop(data, byte_count, || {
        format!(
            "root {operation} update branch {op_id} byte_count {byte_count} is out of bounds for `{input_label}`"
        )
    })
}

fn root_validate_bytes_output_len(
    plan: &MachinePlan,
    output_state_id: StateId,
    actual_len: usize,
    operation: &str,
    op_id: usize,
) -> RuntimeResult<()> {
    let output_slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == output_state_id)
        .ok_or_else(|| {
            format!("root {operation} update branch {op_id} has no output storage slot")
        })?;
    if let boon_plan::PlanValueType::Bytes {
        fixed_len: Some(fixed_len),
    } = &output_slot.value_type
        && *fixed_len != actual_len as u64
    {
        return Err(format!(
            "root {operation} update branch {op_id} output fixed length {fixed_len} does not match produced length {actual_len}"
        )
        .into());
    }
    Ok(())
}

fn root_text_bytes_conversion_operands(
    plan: &MachinePlan,
    op: &boon_plan::PlanOp,
    operation: &str,
) -> RuntimeResult<(StateId, String, PlanConstantId)> {
    let PlanOpKind::UpdateBranch { ordered_inputs, .. } = &op.kind else {
        return Err(format!(
            "root {operation} update branch {} is not an update branch",
            op.id.0
        )
        .into());
    };
    let [
        ValueRef::State(input),
        ValueRef::Constant(encoding_constant_id),
    ] = ordered_inputs.as_slice()
    else {
        return Err(format!(
            "root {operation} update branch {} expected state and encoding constant operands, found {}",
            op.id.0,
            ordered_inputs.len()
        )
        .into());
    };
    if !op.inputs.contains(&ValueRef::State(*input)) {
        return Err(format!(
            "root {operation} update branch {} state operand is not declared as an op input",
            op.id.0
        )
        .into());
    }
    let encoding_constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == *encoding_constant_id)
        .ok_or_else(|| {
            format!(
                "root {operation} update branch {} references missing encoding constant {}",
                op.id.0, encoding_constant_id.0
            )
        })?;
    let PlanConstantValue::Text { value: encoding } = &encoding_constant.value else {
        return Err(format!(
            "root {operation} update branch {} encoding constant {} is not TEXT",
            op.id.0, encoding_constant_id.0
        )
        .into());
    };
    let Some(normalized_encoding) = runtime_normalized_encoding(encoding) else {
        return Err(format!(
            "root {operation} update branch {} encoding constant {} is unsupported: `{encoding}`",
            op.id.0, encoding_constant_id.0
        )
        .into());
    };
    Ok((
        *input,
        normalized_encoding.to_owned(),
        *encoding_constant_id,
    ))
}

fn plan_text_constant_value(
    plan: &MachinePlan,
    constant_id: PlanConstantId,
    operation: &str,
    op_id: usize,
) -> RuntimeResult<String> {
    let constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == constant_id)
        .ok_or_else(|| {
            format!(
                "root {operation} update branch {op_id} references missing text constant {}",
                constant_id.0
            )
        })?;
    let PlanConstantValue::Text { value } = &constant.value else {
        return Err(format!(
            "root {operation} update branch {op_id} constant {} is not TEXT",
            constant_id.0
        )
        .into());
    };
    Ok(value.clone())
}

fn root_prefix_concat_operands(
    plan: &MachinePlan,
    op: &boon_plan::PlanOp,
    operation: &str,
) -> RuntimeResult<(String, ValueRef, String)> {
    let PlanOpKind::UpdateBranch { ordered_inputs, .. } = &op.kind else {
        return Err(format!(
            "root {operation} update branch {} is not an update branch",
            op.id.0
        )
        .into());
    };
    let [
        ValueRef::Constant(prefix_id),
        input,
        ValueRef::Constant(separator_id),
    ] = ordered_inputs.as_slice()
    else {
        return Err(format!(
            "root {operation} update branch {} expected prefix constant, text input, and separator constant operands, found {}",
            op.id.0,
            ordered_inputs.len()
        )
        .into());
    };
    Ok((
        plan_text_constant_value(plan, *prefix_id, operation, op.id.0)?,
        input.clone(),
        plan_text_constant_value(plan, *separator_id, operation, op.id.0)?,
    ))
}

fn root_single_source_payload_input(
    op: &boon_plan::PlanOp,
    active_source_id: SourceId,
) -> RuntimeResult<Option<SourcePayloadField>> {
    let mut inputs = Vec::new();
    for input in &op.inputs {
        if let ValueRef::SourcePayload { source_id, field } = input
            && *source_id == active_source_id
            && !inputs.contains(field)
        {
            inputs.push(field.clone());
        }
    }
    match inputs.as_slice() {
        [] => Ok(None),
        [field] => Ok(Some(field.clone())),
        _ => Err(format!(
            "root update branch {} has ambiguous source-payload inputs",
            op.id.0
        )
        .into()),
    }
}

fn root_text_trim_input(
    op: &boon_plan::PlanOp,
    output_state_id: StateId,
) -> RuntimeResult<StateId> {
    let mut non_output_inputs = Vec::new();
    let mut output_present = false;
    for input in &op.inputs {
        let ValueRef::State(state_id) = input else {
            continue;
        };
        if *state_id == output_state_id {
            output_present = true;
        } else if !non_output_inputs.contains(state_id) {
            non_output_inputs.push(*state_id);
        }
    }
    match non_output_inputs.as_slice() {
        [input] => Ok(*input),
        [] if output_present => Ok(output_state_id),
        [] => Err(format!(
            "root TextTrimOrPrevious update branch {} has no typed state input",
            op.id.0
        )
        .into()),
        _ => Err(format!(
            "root TextTrimOrPrevious update branch {} has ambiguous non-output state inputs",
            op.id.0
        )
        .into()),
    }
}

fn root_state_value<'a>(
    plan: &MachinePlan,
    root_state: &'a serde_json::Map<String, JsonValue>,
    state_id: StateId,
    op_id: usize,
) -> RuntimeResult<&'a JsonValue> {
    let label = plan_state_label(plan, state_id.0);
    root_state.get(&label).ok_or_else(|| {
        format!("root update branch {op_id} input state `{label}` is missing").into()
    })
}

fn root_update_value_ref_json(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    event: &LiveSourceEvent,
    source_route_slot: &boon_plan::SourceRoute,
    input: &ValueRef,
    op_id: usize,
) -> RuntimeResult<JsonValue> {
    match input {
        ValueRef::State(state_id) => {
            Ok(root_state_value(plan, root_state, *state_id, op_id)?.clone())
        }
        ValueRef::Field(field_id) => {
            let derived_label = plan_derived_field_label(plan, field_id.0);
            if let Some(value) = root_state.get(&derived_label).cloned() {
                return Ok(value);
            }
            let semantic_label = plan_semantic_field_label(plan, field_id.0);
            if let Some(value) = root_state.get(&semantic_label).cloned() {
                return Ok(value);
            }
            let local_name = local_field_name(&semantic_label);
            if let Some(value) =
                root_update_event_field_value(event, source_route_slot, &local_name)
            {
                return Ok(value);
            }
            Err(format!(
                "root update branch {op_id} cannot resolve field input `{semantic_label}` from root state or source event"
            )
            .into())
        }
        ValueRef::SourcePayload { source_id, field } => {
            if *source_id != source_route_slot.source_id {
                return Err(format!(
                    "root update branch {op_id} source payload input belongs to source {} but route source is {}",
                    source_id.0, source_route_slot.source_id.0
                )
                .into());
            }
            source_payload_json_value(event, field)
        }
        ValueRef::Constant(constant_id) => plan
            .constants
            .iter()
            .find(|constant| constant.id == *constant_id)
            .ok_or_else(|| {
                format!(
                    "root update branch {op_id} missing constant {}",
                    constant_id.0
                )
                .into()
            })
            .and_then(plan_executor_constant_json_value),
        other => Err(format!(
            "root update branch {op_id} cannot resolve non-scalar input `{other:?}`"
        )
        .into()),
    }
}

fn root_update_event_field_value(
    event: &LiveSourceEvent,
    source_route_slot: &boon_plan::SourceRoute,
    field_name: &str,
) -> Option<JsonValue> {
    if source_route_slot.payload_schema.row_lookup_field_name() == Some(field_name) {
        return live_source_event_payload_text_value(event, field_name)
            .or_else(|| event.address.as_deref())
            .map(|value| JsonValue::String(value.to_owned()));
    }
    live_source_event_payload_text_value(event, field_name)
        .map(|value| JsonValue::String(value.to_owned()))
}

fn live_source_event_payload_text_value<'a>(
    event: &'a LiveSourceEvent,
    field: &str,
) -> Option<&'a str> {
    match field {
        "key" => event.key.as_deref(),
        "text" => event.text.as_deref(),
        "address" => event.address.as_deref(),
        "pointer_x" => event
            .pointer_x
            .as_deref()
            .or_else(|| event.payload.get(field).map(String::as_str)),
        "pointer_y" => event
            .pointer_y
            .as_deref()
            .or_else(|| event.payload.get(field).map(String::as_str)),
        "pointer_width" => event
            .pointer_width
            .as_deref()
            .or_else(|| event.payload.get(field).map(String::as_str)),
        "pointer_height" => event
            .pointer_height
            .as_deref()
            .or_else(|| event.payload.get(field).map(String::as_str)),
        _ => event.payload.get(field).map(String::as_str),
    }
}

fn plan_initial_list_rows_for_root_lookup(
    plan: &MachinePlan,
    list_id: boon_plan::ListId,
    op_id: usize,
) -> RuntimeResult<Vec<PlanListRowState>> {
    let mut lists = plan_initial_list_state(plan)?;
    let root_state = initialize_plan_root_state(plan)?;
    refresh_plan_initial_list_state_with_root_context(plan, &root_state.root_state, &mut lists)?;
    lists.remove(&list_id.0).ok_or_else(|| {
        format!(
            "root List/find_value update branch {op_id} list {} is missing from initial list state",
            list_id.0
        )
        .into()
    })
}

fn root_fixed_bytes_report_json(bytes: &[u8]) -> JsonValue {
    json!({
        "$boon_type": "BYTES",
        "storage": "inline",
        "digest": sha256_bytes(bytes),
        "byte_len": bytes.len() as u64,
    })
}

fn json_value_is_bytes_report(value: &JsonValue) -> bool {
    value.get("$boon_type").and_then(JsonValue::as_str) == Some("BYTES")
}

fn root_fixed_bytes_report_json_with_patches(
    bytes: &[u8],
    patches: &[(usize, u8)],
    operation: &str,
    op_id: usize,
    input_label: &str,
) -> RuntimeResult<JsonValue> {
    if patches.is_empty() {
        return Ok(root_fixed_bytes_report_json(bytes));
    }
    let mut cursor = 0usize;
    let mut hasher = Sha256::new();
    for (index, byte_value) in patches {
        if *index >= bytes.len() {
            return Err(format!(
                "root {operation} update branch {op_id} index {index} is out of bounds for `{input_label}`"
            )
            .into());
        }
        if *index < cursor {
            return Err(format!(
                "root {operation} update branch {op_id} has duplicate or unordered patch index {index} for `{input_label}`"
            )
            .into());
        }
        hasher.update(&bytes[cursor..*index]);
        hasher.update([*byte_value]);
        cursor = *index + 1;
    }
    hasher.update(&bytes[cursor..]);
    let digest = format!("{:x}", hasher.finalize());
    Ok(json!({
        "$boon_type": "BYTES",
        "storage": "inline",
        "digest": digest,
        "byte_len": bytes.len() as u64,
    }))
}

fn root_state_has_fixed_byte_bank(plan: &MachinePlan, state_id: StateId) -> bool {
    plan.storage_layout
        .byte_banks
        .iter()
        .any(|bank| !bank.indexed && bank.state_id == state_id)
}

fn root_fixed_bytes_state_bytes<'a>(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    root_fixed_bytes_banks: &'a RootFixedBytesBanks,
    state_id: StateId,
    op_id: usize,
) -> RuntimeResult<Option<&'a [u8]>> {
    let Some(bytes) = root_fixed_bytes_banks.get(&state_id.0) else {
        return Ok(None);
    };
    let label = plan_state_label(plan, state_id.0);
    let public_value = root_state_value(plan, root_state, state_id, op_id)?;
    if public_value.get("$boon_type").and_then(JsonValue::as_str) != Some("BYTES") {
        return Err(
            format!("root update branch {op_id} input state `{label}` is not BYTES").into(),
        );
    }
    let expected_summary = root_fixed_bytes_report_json(bytes);
    if &expected_summary != public_value {
        return Err(format!(
            "root update branch {op_id} fixed byte bank `{label}` public summary does not match private bank state"
        )
        .into());
    }
    Ok(Some(bytes))
}

fn root_state_inline_bytes(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    root_bytes_state: &RootBytesState,
    root_fixed_bytes_banks: &RootFixedBytesBanks,
    state_id: StateId,
    op_id: usize,
) -> RuntimeResult<Bytes> {
    let label = plan_state_label(plan, state_id.0);
    let public_value = root_state_value(plan, root_state, state_id, op_id)?;
    if public_value.get("$boon_type").and_then(JsonValue::as_str) != Some("BYTES") {
        return Err(
            format!("root update branch {op_id} input state `{label}` is not BYTES").into(),
        );
    }
    let public_digest = public_value.get("digest").and_then(JsonValue::as_str);
    let public_byte_len = public_value.get("byte_len").and_then(JsonValue::as_u64);
    if let Some(runtime_bytes) = root_bytes_state.get(&state_id.0) {
        let expected_summary = runtime_bytes.report_json();
        if &expected_summary != public_value {
            return Err(format!(
                "root update branch {op_id} bytes state `{label}` public summary does not match private byte state"
            )
            .into());
        }
        return Ok(runtime_bytes_copy_from_slice(runtime_bytes.inline_bytes()));
    }
    if let Some(bytes) =
        root_fixed_bytes_state_bytes(plan, root_state, root_fixed_bytes_banks, state_id, op_id)?
    {
        return Ok(runtime_bytes_copy_from_slice(bytes));
    }
    let slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == state_id)
        .ok_or_else(|| format!("root update branch {op_id} has no scalar slot for `{label}`"))?;
    let constant_id = slot.initial_constant_id.ok_or_else(|| {
        format!("root update branch {op_id} bytes state `{label}` has no typed initial constant")
    })?;
    let constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == constant_id)
        .ok_or_else(|| {
            format!(
                "root update branch {op_id} bytes state `{label}` references missing constant {}",
                constant_id.0
            )
        })?;
    let PlanConstantValue::Bytes {
        byte_len,
        sha256,
        inline_bytes: Some(bytes),
    } = &constant.value
    else {
        return Err(format!(
            "root update branch {op_id} bytes state `{label}` is not backed by an inline byte constant"
        )
        .into());
    };
    if public_byte_len != Some(*byte_len) || public_digest != Some(sha256.as_str()) {
        return Err(format!(
            "root update branch {op_id} bytes state `{label}` public summary does not match typed byte constant"
        )
        .into());
    }
    let runtime_bytes =
        RuntimeBytes::inline_with_digest(sha256.clone(), *byte_len, Bytes::copy_from_slice(bytes))?;
    runtime_bytes.inline_bytes().cloned()
}

fn root_state_bytes_view<'a>(
    plan: &MachinePlan,
    root_state: &serde_json::Map<String, JsonValue>,
    root_bytes_state: &'a RootBytesState,
    root_fixed_bytes_banks: &'a RootFixedBytesBanks,
    state_id: StateId,
    op_id: usize,
) -> RuntimeResult<RootBytesView<'a>> {
    let label = plan_state_label(plan, state_id.0);
    let public_value = root_state_value(plan, root_state, state_id, op_id)?;
    if public_value.get("$boon_type").and_then(JsonValue::as_str) != Some("BYTES") {
        return Err(
            format!("root update branch {op_id} input state `{label}` is not BYTES").into(),
        );
    }
    if let Some(runtime_bytes) = root_bytes_state.get(&state_id.0) {
        let expected_summary = runtime_bytes.report_json();
        if &expected_summary != public_value {
            return Err(format!(
                "root update branch {op_id} bytes state `{label}` public summary does not match private byte state"
            )
            .into());
        }
        return Ok(RootBytesView {
            bytes: Cow::Borrowed(runtime_bytes.inline_bytes()),
            access_source: "root_bytes_state",
            cow_kind: "borrowed",
        });
    }
    if let Some(bytes) =
        root_fixed_bytes_state_bytes(plan, root_state, root_fixed_bytes_banks, state_id, op_id)?
    {
        return Ok(RootBytesView {
            bytes: Cow::Borrowed(bytes),
            access_source: "root_fixed_byte_bank",
            cow_kind: "borrowed",
        });
    }
    Ok(RootBytesView {
        bytes: Cow::Owned(
            root_state_inline_bytes(
                plan,
                root_state,
                root_bytes_state,
                root_fixed_bytes_banks,
                state_id,
                op_id,
            )?
            .to_vec(),
        ),
        access_source: "typed_initial_constant_fallback",
        cow_kind: "owned",
    })
}

fn resolve_plan_row_index(
    plan: &MachinePlan,
    source_route_slot: &boon_plan::SourceRoute,
    event: &GenericSourceEvent<'_>,
    list_slot: &boon_plan::ListStorageSlot,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
) -> RuntimeResult<usize> {
    let list_label = plan_list_label(plan, list_slot.list_id.0);
    let rows = list_state
        .get(&list_slot.list_id.0)
        .ok_or_else(|| format!("list state missing list {}", list_slot.list_id.0))?;
    if let Some(target_key) = event.target_key {
        let target_generation = event.target_generation.ok_or_else(|| {
            format!(
                "scoped source `{}` supplied target_key without target_generation",
                event.source
            )
        })?;
        let index = rows
            .iter()
            .position(|row| row.key == target_key && row.generation == target_generation)
            .ok_or_else(|| {
                format!(
                    "scoped source `{}` target key/generation {target_key}/{target_generation} not found in `{list_label}`",
                    event.source
                )
            })?;
        validate_plan_row_binding_epoch(plan, source_route_slot, list_slot, &rows[index], event)?;
        return Ok(index);
    }
    if let Some(lookup_field) = source_route_slot.payload_schema.row_lookup_field_name()
        && let Some(lookup_value) = generic_source_event_row_lookup_value(event, lookup_field)
        && let Some(index) = rows.iter().position(|row| {
            row.fields.get(lookup_field).and_then(JsonValue::as_str) == Some(lookup_value)
        })
    {
        validate_plan_row_binding_epoch(plan, source_route_slot, list_slot, &rows[index], event)?;
        return Ok(index);
    }
    let Some(target_text) = event.target_text else {
        return Err(format!(
            "scoped source `{}` needs target_key, row lookup payload, address, or target_text to resolve a row",
            event.source
        )
        .into());
    };
    let occurrence = event.target_occurrence.unwrap_or(1).max(1);
    let mut seen = 0usize;
    for (index, row) in rows.iter().enumerate() {
        if row
            .fields
            .values()
            .any(|value| value.as_str() == Some(target_text))
        {
            seen += 1;
            if seen == occurrence {
                validate_plan_row_binding_epoch(plan, source_route_slot, list_slot, row, event)?;
                return Ok(index);
            }
        }
    }
    Err(format!(
        "scoped source `{}` target_text `{target_text}` occurrence {occurrence} not found in `{list_label}`",
        event.source
    )
    .into())
}

fn validate_plan_row_binding_epoch(
    plan: &MachinePlan,
    source_route_slot: &boon_plan::SourceRoute,
    list_slot: &boon_plan::ListStorageSlot,
    row: &PlanListRowState,
    event: &GenericSourceEvent<'_>,
) -> RuntimeResult<()> {
    let Some(source_binding_id) =
        plan_row_source_binding_id(plan, list_slot, row.key, source_route_slot.source_id)
    else {
        return Ok(());
    };
    let expected_epoch = event.bind_epoch.or(event.source_epoch);
    if expected_epoch.is_some_and(|epoch| epoch != source_binding_id) {
        return Err(format!(
            "scoped source `{}` bind_epoch/source_epoch does not match row binding id {source_binding_id}",
            event.source
        )
        .into());
    }
    Ok(())
}

fn plan_row_source_binding_id(
    plan: &MachinePlan,
    list_slot: &boon_plan::ListStorageSlot,
    key: u64,
    source_id: SourceId,
) -> Option<u64> {
    let routes = row_scoped_source_routes(plan, list_slot);
    let route_source_ids = routes
        .iter()
        .map(|route| route.source_id)
        .collect::<Vec<_>>();
    plan_row_source_binding_id_core(key, &route_source_ids, source_id)
}

fn row_resolution_report(
    event: &GenericSourceEvent<'_>,
    row_index: usize,
    row: &PlanListRowState,
    source_binding_id: Option<u64>,
    row_lookup_field: Option<&str>,
) -> JsonValue {
    json!({
        "method": if event.target_key.is_some() {
            "key_generation"
        } else if row_lookup_field
            .and_then(|field| generic_source_event_payload_value(event, field))
            .is_some()
        {
            "row_lookup_payload"
        } else if event.address.is_some() {
            "address"
        } else {
            "target_text"
        },
        "row_lookup_field": row_lookup_field,
        "row_lookup_payload": row_lookup_field.and_then(|field| generic_source_event_payload_value(event, field)),
        "target_text": event.target_text,
        "target_occurrence": event.target_occurrence,
        "target_key": event.target_key,
        "target_generation": event.target_generation,
        "address": event.address,
        "row_index": row_index,
        "key": row.key,
        "generation": row.generation,
        "source_binding_id": source_binding_id,
    })
}

fn refresh_indexed_derived_fields_after_state_change(
    plan: &MachinePlan,
    changed_list_slot: &boon_plan::ListStorageSlot,
    changed_list_label: &str,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    changed_row_index: usize,
) -> RuntimeResult<Vec<JsonValue>> {
    let mut deltas = refresh_indexed_derived_fields_for_row_with_options(
        plan,
        changed_list_slot,
        changed_list_label,
        list_state,
        changed_row_index,
        IndexedDerivedRefreshOptions {
            suppress_recursive_cycle_values: false,
            sort_cycle_error_first: true,
            evaluate_demand_current_ops: true,
            emit_demand_current_deltas: false,
            changed_root_states: None,
            root_state: None,
        },
    )?;
    if deltas
        .iter()
        .any(|delta| plan_delta_reports_cycle_error(delta))
    {
        return Ok(deltas);
    }
    deltas.extend(refresh_other_indexed_derived_fields(
        plan,
        list_state,
        changed_list_slot.list_id.0,
        changed_row_index,
    )?);
    Ok(deltas)
}

fn refresh_indexed_derived_fields_for_row(
    plan: &MachinePlan,
    list_slot: &boon_plan::ListStorageSlot,
    list_label: &str,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    row_index: usize,
    suppress_recursive_cycle_values: bool,
    sort_cycle_error_first: bool,
) -> RuntimeResult<Vec<JsonValue>> {
    refresh_indexed_derived_fields_for_row_with_options(
        plan,
        list_slot,
        list_label,
        list_state,
        row_index,
        IndexedDerivedRefreshOptions {
            suppress_recursive_cycle_values,
            sort_cycle_error_first,
            evaluate_demand_current_ops: true,
            emit_demand_current_deltas: true,
            changed_root_states: None,
            root_state: None,
        },
    )
}

fn apply_indexed_source_event_transforms_for_row(
    plan: &MachinePlan,
    source_id: SourceId,
    list_slot: &boon_plan::ListStorageSlot,
    list_label: &str,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    row_index: usize,
) -> RuntimeResult<Vec<JsonValue>> {
    let mut row_eval = list_state
        .get(&list_slot.list_id.0)
        .and_then(|rows| rows.get(row_index))
        .cloned()
        .ok_or_else(|| format!("row index {row_index} missing in `{list_label}`"))?;
    let mut changed_fields = Vec::new();
    for op in plan
        .regions
        .iter()
        .filter(|region| region.kind == RegionKind::DerivedEvaluation)
        .flat_map(|region| region.ops.iter())
    {
        if !op.indexed {
            continue;
        }
        let Some(ValueRef::Field(output_id)) = op.output else {
            continue;
        };
        if !plan_row_expression_applies_to_list(plan, list_slot, output_id) {
            continue;
        }
        let PlanOpKind::DerivedValue {
            derived_kind: boon_plan::PlanDerivedKind::SourceEventTransform,
            expression: Some(PlanDerivedExpression::SourceEventTransform { arms, .. }),
            ..
        } = &op.kind
        else {
            continue;
        };
        let Some(arm) = arms.iter().find(|arm| arm.source_id == source_id) else {
            continue;
        };
        if plan_row_expression_row_input_missing(plan, &row_eval, &arm.value) {
            continue;
        }
        let output_name = local_field_name(&plan_semantic_field_label(plan, output_id.0));
        let value =
            eval_plan_row_expression(plan, list_state, &row_eval, &arm.value).map_err(|error| {
                format!(
                    "indexed source event transform op {} row {}: {error}",
                    op.id.0, row_eval.key
                )
            })?;
        if row_eval.fields.get(&output_name) == Some(&value) {
            continue;
        }
        row_eval.fields.insert(output_name.clone(), value.clone());
        changed_fields.push((output_name, value));
    }
    if changed_fields.is_empty() {
        return Ok(Vec::new());
    }
    let row = list_state
        .get_mut(&list_slot.list_id.0)
        .and_then(|rows| rows.get_mut(row_index))
        .ok_or_else(|| format!("row index {row_index} missing in `{list_label}`"))?;
    let mut deltas = Vec::new();
    for (field_name, value) in changed_fields {
        row.fields.insert(field_name.clone(), value.clone());
        deltas.push(json!({
            "kind": "FieldSet",
            "list_id": list_label,
            "key": row.key,
            "generation": row.generation,
            "source_id": null,
            "bind_epoch": null,
            "field_path": field_name,
            "value": value,
        }));
    }
    Ok(deltas)
}

#[derive(Clone, Copy)]
struct IndexedDerivedRefreshOptions<'a> {
    suppress_recursive_cycle_values: bool,
    sort_cycle_error_first: bool,
    evaluate_demand_current_ops: bool,
    emit_demand_current_deltas: bool,
    changed_root_states: Option<&'a BTreeSet<StateId>>,
    root_state: Option<&'a serde_json::Map<String, JsonValue>>,
}

fn refresh_indexed_derived_fields_for_row_with_options(
    plan: &MachinePlan,
    list_slot: &boon_plan::ListStorageSlot,
    list_label: &str,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    row_index: usize,
    options: IndexedDerivedRefreshOptions<'_>,
) -> RuntimeResult<Vec<JsonValue>> {
    let mut row_eval = list_state
        .get(&list_slot.list_id.0)
        .and_then(|rows| rows.get(row_index))
        .cloned()
        .ok_or_else(|| format!("row index {row_index} missing in `{list_label}`"))?;
    if let Some(root_state) = options.root_state {
        row_eval = plan_executor_row_with_root_values(plan, &row_eval, root_state);
    }
    let mut changed_fields = Vec::new();
    for op in plan
        .regions
        .iter()
        .filter(|region| region.kind == RegionKind::DerivedEvaluation)
        .flat_map(|region| region.ops.iter())
    {
        if !op.indexed {
            continue;
        }
        let demand_current = plan_indexed_derived_op_is_demand_current(op);
        if demand_current && !options.evaluate_demand_current_ops {
            continue;
        }
        if let Some(changed_root_states) = options.changed_root_states {
            let Some(expression) = plan_op_derived_expression(op) else {
                continue;
            };
            if !changed_root_states
                .iter()
                .any(|state_id| plan_derived_expression_contains_state(expression, *state_id))
            {
                continue;
            }
        }
        let Some(ValueRef::Field(output_id)) = op.output else {
            continue;
        };
        let Some(value) =
            eval_indexed_derived_row_value(plan, list_slot, list_state, &row_eval, op, output_id)?
        else {
            continue;
        };
        if options.suppress_recursive_cycle_values
            && row_value_is_cycle_error(&value)
            && !plan_op_is_error_text_row_expression(op)
        {
            continue;
        }
        let output_name = local_field_name(&plan_semantic_field_label(plan, output_id.0));
        if row_eval.fields.get(&output_name) == Some(&value) {
            continue;
        }
        row_eval.fields.insert(output_name.clone(), value.clone());
        changed_fields.push((
            output_name,
            value,
            !demand_current || options.emit_demand_current_deltas,
        ));
    }
    if changed_fields.is_empty() {
        return Ok(Vec::new());
    }
    if options.sort_cycle_error_first {
        changed_fields.sort_by_key(|(field_name, _, _)| {
            if field_name == "error" {
                0
            } else if field_name == "value" {
                1
            } else {
                2
            }
        });
    }
    let row = list_state
        .get_mut(&list_slot.list_id.0)
        .and_then(|rows| rows.get_mut(row_index))
        .ok_or_else(|| format!("row index {row_index} missing in `{list_label}`"))?;
    let mut deltas = Vec::new();
    for (field_name, value, emit_delta) in changed_fields {
        row.fields.insert(field_name.clone(), value.clone());
        if emit_delta {
            deltas.push(json!({
                "kind": "FieldSet",
                "list_id": list_label,
                "key": row.key,
                "generation": row.generation,
                "source_id": null,
                "bind_epoch": null,
                "field_path": field_name,
                "value": value,
            }));
        }
    }
    Ok(deltas)
}

fn stale_empty_text_indexed_derived_deltas(
    plan: &MachinePlan,
    list_slot: &boon_plan::ListStorageSlot,
    list_label: &str,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
    row_index: usize,
    source_id: SourceId,
    current_op_id: usize,
) -> RuntimeResult<Vec<JsonValue>> {
    let later_states =
        later_indexed_derived_feeding_states_for_source(plan, source_id, current_op_id);
    if later_states.is_empty() {
        return Ok(Vec::new());
    }
    let row = list_state
        .get(&list_slot.list_id.0)
        .and_then(|rows| rows.get(row_index))
        .ok_or_else(|| format!("row index {row_index} missing in `{list_label}`"))?;
    let mut deltas = Vec::new();
    for op in plan
        .regions
        .iter()
        .filter(|region| region.kind == RegionKind::DerivedEvaluation)
        .flat_map(|region| region.ops.iter())
    {
        if !op.indexed || plan_op_is_error_text_row_expression(op) {
            continue;
        }
        let Some(ValueRef::Field(output_id)) = op.output else {
            continue;
        };
        let PlanOpKind::DerivedValue {
            derived_kind: boon_plan::PlanDerivedKind::Pure,
            expression: Some(PlanDerivedExpression::RowExpression { expression }),
            ..
        } = &op.kind
        else {
            continue;
        };
        if !plan_row_expression_applies_to_list(plan, list_slot, output_id)
            || !later_states
                .iter()
                .any(|state_id| plan_row_expression_contains_state(expression, *state_id))
        {
            continue;
        }
        if plan_row_expression_row_input_missing(plan, row, expression) {
            continue;
        }
        let output_name = local_field_name(&plan_semantic_field_label(plan, output_id.0));
        let value =
            eval_plan_row_expression(plan, list_state, row, expression).map_err(|error| {
                format!(
                    "stale empty indexed derived op {} row {}: {error}",
                    op.id.0, row.key
                )
            })?;
        if value.as_str() != Some("") || row.fields.get(&output_name) != Some(&value) {
            continue;
        }
        deltas.push(json!({
            "kind": "FieldSet",
            "list_id": list_label,
            "key": row.key,
            "generation": row.generation,
            "source_id": null,
            "bind_epoch": null,
            "field_path": output_name,
            "value": value,
        }));
    }
    Ok(deltas)
}

fn refresh_other_indexed_derived_fields(
    plan: &MachinePlan,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    skipped_list_id: usize,
    skipped_row_index: usize,
) -> RuntimeResult<Vec<JsonValue>> {
    let mut deltas = Vec::new();
    for list_slot in &plan.storage_layout.list_slots {
        let row_count = list_state
            .get(&list_slot.list_id.0)
            .map(Vec::len)
            .unwrap_or_default();
        let list_label = plan_list_label(plan, list_slot.list_id.0);
        for row_index in 0..row_count {
            if list_slot.list_id.0 == skipped_list_id && row_index == skipped_row_index {
                continue;
            }
            deltas.extend(refresh_indexed_derived_fields_for_row_with_options(
                plan,
                list_slot,
                &list_label,
                list_state,
                row_index,
                IndexedDerivedRefreshOptions {
                    suppress_recursive_cycle_values: true,
                    sort_cycle_error_first: true,
                    evaluate_demand_current_ops: true,
                    emit_demand_current_deltas: false,
                    changed_root_states: None,
                    root_state: None,
                },
            )?);
        }
    }
    Ok(deltas)
}

fn refresh_indexed_derived_fields_after_root_state_changes(
    plan: &MachinePlan,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    changed_root_state_ids: &BTreeSet<StateId>,
) -> RuntimeResult<Vec<JsonValue>> {
    if changed_root_state_ids.is_empty() {
        return Ok(Vec::new());
    }
    let mut deltas = Vec::new();
    for list_slot in &plan.storage_layout.list_slots {
        let row_count = list_state
            .get(&list_slot.list_id.0)
            .map(Vec::len)
            .unwrap_or_default();
        let list_label = plan_list_label(plan, list_slot.list_id.0);
        for row_index in 0..row_count {
            deltas.extend(refresh_indexed_derived_fields_for_row_with_options(
                plan,
                list_slot,
                &list_label,
                list_state,
                row_index,
                IndexedDerivedRefreshOptions {
                    suppress_recursive_cycle_values: true,
                    sort_cycle_error_first: true,
                    evaluate_demand_current_ops: false,
                    emit_demand_current_deltas: true,
                    changed_root_states: Some(changed_root_state_ids),
                    root_state: None,
                },
            )?);
        }
    }
    Ok(deltas)
}

fn plan_delta_reports_cycle_error(delta: &JsonValue) -> bool {
    delta.get("field_path").and_then(JsonValue::as_str) == Some("error")
        && delta.get("value").is_some_and(row_value_is_cycle_error)
}

fn refresh_all_indexed_derived_fields(
    plan: &MachinePlan,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
) -> RuntimeResult<Vec<JsonValue>> {
    refresh_all_indexed_derived_fields_with_options(plan, list_state, true, true)
}

fn refresh_all_indexed_derived_fields_with_options(
    plan: &MachinePlan,
    list_state: &mut BTreeMap<usize, Vec<PlanListRowState>>,
    suppress_recursive_cycle_values: bool,
    sort_cycle_error_first: bool,
) -> RuntimeResult<Vec<JsonValue>> {
    let mut deltas = Vec::new();
    for list_slot in &plan.storage_layout.list_slots {
        let row_count = list_state
            .get(&list_slot.list_id.0)
            .map(Vec::len)
            .unwrap_or_default();
        let list_label = plan_list_label(plan, list_slot.list_id.0);
        for row_index in 0..row_count {
            deltas.extend(refresh_indexed_derived_fields_for_row(
                plan,
                list_slot,
                &list_label,
                list_state,
                row_index,
                suppress_recursive_cycle_values,
                sort_cycle_error_first,
            )?);
        }
    }
    Ok(deltas)
}

fn changed_root_state_ids_from_update_reports(update_reports: &[JsonValue]) -> BTreeSet<StateId> {
    update_reports
        .iter()
        .filter(|report| report.get("changed").and_then(JsonValue::as_bool) == Some(true))
        .filter_map(|report| report.get("target_state_id").and_then(JsonValue::as_u64))
        .map(|state_id| StateId(state_id as usize))
        .collect()
}

fn plan_indexed_derived_op_is_demand_current(op: &boon_plan::PlanOp) -> bool {
    matches!(
        &op.kind,
        PlanOpKind::DerivedValue {
            startup_recompute: false,
            expression: Some(PlanDerivedExpression::RowExpression { .. }),
            ..
        } if op.indexed
    )
}

fn plan_op_derived_expression(op: &boon_plan::PlanOp) -> Option<&PlanDerivedExpression> {
    match &op.kind {
        PlanOpKind::DerivedValue {
            expression: Some(expression),
            ..
        } => Some(expression),
        _ => None,
    }
}

fn plan_op_is_error_text_row_expression(op: &boon_plan::PlanOp) -> bool {
    matches!(
        &op.kind,
        PlanOpKind::DerivedValue {
            expression: Some(PlanDerivedExpression::RowExpression {
                expression: PlanRowExpression::BuiltinCall { function, .. },
            }),
            ..
        } if function == "Error/text"
    )
}

fn source_has_later_indexed_state_feeding_derived(
    plan: &MachinePlan,
    source_id: SourceId,
    current_op_id: usize,
) -> bool {
    !later_indexed_derived_feeding_states_for_source(plan, source_id, current_op_id).is_empty()
}

fn later_indexed_derived_feeding_states_for_source(
    plan: &MachinePlan,
    source_id: SourceId,
    current_op_id: usize,
) -> Vec<StateId> {
    plan.regions
        .iter()
        .filter(|region| region.kind == RegionKind::UpdateBranches)
        .flat_map(|region| region.ops.iter())
        .filter_map(|op| {
            if !op.indexed
                || op.id.0 <= current_op_id
                || !op.inputs.contains(&ValueRef::Source(source_id))
            {
                return None;
            }
            let Some(ValueRef::State(state_id)) = op.output else {
                return None;
            };
            indexed_state_feeds_indexed_derived_expression(plan, state_id).then_some(state_id)
        })
        .collect()
}

fn indexed_state_feeds_indexed_derived_expression(plan: &MachinePlan, state_id: StateId) -> bool {
    plan.regions
        .iter()
        .filter(|region| region.kind == RegionKind::DerivedEvaluation)
        .flat_map(|region| region.ops.iter())
        .any(|op| {
            if !op.indexed {
                return false;
            }
            let PlanOpKind::DerivedValue {
                expression: Some(expression),
                ..
            } = &op.kind
            else {
                return false;
            };
            plan_derived_expression_contains_state(expression, state_id)
        })
}

fn plan_derived_expression_contains_state(
    expression: &PlanDerivedExpression,
    state_id: StateId,
) -> bool {
    match expression {
        PlanDerivedExpression::SourceKeyTextTrimNonEmpty { state, .. } => {
            *state == ValueRef::State(state_id)
        }
        PlanDerivedExpression::SourceEventTransform { default, arms, .. } => {
            plan_row_expression_contains_state(default, state_id)
                || arms
                    .iter()
                    .any(|arm| plan_row_expression_contains_state(&arm.value, state_id))
        }
        PlanDerivedExpression::BoolNot { input } => *input == ValueRef::State(state_id),
        PlanDerivedExpression::BoolAnd { left, right } => {
            plan_derived_expression_contains_state(left, state_id)
                || plan_derived_expression_contains_state(right, state_id)
        }
        PlanDerivedExpression::BoolNotExpression { input } => {
            plan_derived_expression_contains_state(input, state_id)
        }
        PlanDerivedExpression::RowExpression { expression } => {
            plan_row_expression_contains_state(expression, state_id)
        }
        PlanDerivedExpression::NumberCompareConst { left, .. } => {
            *left == ValueRef::State(state_id)
        }
    }
}

fn plan_row_expression_contains_state(expression: &PlanRowExpression, state_id: StateId) -> bool {
    match expression {
        PlanRowExpression::Field { input } => *input == ValueRef::State(state_id),
        PlanRowExpression::Object { fields } => fields
            .iter()
            .any(|field| plan_row_expression_contains_state(&field.value, state_id)),
        PlanRowExpression::TextTrim { input }
        | PlanRowExpression::TextIsEmpty { input }
        | PlanRowExpression::TextLength { input }
        | PlanRowExpression::TextToNumber { input }
        | PlanRowExpression::ObjectField { object: input, .. }
        | PlanRowExpression::ListSum { input } => {
            plan_row_expression_contains_state(input, state_id)
        }
        PlanRowExpression::TextStartsWith { input, prefix } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(prefix, state_id)
        }
        PlanRowExpression::TextSubstring {
            input,
            start,
            length,
        } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(start, state_id)
                || plan_row_expression_contains_state(length, state_id)
        }
        PlanRowExpression::TextToBytes { input, encoding } => {
            plan_row_expression_contains_state(input, state_id)
                || encoding
                    .as_deref()
                    .is_some_and(|encoding| plan_row_expression_contains_state(encoding, state_id))
        }
        PlanRowExpression::BytesToText { input, encoding } => {
            plan_row_expression_contains_state(input, state_id)
                || encoding
                    .as_deref()
                    .is_some_and(|encoding| plan_row_expression_contains_state(encoding, state_id))
        }
        PlanRowExpression::BytesToHex { input }
        | PlanRowExpression::BytesToBase64 { input }
        | PlanRowExpression::BytesFromHex { input }
        | PlanRowExpression::BytesFromBase64 { input } => {
            plan_row_expression_contains_state(input, state_id)
        }
        PlanRowExpression::BytesIsEmpty { input } => {
            plan_row_expression_contains_state(input, state_id)
        }
        PlanRowExpression::BytesLength { input } => {
            plan_row_expression_contains_state(input, state_id)
        }
        PlanRowExpression::BytesGet { input, index } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(index, state_id)
        }
        PlanRowExpression::BytesSlice {
            input,
            offset,
            byte_count,
        } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(offset, state_id)
                || plan_row_expression_contains_state(byte_count, state_id)
        }
        PlanRowExpression::BytesTake { input, byte_count }
        | PlanRowExpression::BytesDrop { input, byte_count } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(byte_count, state_id)
        }
        PlanRowExpression::BytesZeros { byte_count } => {
            plan_row_expression_contains_state(byte_count, state_id)
        }
        PlanRowExpression::BytesReadUnsigned {
            input,
            offset,
            byte_count,
            endian,
        }
        | PlanRowExpression::BytesReadSigned {
            input,
            offset,
            byte_count,
            endian,
        } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(offset, state_id)
                || plan_row_expression_contains_state(byte_count, state_id)
                || plan_row_expression_contains_state(endian, state_id)
        }
        PlanRowExpression::BytesSet {
            input,
            index,
            value,
        } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(index, state_id)
                || plan_row_expression_contains_state(value, state_id)
        }
        PlanRowExpression::BytesWriteUnsigned {
            input,
            offset,
            byte_count,
            endian,
            value,
        }
        | PlanRowExpression::BytesWriteSigned {
            input,
            offset,
            byte_count,
            endian,
            value,
        } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(offset, state_id)
                || plan_row_expression_contains_state(byte_count, state_id)
                || plan_row_expression_contains_state(endian, state_id)
                || plan_row_expression_contains_state(value, state_id)
        }
        PlanRowExpression::BytesFind { input, needle } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(needle, state_id)
        }
        PlanRowExpression::BytesStartsWith { input, prefix } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(prefix, state_id)
        }
        PlanRowExpression::BytesEndsWith { input, suffix } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(suffix, state_id)
        }
        PlanRowExpression::BytesConcat { left, right } => {
            plan_row_expression_contains_state(left, state_id)
                || plan_row_expression_contains_state(right, state_id)
        }
        PlanRowExpression::BytesEqual { left, right } => {
            plan_row_expression_contains_state(left, state_id)
                || plan_row_expression_contains_state(right, state_id)
        }
        PlanRowExpression::NumberInfix { left, right, .. } => {
            plan_row_expression_contains_state(left, state_id)
                || plan_row_expression_contains_state(right, state_id)
        }
        PlanRowExpression::TextConcat { parts } => parts
            .iter()
            .any(|part| plan_row_expression_contains_state(part, state_id)),
        PlanRowExpression::ListGetField { index, .. } => {
            plan_row_expression_contains_state(index, state_id)
        }
        PlanRowExpression::ListFindValue {
            value, fallback, ..
        } => {
            plan_row_expression_contains_state(value, state_id)
                || fallback
                    .as_deref()
                    .is_some_and(|fallback| plan_row_expression_contains_state(fallback, state_id))
        }
        PlanRowExpression::ListRange { from, to } => {
            plan_row_expression_contains_state(from, state_id)
                || plan_row_expression_contains_state(to, state_id)
        }
        PlanRowExpression::ListLiteral { items } => items
            .iter()
            .any(|item| plan_row_expression_contains_state(item, state_id)),
        PlanRowExpression::ListMap { input, value, .. } => {
            plan_row_expression_contains_state(input, state_id)
                || plan_row_expression_contains_state(value, state_id)
        }
        PlanRowExpression::BuiltinCall { input, args, .. } => {
            input
                .as_deref()
                .is_some_and(|input| plan_row_expression_contains_state(input, state_id))
                || args
                    .iter()
                    .any(|arg| plan_row_expression_contains_state(&arg.value, state_id))
        }
        PlanRowExpression::Select { input, arms } => {
            plan_row_expression_contains_state(input, state_id)
                || arms
                    .iter()
                    .any(|arm| plan_row_expression_contains_state(&arm.value, state_id))
        }
        PlanRowExpression::Constant { .. }
        | PlanRowExpression::ListRef { .. }
        | PlanRowExpression::ListMapItem { .. } => false,
    }
}

fn eval_indexed_derived_row_value(
    plan: &MachinePlan,
    list_slot: &boon_plan::ListStorageSlot,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
    row: &PlanListRowState,
    op: &boon_plan::PlanOp,
    output_id: FieldId,
) -> RuntimeResult<Option<JsonValue>> {
    let PlanOpKind::DerivedValue {
        derived_kind: boon_plan::PlanDerivedKind::Pure,
        expression: Some(expression),
        ..
    } = &op.kind
    else {
        return Ok(None);
    };
    match expression {
        PlanDerivedExpression::BoolNot { input } => {
            let Some(input_state_id) = (match input {
                ValueRef::State(state_id) => Some(state_id),
                _ => None,
            }) else {
                return Err(
                    format!("indexed Bool/not op {} input is not a state ref", op.id.0).into(),
                );
            };
            let Some(input_slot) = plan
                .storage_layout
                .scalar_slots
                .iter()
                .find(|slot| slot.state_id == *input_state_id)
            else {
                return Err(
                    format!("indexed Bool/not op {} input state is missing", op.id.0).into(),
                );
            };
            if input_slot.scope_id != list_slot.scope_id {
                return Ok(None);
            }
            let input_name = local_field_name(&plan_state_label(plan, input_state_id.0));
            let Some(input_value) = row.fields.get(&input_name).and_then(JsonValue::as_bool) else {
                return Ok(None);
            };
            Ok(Some(JsonValue::Bool(!input_value)))
        }
        PlanDerivedExpression::RowExpression { expression } => {
            if !plan_row_expression_applies_to_list(plan, list_slot, output_id) {
                return Ok(None);
            }
            if plan_row_expression_row_input_missing(plan, row, expression) {
                return Ok(None);
            }
            Ok(Some(
                eval_plan_row_expression(plan, list_state, row, expression).map_err(|error| {
                    format!("indexed derived op {} row {}: {error}", op.id.0, row.key)
                })?,
            ))
        }
        _ => Ok(None),
    }
}

fn execute_root_scalar_update_branch(
    plan: &MachinePlan,
    op: &boon_plan::PlanOp,
    source_id: SourceId,
    source_route_slot: &boon_plan::SourceRoute,
    event: &LiveSourceEvent,
    list_state: Option<&BTreeMap<usize, Vec<PlanListRowState>>>,
    root_state: &PlanExecutorRootState,
    host_file_root: Option<&Path>,
) -> RuntimeResult<Option<RootExecutedUpdate>> {
    let root_environment = root_state;
    let root_bytes_state = &root_environment.private_bytes;
    let root_fixed_bytes_banks = &root_environment.fixed_byte_banks;
    let root_state = &root_environment.root_state;
    let source_guard = match &op.kind {
        PlanOpKind::UpdateBranch { source_guard, .. } => source_guard,
        _ => {
            return Err(format!(
                "CPU PlanExecutor root update branch {} is not an update branch",
                op.id.0
            )
            .into());
        }
    };
    let root_json_event = root_json_source_event_from_live(event);
    if !plan_executor_source_guard_matches(source_guard, source_id, &root_json_event)? {
        return Ok(None);
    }
    let Some(ValueRef::State(output_state_id)) = op.output else {
        return Err(format!(
            "CPU PlanExecutor root update branch {} does not target a state slot",
            op.id.0
        )
        .into());
    };
    if let Some(bytes_dispatch) = plan_root_bytes_update_dispatch_kind(op) {
        let (
            value,
            bytes_value,
            fixed_bytes_mutation,
            bytes_access,
            executor_core,
            expression_kind,
            update_constant_id,
            update_constant_value,
            host_effect,
        ) = match bytes_dispatch {
            RootBytesUpdateDispatchKind::Read => {
                let evaluation = evaluate_root_bytes_read_update(
                    plan,
                    op,
                    root_state,
                    root_environment,
                    host_file_root,
                )?;
                if !evaluation.supported {
                    return Err(evaluation
                        .unsupported_reason
                        .unwrap_or_else(|| {
                            "root BYTES read evaluator did not support branch".to_owned()
                        })
                        .into());
                }
                let value = evaluation.value.ok_or_else(|| {
                    format!(
                        "root BYTES read evaluator reported supported branch {} without a value",
                        op.id.0
                    )
                })?;
                let expression_kind = evaluation.expression_kind.ok_or_else(|| {
                    format!(
                        "root BYTES read evaluator reported supported branch {} without an expression kind",
                        op.id.0
                    )
                })?;
                (
                    value,
                    evaluation.bytes,
                    None,
                    evaluation.bytes_access,
                    evaluation.executor_report,
                    expression_kind,
                    evaluation.update_constant_id,
                    evaluation.update_constant_value,
                    JsonValue::Null,
                )
            }
            RootBytesUpdateDispatchKind::Write => {
                let evaluation = evaluate_root_bytes_write_update(
                    plan,
                    op,
                    root_state,
                    root_environment,
                    host_file_root,
                )?;
                if !evaluation.supported {
                    return Err(evaluation
                        .unsupported_reason
                        .unwrap_or_else(|| {
                            "root BYTES write evaluator did not support branch".to_owned()
                        })
                        .into());
                }
                record_runtime_bytes_executor_copy_cost(&evaluation.executor_report);
                let value = evaluation.value.ok_or_else(|| {
                    format!(
                        "root BYTES write evaluator reported supported branch {} without a value",
                        op.id.0
                    )
                })?;
                let expression_kind = evaluation.expression_kind.ok_or_else(|| {
                    format!(
                        "root BYTES write evaluator reported supported branch {} without an expression kind",
                        op.id.0
                    )
                })?;
                (
                    value,
                    evaluation.bytes,
                    evaluation.fixed_mutation,
                    evaluation.bytes_access,
                    evaluation.executor_report,
                    expression_kind,
                    evaluation.update_constant_id,
                    evaluation.update_constant_value,
                    evaluation.host_effect,
                )
            }
        };
        return Ok(Some(assemble_plan_root_runtime_branch_update(
            RootRuntimeBranchUpdateInput {
                value,
                bytes_value,
                fixed_bytes_mutation,
                bytes_access,
                runtime_branch_core: executor_core,
                state_write_core: JsonValue::Null,
                bytes_state_core: JsonValue::Null,
                expression_kind: expression_kind.to_owned(),
                source_payload_field: JsonValue::Null,
                update_constant_id,
                update_constant_value,
                host_effect,
            },
        )));
    }
    let mut fixed_bytes_mutation = None;
    let mut executor_core = JsonValue::Null;
    let (
        value,
        bytes_value,
        expression_kind,
        source_payload_field,
        update_constant_id,
        update_constant_value,
    ) = match &op.kind {
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::SourcePayload,
            source_payload_field: Some(source_payload_field),
            update_constant_id: None,
            ..
        } => {
            if !source_route_slot
                .payload_schema
                .fields
                .contains(source_payload_field)
            {
                return Err(format!(
                    "selected update branch {} reads payload field {:?}, but route schema is {:?}",
                    op.id.0, source_payload_field, source_route_slot.payload_schema.fields
                )
                .into());
            }
            let typed_payload_ref_present = op.inputs.iter().any(|input| {
                matches!(
                    input,
                    ValueRef::SourcePayload {
                        source_id: input_source_id,
                        field
                    } if *input_source_id == source_id && field == source_payload_field
                )
            });
            if !typed_payload_ref_present {
                return Err(format!(
                    "selected update branch {} is missing typed SourcePayload input",
                    op.id.0
                )
                .into());
            }
            let (value, bytes_value) = if matches!(source_payload_field, SourcePayloadField::Bytes)
            {
                let root_json_event = root_json_source_event_from_live(event);
                let commit = evaluate_root_bytes_source_payload_commit(
                    plan,
                    output_state_id,
                    &root_json_event,
                    source_payload_field,
                    op.id,
                )?;
                executor_core = commit.executor_report;
                (commit.value, Some(commit.bytes))
            } else {
                source_payload_value_for_output(
                    plan,
                    output_state_id,
                    event,
                    source_payload_field,
                    op.id.0,
                )?
            };
            (
                value,
                bytes_value,
                "source_payload",
                serde_json::to_value(source_payload_field)?,
                JsonValue::Null,
                JsonValue::Null,
            )
        }
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::Const,
            source_payload_field: None,
            update_constant_id: Some(update_constant_id),
            ..
        } => {
            let constant = plan
                .constants
                .iter()
                .find(|constant| constant.id == *update_constant_id)
                .ok_or_else(|| format!("missing update constant {}", update_constant_id.0))?;
            let value = plan_executor_constant_json_value(constant)?;
            let bytes_value =
                plan_constant_executor_bytes_for_output(plan, output_state_id, constant, op.id.0)?;
            (
                value.clone(),
                bytes_value,
                "const",
                JsonValue::Null,
                json!(update_constant_id.0),
                value,
            )
        }
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::BoolNot,
            source_payload_field: None,
            update_constant_id: None,
            ..
        } => {
            let input_state_id = root_single_state_input(op)?;
            let input_value = root_state_value(plan, root_state, input_state_id, op.id.0)?
                .as_bool()
                .ok_or_else(|| {
                    let label = plan_state_label(plan, input_state_id.0);
                    format!(
                        "root Bool/not update branch {} input state `{label}` is not bool",
                        op.id.0
                    )
                })?;
            (
                JsonValue::Bool(!input_value),
                None,
                "bool_not",
                JsonValue::Null,
                JsonValue::Null,
                JsonValue::Null,
            )
        }
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::ReadPath,
            source_payload_field: None,
            update_constant_id: None,
            ..
        } => {
            if let Some(payload_field) = root_single_source_payload_input(op, source_id)? {
                let typed_payload_ref_present = op.inputs.iter().any(|input| {
                    matches!(
                        input,
                        ValueRef::SourcePayload {
                            source_id: input_source_id,
                            field
                        } if *input_source_id == source_id && *field == payload_field
                    )
                });
                if !typed_payload_ref_present {
                    return Err(format!(
                        "root ReadPath update branch {} is missing typed SourcePayload input",
                        op.id.0
                    )
                    .into());
                }
                (
                    source_payload_json_value(event, &payload_field)?,
                    None,
                    "read_path",
                    serde_json::to_value(&payload_field)?,
                    JsonValue::Null,
                    JsonValue::Null,
                )
            } else {
                let input_state_id = root_single_state_input(op)?;
                let value = root_state_value(plan, root_state, input_state_id, op.id.0)?.clone();
                let bytes_value =
                    if value.get("$boon_type").and_then(JsonValue::as_str) == Some("BYTES") {
                        if root_state_has_fixed_byte_bank(plan, output_state_id)
                            && root_fixed_bytes_state_bytes(
                                plan,
                                root_state,
                                root_fixed_bytes_banks,
                                input_state_id,
                                op.id.0,
                            )?
                            .is_some()
                        {
                            fixed_bytes_mutation = Some(RootBytesFixedMutation {
                                input_state_id,
                                output_state_id,
                                patches: Vec::new(),
                            });
                            None
                        } else if let Some(bytes) = root_bytes_state.get(&input_state_id.0) {
                            Some(bytes.clone())
                        } else if let Some(bytes) = root_fixed_bytes_state_bytes(
                            plan,
                            root_state,
                            root_fixed_bytes_banks,
                            input_state_id,
                            op.id.0,
                        )? {
                            Some(PlanExecutorBytes::from_inline(
                                sha256_bytes(bytes),
                                bytes.len() as u64,
                                bytes.to_vec(),
                                "root ReadPath fixed byte bank",
                            )?)
                        } else {
                            None
                        }
                    } else {
                        None
                    };
                (
                    value,
                    bytes_value,
                    "read_path",
                    JsonValue::Null,
                    JsonValue::Null,
                    JsonValue::Null,
                )
            }
        }
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::PreviousValue,
            source_payload_field: None,
            update_constant_id: None,
            ..
        } => {
            let input_state_id = root_single_state_input(op)?;
            let value = root_state_value(plan, root_state, input_state_id, op.id.0)?.clone();
            let bytes_value =
                if value.get("$boon_type").and_then(JsonValue::as_str) == Some("BYTES") {
                    if root_state_has_fixed_byte_bank(plan, output_state_id)
                        && root_fixed_bytes_state_bytes(
                            plan,
                            root_state,
                            root_fixed_bytes_banks,
                            input_state_id,
                            op.id.0,
                        )?
                        .is_some()
                    {
                        fixed_bytes_mutation = Some(RootBytesFixedMutation {
                            input_state_id,
                            output_state_id,
                            patches: Vec::new(),
                        });
                        None
                    } else if let Some(bytes) = root_bytes_state.get(&input_state_id.0) {
                        Some(bytes.clone())
                    } else if let Some(bytes) = root_fixed_bytes_state_bytes(
                        plan,
                        root_state,
                        root_fixed_bytes_banks,
                        input_state_id,
                        op.id.0,
                    )? {
                        Some(PlanExecutorBytes::from_inline(
                            sha256_bytes(bytes),
                            bytes.len() as u64,
                            bytes.to_vec(),
                            "root PreviousValue fixed byte bank",
                        )?)
                    } else {
                        None
                    }
                } else {
                    None
                };
            (
                value,
                bytes_value,
                "previous_value",
                JsonValue::Null,
                JsonValue::Null,
                JsonValue::Null,
            )
        }
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::ListFindValue,
            source_payload_field: None,
            update_constant_id: None,
            ordered_inputs,
            ..
        } => {
            let [
                ValueRef::List(list_id),
                ValueRef::Field(field_id),
                expected_ref,
                ValueRef::Field(target_id),
                rest @ ..,
            ] = ordered_inputs.as_slice()
            else {
                return Err(format!(
                    "root List/find_value update branch {} ordered inputs must be list, field, expected, target, optional fallback; got {:?}",
                    op.id.0, ordered_inputs
                )
                .into());
            };
            let expected = root_update_value_ref_json(
                plan,
                root_state,
                event,
                source_route_slot,
                expected_ref,
                op.id.0,
            )?;
            let field_name = plan_row_field_local_name(plan, *field_id);
            let target_name = plan_row_field_local_name(plan, *target_id);
            let initial_rows;
            let rows: &[PlanListRowState] =
                if let Some(rows) = list_state.and_then(|lists| lists.get(&list_id.0)) {
                    rows
                } else {
                    initial_rows = plan_initial_list_rows_for_root_lookup(plan, *list_id, op.id.0)?;
                    &initial_rows
                };
            let value = rows
                .iter()
                .find(|row| row_json_values_equal(row.fields.get(&field_name), &expected))
                .and_then(|row| row.fields.get(&target_name).cloned());
            let value = match value {
                Some(value) => value,
                None => {
                    let Some(fallback_ref) = rest.first() else {
                        return Err(format!(
                            "root List/find_value update branch {} found no row and has no fallback",
                            op.id.0
                        )
                        .into());
                    };
                    root_update_value_ref_json(
                        plan,
                        root_state,
                        event,
                        source_route_slot,
                        fallback_ref,
                        op.id.0,
                    )?
                }
            };
            (
                value,
                None,
                "list_find_value",
                JsonValue::Null,
                JsonValue::Null,
                JsonValue::Null,
            )
        }
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::TextTrimOrPrevious,
            source_payload_field,
            update_constant_id: None,
            ..
        } => {
            let raw = if let Some(payload_field) = source_payload_field {
                let typed_payload_ref_present = op.inputs.iter().any(|input| {
                    matches!(
                        input,
                        ValueRef::SourcePayload {
                            source_id: input_source_id,
                            field
                        } if *input_source_id == source_id && field == payload_field
                    )
                });
                if !typed_payload_ref_present {
                    return Err(format!(
                            "root TextTrimOrPrevious update branch {} is missing typed SourcePayload input",
                            op.id.0
                        )
                        .into());
                }
                source_payload_json_value(event, payload_field)?
                    .as_str()
                    .ok_or_else(|| {
                        format!(
                            "root TextTrimOrPrevious update branch {} payload is not text",
                            op.id.0
                        )
                    })?
                    .to_owned()
            } else {
                let input_state_id = root_text_trim_input(op, output_state_id)?;
                let input_label = plan_state_label(plan, input_state_id.0);
                root_state_value(plan, root_state, input_state_id, op.id.0)?
                        .as_str()
                        .ok_or_else(|| {
                            format!(
                                "root TextTrimOrPrevious update branch {} input state `{input_label}` is not text",
                                op.id.0
                            )
                        })?
                        .to_owned()
            };
            let output_label = plan_state_label(plan, output_state_id.0);
            let current = root_state
                    .get(&output_label)
                    .and_then(JsonValue::as_str)
                    .ok_or_else(|| {
                        format!(
                            "root TextTrimOrPrevious update branch {} output state `{output_label}` is not text",
                            op.id.0
                        )
                    })?;
            let trimmed = raw.trim();
            let value = if trimmed.is_empty() {
                current.to_owned()
            } else {
                trimmed.to_owned()
            };
            (
                JsonValue::String(value),
                None,
                "text_trim_or_previous",
                source_payload_field
                    .as_ref()
                    .map(serde_json::to_value)
                    .transpose()?
                    .unwrap_or(JsonValue::Null),
                JsonValue::Null,
                JsonValue::Null,
            )
        }
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::PrefixPayloadConcat,
            source_payload_field: Some(source_payload_field),
            update_constant_id: None,
            ..
        } => {
            if !source_route_slot
                .payload_schema
                .fields
                .contains(source_payload_field)
            {
                return Err(format!(
                    "root PrefixPayloadConcat update branch {} reads payload field {:?}, but route schema is {:?}",
                    op.id.0, source_payload_field, source_route_slot.payload_schema.fields
                )
                .into());
            }
            let (prefix, input, separator) =
                root_prefix_concat_operands(plan, op, "PrefixPayloadConcat")?;
            let input_value = root_update_value_ref_json(
                plan,
                root_state,
                event,
                source_route_slot,
                &input,
                op.id.0,
            )?;
            let payload = input_value.as_str().ok_or_else(|| {
                format!(
                    "root PrefixPayloadConcat update branch {} input is not text",
                    op.id.0
                )
            })?;
            (
                JsonValue::String(format!("{prefix}{separator}{payload}")),
                None,
                "prefix_payload_concat",
                serde_json::to_value(source_payload_field)?,
                JsonValue::Null,
                JsonValue::Null,
            )
        }
        PlanOpKind::UpdateBranch {
            expression_kind: PlanExpressionKind::PrefixRootConcat,
            source_payload_field: None,
            update_constant_id: None,
            ..
        } => {
            let (prefix, input, separator) =
                root_prefix_concat_operands(plan, op, "PrefixRootConcat")?;
            let input_value = root_update_value_ref_json(
                plan,
                root_state,
                event,
                source_route_slot,
                &input,
                op.id.0,
            )?;
            let value = input_value.as_str().ok_or_else(|| {
                format!(
                    "root PrefixRootConcat update branch {} input is not text",
                    op.id.0
                )
            })?;
            (
                JsonValue::String(format!("{prefix}{separator}{value}")),
                None,
                "prefix_root_concat",
                JsonValue::Null,
                JsonValue::Null,
                JsonValue::Null,
            )
        }
        _ => {
            return Err(format!(
                "selected root update branch {} has unsupported expression kind {:?}",
                op.id.0, op.kind
            )
            .into());
        }
    };
    Ok(Some(assemble_plan_root_runtime_branch_update(
        RootRuntimeBranchUpdateInput {
            value,
            bytes_value,
            fixed_bytes_mutation,
            bytes_access: JsonValue::Null,
            runtime_branch_core: executor_core,
            state_write_core: JsonValue::Null,
            bytes_state_core: JsonValue::Null,
            expression_kind: expression_kind.to_owned(),
            source_payload_field,
            update_constant_id,
            update_constant_value,
            host_effect: JsonValue::Null,
        },
    )))
}

fn plan_root_scalar_initial_state(
    plan: &MachinePlan,
) -> RuntimeResult<(PlanExecutorRootState, JsonValue, usize)> {
    let root_state = initialize_plan_root_state(plan)?;
    let executor_report = root_state.executor_report.clone();
    let initialized_state_count = root_state.initialized_state_count;
    Ok((root_state, executor_report, initialized_state_count))
}

fn plan_initial_list_state(
    plan: &MachinePlan,
) -> RuntimeResult<BTreeMap<usize, Vec<PlanListRowState>>> {
    let mut lists = BTreeMap::new();
    for slot in &plan.storage_layout.list_slots {
        let mut rows = Vec::new();
        for (index, initial_row) in slot.initial_rows.iter().enumerate() {
            let mut fields = BTreeMap::new();
            let mut private_bytes = BTreeMap::new();
            let mut fixed_bytes_banks = BTreeMap::new();
            for field in &initial_row.fields {
                let field_id = field.field_id.ok_or_else(|| {
                    format!(
                        "initial row field `{}` for list {} has no typed field id",
                        field.name, slot.list_id.0
                    )
                })?;
                let field_name = local_field_name(&plan_semantic_field_label(plan, field_id.0));
                let field_context = format!(
                    "initial row field `{}` for list {}",
                    field.name, slot.list_id.0
                );
                fields.insert(
                    field_name.clone(),
                    plan_executor_constant_value_json_value(&field.value, &field_context)?,
                );
                if let Some(bytes) =
                    plan_executor_constant_value_bytes(&field.value, &field_context)?
                {
                    if plan_indexed_field_has_fixed_byte_bank(plan, slot.scope_id, &field_name) {
                        fixed_bytes_banks.insert(field_name.clone(), bytes.inline_bytes().to_vec());
                    }
                    private_bytes.insert(field_name, bytes);
                }
            }
            let key = index as u64 + 1;
            let generation = 1;
            let _ = refresh_plan_list_row_bool_not_fields(
                plan,
                slot,
                &plan_list_label(plan, slot.list_id.0),
                key,
                generation,
                &mut fields,
            )?;
            rows.push(PlanListRowState {
                key,
                generation,
                fields,
                private_bytes,
                fixed_bytes_banks,
            });
        }
        if matches!(slot.initializer_kind, boon_plan::ListInitializerKind::Range) {
            let range = slot.range.ok_or_else(|| {
                format!(
                    "range list `{}` has no typed range bounds",
                    plan_list_label(plan, slot.list_id.0)
                )
            })?;
            let count = if range.from <= range.to {
                usize::try_from(range.to.saturating_sub(range.from).saturating_add(1))
                    .map_err(|_| "List/range row count is out of range")?
            } else {
                0
            };
            for (offset, value) in (range.from..=range.to).take(count).enumerate() {
                let mut fields = BTreeMap::new();
                let text = value.to_string();
                fields.insert("index".to_owned(), JsonValue::String(text.clone()));
                fields.insert("value".to_owned(), JsonValue::String(text));
                let (defaults, default_bytes, default_fixed_banks) =
                    plan_executor_list_row_default_fields_to_runtime(plan_list_row_default_fields(
                        plan, slot,
                    )?);
                for (field, value) in defaults {
                    fields.entry(field).or_insert(value);
                }
                let private_bytes = default_bytes;
                let fixed_bytes_banks = default_fixed_banks;
                let key = offset as u64 + 1;
                let generation = 1;
                let _ = refresh_plan_list_row_bool_not_fields(
                    plan,
                    slot,
                    &plan_list_label(plan, slot.list_id.0),
                    key,
                    generation,
                    &mut fields,
                )?;
                rows.push(PlanListRowState {
                    key,
                    generation,
                    fields,
                    private_bytes,
                    fixed_bytes_banks,
                });
            }
        }
        lists.insert(slot.list_id.0, rows);
    }
    Ok(lists)
}

fn plan_executor_list_row_default_fields_to_runtime(
    defaults: ListRowDefaultFields,
) -> (
    BTreeMap<String, JsonValue>,
    BTreeMap<String, PlanExecutorBytes>,
    BTreeMap<String, Vec<u8>>,
) {
    (
        defaults.fields,
        defaults.private_bytes,
        defaults.fixed_byte_banks,
    )
}

fn plan_row_field_local_name(plan: &MachinePlan, field_id: boon_plan::FieldId) -> String {
    local_field_name(&plan_semantic_field_label(plan, field_id.0))
}

fn plan_list_summary(
    plan: &MachinePlan,
    list_state: &BTreeMap<usize, Vec<PlanListRowState>>,
) -> JsonValue {
    let executor_rows = plan_executor_list_state_for_materialization(list_state);
    summarize_plan_lists_core(plan, &executor_rows)
}

fn source_has_unsupported_root_scenario_ops(plan: &MachinePlan, source_id: SourceId) -> bool {
    plan.regions
        .iter()
        .filter(|region| {
            matches!(
                region.kind,
                RegionKind::DerivedEvaluation
                    | RegionKind::ListOperations
                    | RegionKind::ListProjections
            )
        })
        .flat_map(|region| region.ops.iter())
        .any(|op| {
            op.inputs
                .iter()
                .any(|input| matches!(input, ValueRef::Source(id) if *id == source_id))
        })
}

fn live_source_event_from_generic(event: &GenericSourceEvent<'_>) -> LiveSourceEvent {
    LiveSourceEvent {
        source: event.source.to_owned(),
        text: event.text.map(str::to_owned),
        key: event.key.map(str::to_owned),
        list_id: event.list_id.map(str::to_owned),
        address: event.address.map(str::to_owned),
        payload: event
            .payload
            .iter()
            .map(|(key, value)| (key.clone(), (*value).to_owned()))
            .collect(),
        payload_bytes: event.payload_bytes.clone(),
        pointer_x: event.pointer_x.map(str::to_owned),
        pointer_y: event.pointer_y.map(str::to_owned),
        pointer_width: event.pointer_width.map(str::to_owned),
        pointer_height: event.pointer_height.map(str::to_owned),
        target_text: event.target_text.map(str::to_owned),
        target_occurrence: event.target_occurrence,
        target_key: event.target_key,
        target_generation: event.target_generation,
        bind_epoch: event.bind_epoch,
        source_epoch: event.source_epoch,
        ..Default::default()
    }
}

fn root_json_source_event_from_generic(event: &GenericSourceEvent<'_>) -> RootJsonSourceEvent {
    RootJsonSourceEvent {
        text: event.text.map(str::to_owned),
        key: event.key.map(str::to_owned),
        address: event.address.map(str::to_owned),
        payload: event
            .payload
            .iter()
            .map(|(key, value)| (key.clone(), (*value).to_owned()))
            .collect(),
        payload_bytes: event.payload_bytes.clone(),
    }
}

fn root_json_source_event_from_live(event: &LiveSourceEvent) -> RootJsonSourceEvent {
    RootJsonSourceEvent {
        text: event.text.clone(),
        key: event.key.clone(),
        address: event.address.clone(),
        payload: event.payload.clone(),
        payload_bytes: event.payload_bytes.clone(),
    }
}

fn row_scoped_source_routes<'a>(
    plan: &'a MachinePlan,
    list_slot: &boon_plan::ListStorageSlot,
) -> Vec<&'a boon_plan::SourceRoute> {
    let mut routes = plan
        .source_routes
        .iter()
        .filter(|route| route.scoped && route.scope_id == list_slot.scope_id)
        .collect::<Vec<_>>();
    routes.sort_by_key(|route| route.source_id.0);
    routes
}

fn source_payload_json_value(
    event: &LiveSourceEvent,
    field: &SourcePayloadField,
) -> RuntimeResult<JsonValue> {
    match field {
        SourcePayloadField::Text => event
            .text
            .clone()
            .map(JsonValue::String)
            .ok_or_else(|| "source event is missing text payload".into()),
        SourcePayloadField::Key => event
            .key
            .clone()
            .map(JsonValue::String)
            .ok_or_else(|| "source event is missing key payload".into()),
        SourcePayloadField::Address => event
            .address
            .clone()
            .map(JsonValue::String)
            .ok_or_else(|| "source event is missing address payload".into()),
        SourcePayloadField::Bytes => {
            source_payload_runtime_bytes(event, field).map(|bytes| bytes.report_json())
        }
        SourcePayloadField::Named(name) => event
            .payload
            .get(name)
            .cloned()
            .map(JsonValue::String)
            .ok_or_else(|| format!("source event is missing `{name}` payload").into()),
    }
}

fn generic_source_payload_runtime_bytes(
    event: &GenericSourceEvent<'_>,
    field: &SourcePayloadField,
) -> RuntimeResult<RuntimeBytes> {
    let field_name = source_payload_bytes_field_name(field)?;
    event
        .payload_bytes
        .get(field_name)
        .map(|bytes| RuntimeBytes::dynamic(Bytes::from(bytes.clone())))
        .ok_or_else(|| format!("source event is missing `{field_name}` BYTES payload").into())
}

fn source_payload_runtime_bytes(
    event: &LiveSourceEvent,
    field: &SourcePayloadField,
) -> RuntimeResult<RuntimeBytes> {
    let field_name = source_payload_bytes_field_name(field)?;
    event
        .payload_bytes
        .get(field_name)
        .map(|bytes| RuntimeBytes::dynamic(Bytes::from(bytes.clone())))
        .ok_or_else(|| format!("source event is missing `{field_name}` BYTES payload").into())
}

fn source_payload_executor_bytes(
    event: &LiveSourceEvent,
    field: &SourcePayloadField,
) -> RuntimeResult<PlanExecutorBytes> {
    let field_name = source_payload_bytes_field_name(field)?;
    let bytes = event
        .payload_bytes
        .get(field_name)
        .ok_or_else(|| format!("source event is missing `{field_name}` BYTES payload"))?;
    PlanExecutorBytes::from_inline(
        sha256_bytes(bytes),
        bytes.len() as u64,
        bytes.clone(),
        "root source-payload BYTES",
    )
}

fn source_payload_bytes_field_name(field: &SourcePayloadField) -> RuntimeResult<&str> {
    match field {
        SourcePayloadField::Bytes => Ok("bytes"),
        other => Err(format!("source payload field {other:?} is not BYTES").into()),
    }
}

fn source_payload_value_for_output(
    plan: &MachinePlan,
    output_state_id: StateId,
    event: &LiveSourceEvent,
    field: &SourcePayloadField,
    op_id: usize,
) -> RuntimeResult<(JsonValue, Option<PlanExecutorBytes>)> {
    let slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == output_state_id)
        .ok_or_else(|| {
            format!(
                "root source-payload update branch {op_id} targets missing state {}",
                output_state_id.0
            )
        })?;
    match field {
        SourcePayloadField::Bytes => {
            let bytes = source_payload_executor_bytes(event, field)?;
            let boon_plan::PlanValueType::Bytes { fixed_len } = &slot.value_type else {
                return Err(format!(
                    "root source-payload update branch {op_id} reads BYTES payload but output state `{}` is not BYTES",
                    plan_state_label(plan, output_state_id.0)
                )
                .into());
            };
            if let Some(expected_len) = *fixed_len
                && expected_len != bytes.byte_len()
            {
                return Err(format!(
                    "root source-payload update branch {op_id} BYTES payload has byte_len {} but output fixed_len {expected_len}",
                    bytes.byte_len()
                )
                .into());
            }
            Ok((bytes.report_json(), Some(bytes)))
        }
        SourcePayloadField::Address
        | SourcePayloadField::Key
        | SourcePayloadField::Named(_)
        | SourcePayloadField::Text => {
            if slot.value_type != boon_plan::PlanValueType::Text {
                return Err(format!(
                    "root source-payload update branch {op_id} reads text payload but output state `{}` is not TEXT",
                    plan_state_label(plan, output_state_id.0)
                )
                .into());
            }
            Ok((source_payload_json_value(event, field)?, None))
        }
    }
}

fn plan_constant_runtime_bytes_for_output(
    plan: &MachinePlan,
    output_state_id: StateId,
    constant: &boon_plan::PlanConstant,
    op_id: usize,
) -> RuntimeResult<Option<RuntimeBytes>> {
    let slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == output_state_id)
        .ok_or_else(|| {
            format!(
                "root const update branch {op_id} targets missing state {}",
                output_state_id.0
            )
        })?;
    plan_executor_constant_bytes_for_storage_slot(
        constant,
        slot,
        &format!("root const update branch {op_id}"),
    )
    .and_then(|bytes| bytes.map(plan_executor_bytes_to_runtime_bytes).transpose())
}

fn plan_constant_executor_bytes_for_output(
    plan: &MachinePlan,
    output_state_id: StateId,
    constant: &boon_plan::PlanConstant,
    op_id: usize,
) -> RuntimeResult<Option<PlanExecutorBytes>> {
    let slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == output_state_id)
        .ok_or_else(|| {
            format!(
                "root const update branch {op_id} targets missing state {}",
                output_state_id.0
            )
        })?;
    plan_executor_constant_bytes_for_storage_slot(
        constant,
        slot,
        &format!("root const update branch {op_id}"),
    )
}

fn plan_executor_bytes_to_runtime_bytes(bytes: PlanExecutorBytes) -> RuntimeResult<RuntimeBytes> {
    RuntimeBytes::inline_with_digest(
        bytes.digest().to_owned(),
        bytes.byte_len(),
        Bytes::copy_from_slice(bytes.inline_bytes()),
    )
}

fn runtime_source_payload_bytes_to_plan_executor_bytes(
    bytes: RuntimeBytes,
) -> RuntimeResult<PlanExecutorBytes> {
    let inline = bytes.inline_bytes()?.as_ref().to_vec();
    PlanExecutorBytes::from_inline(
        bytes.digest,
        bytes.byte_len,
        inline,
        "indexed source-payload BYTES state",
    )
}

fn indexed_row_view_for_plan_executor(row: &PlanListRowState) -> RuntimeResult<IndexedRowView> {
    Ok(IndexedRowView {
        fields: row.fields.clone(),
        private_bytes: row.private_bytes.clone(),
        fixed_byte_banks: row.fixed_bytes_banks.clone(),
    })
}

fn evaluate_indexed_bytes_read_update_for_runtime(
    plan: &MachinePlan,
    op: &boon_plan::PlanOp,
    row: &PlanListRowState,
    host_file_root: Option<&Path>,
) -> RuntimeResult<IndexedBytesReadEvaluation> {
    let row_view = indexed_row_view_for_plan_executor(row)?;
    let evaluation = evaluate_indexed_bytes_read_update(plan, op, &row_view, host_file_root)?;
    if !evaluation.supported {
        return Err(evaluation
            .unsupported_reason
            .unwrap_or_else(|| "indexed BYTES read evaluator did not support branch".to_owned())
            .into());
    }
    Ok(evaluation)
}

fn evaluate_indexed_bytes_write_update_for_runtime(
    plan: &MachinePlan,
    op: &boon_plan::PlanOp,
    row: &PlanListRowState,
    host_file_root: Option<&Path>,
) -> RuntimeResult<IndexedBytesWriteEvaluation> {
    let row_view = indexed_row_view_for_plan_executor(row)?;
    let evaluation = evaluate_indexed_bytes_write_update(plan, op, &row_view, host_file_root)?;
    if !evaluation.supported {
        return Err(evaluation
            .unsupported_reason
            .unwrap_or_else(|| "indexed BYTES write evaluator did not support branch".to_owned())
            .into());
    }
    Ok(evaluation)
}

fn json_value_at_dotted_path<'a>(root: &'a JsonValue, path: &str) -> Option<&'a JsonValue> {
    if let Some(value) = root.get(path) {
        return Some(value);
    }
    let mut value = root;
    for segment in path.split('.') {
        value = value.get(segment)?;
    }
    Some(value)
}

fn runtime_delta_signature(delta: &SemanticDelta<'_>) -> String {
    match &delta.field_path {
        Some(field) => format!("{}:{field}", delta.kind),
        None => delta.kind.to_owned(),
    }
}

fn semantic_delta_is_row_field(
    delta: &SemanticDelta<'_>,
    list: &str,
    key: u64,
    generation: u64,
    field: &str,
) -> bool {
    delta.kind == "FieldSet"
        && delta.list_id.as_deref() == Some(list)
        && delta.key == Some(key)
        && delta.generation == Some(generation)
        && delta.field_path.as_deref() == Some(field)
}

fn plan_executor_initial_value(
    plan: &MachinePlan,
    constant_id: Option<PlanConstantId>,
    value_type: &PlanValueType,
    initial_value_kind: PlanInitialValueKind,
) -> RuntimeResult<JsonValue> {
    let constant_id = constant_id.ok_or("state initializer is missing a typed constant id")?;
    let constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == constant_id)
        .ok_or_else(|| format!("missing plan constant {}", constant_id.0))?;
    match (&constant.value, value_type, initial_value_kind) {
        (PlanConstantValue::Text { value }, PlanValueType::Text, PlanInitialValueKind::Text) => {
            Ok(json!(value))
        }
        (
            PlanConstantValue::Number { value },
            PlanValueType::Number,
            PlanInitialValueKind::Number,
        ) => Ok(json!(value)),
        (PlanConstantValue::Byte { value }, PlanValueType::Byte, PlanInitialValueKind::Byte) => {
            Ok(json!(value))
        }
        (PlanConstantValue::Bool { value }, PlanValueType::Bool, PlanInitialValueKind::Bool) => {
            Ok(json!(value))
        }
        (PlanConstantValue::Enum { value }, PlanValueType::Enum, PlanInitialValueKind::Enum) => {
            Ok(json!(value))
        }
        (
            PlanConstantValue::Bytes {
                byte_len,
                sha256,
                inline_bytes: Some(bytes),
            },
            PlanValueType::Bytes { fixed_len },
            PlanInitialValueKind::Bytes,
        ) => {
            if let Some(expected_len) = *fixed_len {
                if expected_len != *byte_len {
                    return Err(format!(
                        "plan bytes constant {} has byte_len {byte_len} but storage fixed_len {expected_len}",
                        constant_id.0
                    )
                    .into());
                }
            }
            let runtime_bytes = RuntimeBytes::inline_with_digest(
                sha256.clone(),
                *byte_len,
                Bytes::copy_from_slice(bytes),
            )?;
            Ok(runtime_bytes.report_json())
        }
        (
            PlanConstantValue::Bytes {
                inline_bytes: None, ..
            },
            PlanValueType::Bytes { .. },
            PlanInitialValueKind::Bytes,
        ) => Err(format!(
            "plan bytes constant {} has no executable payload",
            constant_id.0
        )
        .into()),
        _ => Err(format!(
            "plan constant {} does not match scalar storage type {:?}/{:?}",
            constant_id.0, value_type, initial_value_kind
        )
        .into()),
    }
}

pub fn run_compiled_artifact_scenario(
    artifact_path: &Path,
    scenario_path: &Path,
) -> RuntimeResult<ArtifactScenarioRunOutput> {
    let artifact = CompiledArtifact::load_from_path(artifact_path)?;
    let plan = artifact.machine_plan()?;
    let scenario = parse_scenario(scenario_path)?;
    run_artifact_plan_scenario(&plan, &scenario)
}

