fn optional_runtime_generic_statement(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<Option<RuntimeGenericStatement>> {
    let Some(value) = object.get(key) else {
        return Ok(None);
    };
    if value.is_null() {
        return Ok(None);
    }
    Ok(Some(RuntimeGenericStatement::from_artifact(
        value,
        &format!("{context}.{key}"),
    )?))
}

