struct SourceRouteRowBindingStats {
    list: String,
    index: usize,
    key: u64,
    generation: u64,
}

impl SourceRouteExecutionStats {
    fn push_scan_sample(
        &mut self,
        source: &str,
        action: &SourceAction,
        list: &str,
        target: Option<&str>,
        rows_scanned: usize,
        rows_touched: usize,
        row_context: &'static str,
    ) {
        if rows_scanned == 0 {
            return;
        }
        self.rows_touched = self.rows_touched.saturating_add(rows_touched);
        let sample = LiveRuntimeSourceRouteScanSample {
            route_id: self.route_id,
            source: source.to_owned(),
            action: action.kind_label().to_owned(),
            list: list.to_owned(),
            target: target.map(str::to_owned),
            field: target.map(row_field_name).map(str::to_owned),
            rows_scanned,
            rows_touched,
            row_context: row_context.to_owned(),
        };
        if self.scan_samples.len() < LiveRuntimeSourceRouteScanSummary::SAMPLE_LIMIT {
            self.scan_samples.push(sample);
        }
    }

    fn scan_summary(&self) -> LiveRuntimeSourceRouteScanSummary {
        LiveRuntimeSourceRouteScanSummary {
            total_rows_scanned: self.rows_scanned,
            total_rows_touched: self.rows_touched,
            sample_count: self.scan_samples.len(),
            samples: self.scan_samples.clone(),
        }
    }

    fn to_report(
        &self,
        dirty_key_count: usize,
        recompute_candidate_count: usize,
        allocation_count: u64,
        allocation_bytes: u64,
    ) -> JsonValue {
        json!({
            "route_id": self.route_id,
            "source_id": self.source_id,
            "source": self.source,
            "payload_schema_field_count": self.payload_schema_field_count,
            "row_binding_identity": self.row_binding.as_ref().map(|row| {
                json!({
                    "list": row.list,
                    "index": row.index,
                    "key": row.key,
                    "generation": row.generation
                })
            }),
            "action_op_count": self.action_op_count,
            "rows_scanned": self.rows_scanned,
            "rows_touched": self.rows_touched,
            "scan_samples": self.scan_samples,
            "dirty_key_count": dirty_key_count,
            "recompute_candidate_count": recompute_candidate_count,
            "allocation_count": allocation_count,
            "allocation_bytes": allocation_bytes,
            "fallback_reasons": self.fallback_reasons,
            "deopt_reasons": self.deopt_reasons,
            "hot_path_vector_clone_count": 0
        })
    }
}

