    fn record_root_materialization_sample(
        &mut self,
        path: String,
        kind: &DerivedValueKind,
        elapsed_ms: f64,
        changed: bool,
        emitted_mutation: bool,
        changed_read_count: usize,
        list_view_profile: Option<LiveRuntimeRootListViewProfile>,
    ) {
        let stats = &mut self.root_materialization_stats;
        stats.candidate_count = stats.candidate_count.saturating_add(1);
        stats.total_ms += elapsed_ms;
        stats.sample_count = stats.sample_count.saturating_add(1);
        if changed {
            stats.changed_count = stats.changed_count.saturating_add(1);
        }
        if emitted_mutation {
            stats.emitted_mutation_count = stats.emitted_mutation_count.saturating_add(1);
        }
        stats.by_path.entry(path.clone()).or_default().record(
            elapsed_ms,
            changed,
            emitted_mutation,
            changed_read_count,
            list_view_profile.as_ref(),
        );
        if !runtime_profile_root_materialization_samples_enabled() {
            return;
        }
        let sample = LiveRuntimeRootMaterializationSample {
            path,
            kind: derived_value_kind_label(kind).to_owned(),
            elapsed_ms,
            changed,
            emitted_mutation,
            changed_read_count,
            list_view_profile,
        };
        if stats.samples.len() < LiveRuntimeRootMaterializationStats::SAMPLE_LIMIT {
            stats.samples.push(sample);
            return;
        }
        let Some((min_index, min_sample)) =
            stats
                .samples
                .iter()
                .enumerate()
                .min_by(|(_, left), (_, right)| {
                    left.elapsed_ms
                        .partial_cmp(&right.elapsed_ms)
                        .unwrap_or(std::cmp::Ordering::Equal)
                })
        else {
            return;
        };
        if sample.elapsed_ms > min_sample.elapsed_ms {
            stats.samples[min_index] = sample;
        }
    }

