fn static_bytes_scalar_arg(arg: &BytesScalarArg) -> Option<u64> {
    match arg {
        BytesScalarArg::Static(value) => Some(*value),
        BytesScalarArg::Path(_) => None,
    }
}

fn runtime_bytes_scalar_arg_usize(
    arg: &BytesScalarArg,
    read_textlike: impl Fn(&str) -> Option<String> + Copy,
    operation: &str,
    label: &str,
) -> RuntimeResult<usize> {
    let value = match arg {
        BytesScalarArg::Static(value) => i64::try_from(*value).map_err(|_| {
            format!("{operation} {label} static value {value} exceeds supported integer range")
        })?,
        BytesScalarArg::Path(path) => read_textlike(path)
            .ok_or_else(|| format!("{operation} {label} path `{path}` is missing"))?
            .parse::<i64>()
            .map_err(|_| format!("{operation} {label} path `{path}` is not NUMBER"))?,
    };
    usize::try_from(value)
        .map_err(|_| format!("{operation} {label} value {value} is negative or too large").into())
}

impl ScalarUpdateExpression {
    fn from_compiler(expression: CompilerScalarUpdateExpression) -> Self {
        match expression {
            CompilerScalarUpdateExpression::SourceText => Self::SourceText,
            CompilerScalarUpdateExpression::SourceKey => Self::SourceKey,
            CompilerScalarUpdateExpression::SourceAddress => Self::SourceAddress,
            CompilerScalarUpdateExpression::SourcePayload(value) => Self::SourcePayload(value),
            CompilerScalarUpdateExpression::Const(value) => Self::Const(value),
            CompilerScalarUpdateExpression::NumberInfix { left, op, right } => {
                Self::NumberInfix { left, op, right }
            }
            CompilerScalarUpdateExpression::ProjectTime {
                pointer_x,
                pointer_width,
                viewport_start,
                viewport_end,
                fallback,
            } => Self::ProjectTime {
                pointer_x,
                pointer_width,
                viewport_start,
                viewport_end,
                fallback,
            },
            CompilerScalarUpdateExpression::MatchNumberInfixConst {
                left,
                op,
                right,
                arms,
            } => Self::MatchNumberInfixConst {
                left,
                op,
                right,
                arms,
            },
            CompilerScalarUpdateExpression::ListFindValue {
                list,
                field,
                expected,
                target,
                fallback,
            } => Self::ListFindValue {
                list,
                field,
                expected,
                target,
                fallback,
            },
            CompilerScalarUpdateExpression::PreviousValue(value) => Self::PreviousValue(value),
            CompilerScalarUpdateExpression::ReadPath(value) => Self::ReadPath(value),
            CompilerScalarUpdateExpression::TextTrimOrPrevious { path, previous } => {
                Self::TextTrimOrPrevious { path, previous }
            }
            CompilerScalarUpdateExpression::PrefixPayloadConcat {
                prefix,
                payload_path,
                separator,
            } => Self::PrefixPayloadConcat {
                prefix,
                payload_path,
                separator,
            },
            CompilerScalarUpdateExpression::PrefixRootConcat {
                prefix,
                path,
                separator,
            } => Self::PrefixRootConcat {
                prefix,
                path,
                separator,
            },
            CompilerScalarUpdateExpression::BoolNot(value) => Self::BoolNot(value),
            CompilerScalarUpdateExpression::BytesLength(value) => Self::BytesLength(value),
            CompilerScalarUpdateExpression::BytesIsEmpty(value) => Self::BytesIsEmpty(value),
            CompilerScalarUpdateExpression::BytesGet { path, index } => {
                Self::BytesGet { path, index }
            }
            CompilerScalarUpdateExpression::BytesSet { path, index, value } => {
                Self::BytesSet { path, index, value }
            }
            CompilerScalarUpdateExpression::BytesSlice {
                path,
                offset,
                byte_count,
            } => Self::BytesSlice {
                path,
                offset,
                byte_count,
            },
            CompilerScalarUpdateExpression::BytesTake { path, byte_count } => {
                Self::BytesTake { path, byte_count }
            }
            CompilerScalarUpdateExpression::BytesDrop { path, byte_count } => {
                Self::BytesDrop { path, byte_count }
            }
            CompilerScalarUpdateExpression::BytesZeros { byte_count } => {
                Self::BytesZeros { byte_count }
            }
            CompilerScalarUpdateExpression::BytesToHex { path } => Self::BytesToHex { path },
            CompilerScalarUpdateExpression::BytesFromHex { path } => Self::BytesFromHex { path },
            CompilerScalarUpdateExpression::BytesToBase64 { path } => Self::BytesToBase64 { path },
            CompilerScalarUpdateExpression::BytesFromBase64 { path } => {
                Self::BytesFromBase64 { path }
            }
            CompilerScalarUpdateExpression::BytesReadUnsigned {
                path,
                offset,
                byte_count,
                endian,
            } => Self::BytesReadUnsigned {
                path,
                offset,
                byte_count,
                endian,
            },
            CompilerScalarUpdateExpression::BytesReadSigned {
                path,
                offset,
                byte_count,
                endian,
            } => Self::BytesReadSigned {
                path,
                offset,
                byte_count,
                endian,
            },
            CompilerScalarUpdateExpression::BytesWriteUnsigned {
                path,
                offset,
                byte_count,
                endian,
                value,
            } => Self::BytesWriteUnsigned {
                path,
                offset,
                byte_count,
                endian,
                value,
            },
            CompilerScalarUpdateExpression::BytesWriteSigned {
                path,
                offset,
                byte_count,
                endian,
                value,
            } => Self::BytesWriteSigned {
                path,
                offset,
                byte_count,
                endian,
                value,
            },
            CompilerScalarUpdateExpression::FileReadBytes { path } => Self::FileReadBytes { path },
            CompilerScalarUpdateExpression::TextToBytes { path, encoding } => {
                Self::TextToBytes { path, encoding }
            }
            CompilerScalarUpdateExpression::BytesToText { path, encoding } => {
                Self::BytesToText { path, encoding }
            }
            CompilerScalarUpdateExpression::BytesConcat { left, right } => {
                Self::BytesConcat { left, right }
            }
            CompilerScalarUpdateExpression::BytesEqual { left, right } => {
                Self::BytesEqual { left, right }
            }
            CompilerScalarUpdateExpression::BytesFind { haystack, needle } => {
                Self::BytesFind { haystack, needle }
            }
            CompilerScalarUpdateExpression::BytesStartsWith { path, prefix } => {
                Self::BytesStartsWith { path, prefix }
            }
            CompilerScalarUpdateExpression::BytesEndsWith { path, suffix } => {
                Self::BytesEndsWith { path, suffix }
            }
            CompilerScalarUpdateExpression::MatchConst { input, arms } => {
                Self::MatchConst { input, arms }
            }
            CompilerScalarUpdateExpression::MatchValueConst { input, arms } => {
                Self::MatchValueConst { input, arms }
            }
            CompilerScalarUpdateExpression::MatchTextIsEmptyConst { input, arms } => {
                Self::MatchTextIsEmptyConst { input, arms }
            }
            CompilerScalarUpdateExpression::Unsupported => Self::Unsupported,
        }
    }

    fn is_root_text_expression(&self) -> bool {
        matches!(
            self,
            Self::SourceText
                | Self::SourceKey
                | Self::SourceAddress
                | Self::SourcePayload(_)
                | Self::Const(_)
                | Self::NumberInfix { .. }
                | Self::ProjectTime { .. }
                | Self::MatchNumberInfixConst { .. }
                | Self::ListFindValue { .. }
                | Self::PreviousValue(_)
                | Self::ReadPath(_)
                | Self::PrefixPayloadConcat { .. }
                | Self::PrefixRootConcat { .. }
                | Self::BytesToHex { .. }
                | Self::BytesToBase64 { .. }
                | Self::BytesToText { .. }
                | Self::MatchConst { .. }
                | Self::MatchValueConst { .. }
                | Self::MatchTextIsEmptyConst { .. }
        )
    }

    fn is_indexed_text_expression(&self) -> bool {
        matches!(
            self,
            Self::SourceText
                | Self::SourceKey
                | Self::SourcePayload(_)
                | Self::PreviousValue(_)
                | Self::ReadPath(_)
                | Self::TextTrimOrPrevious { .. }
                | Self::PrefixPayloadConcat { .. }
                | Self::PrefixRootConcat { .. }
                | Self::BytesToHex { .. }
                | Self::BytesToBase64 { .. }
                | Self::BytesToText { .. }
                | Self::MatchConst { .. }
                | Self::MatchValueConst { .. }
                | Self::MatchTextIsEmptyConst { .. }
                | Self::MatchNumberInfixConst { .. }
        ) || matches!(self, Self::Const(value) if value != "True" && value != "False")
    }

    fn is_indexed_bool_expression(&self) -> bool {
        matches!(self, Self::Const(value) if value == "True" || value == "False")
            || matches!(self, Self::BoolNot(_))
            || matches!(self, Self::BytesIsEmpty(_))
            || matches!(self, Self::BytesEqual { .. })
            || matches!(self, Self::BytesStartsWith { .. })
            || matches!(self, Self::BytesEndsWith { .. })
    }

    fn is_indexed_bool_match_expression(&self) -> bool {
        match self {
            Self::MatchConst { arms, .. } => arms.iter().all(|arm| {
                matches!(arm.output.as_str(), "True" | "False" | "SKIP")
                    || !arm.output.contains('.')
            }),
            Self::MatchValueConst { arms, .. }
            | Self::MatchTextIsEmptyConst { arms, .. }
            | Self::MatchNumberInfixConst { arms, .. } => arms
                .iter()
                .all(|arm| update_value_expression_is_bool_compatible(&arm.output)),
            _ => false,
        }
    }

    fn is_indexed_value_expression(&self) -> bool {
        matches!(
            self,
            Self::BytesLength(_)
                | Self::BytesGet { .. }
                | Self::BytesSet { .. }
                | Self::BytesSlice { .. }
                | Self::BytesTake { .. }
                | Self::BytesDrop { .. }
                | Self::BytesZeros { .. }
                | Self::BytesFromHex { .. }
                | Self::BytesFromBase64 { .. }
                | Self::BytesReadUnsigned { .. }
                | Self::BytesReadSigned { .. }
                | Self::BytesWriteUnsigned { .. }
                | Self::BytesWriteSigned { .. }
                | Self::FileReadBytes { .. }
                | Self::TextToBytes { .. }
                | Self::BytesConcat { .. }
                | Self::BytesFind { .. }
        )
    }

    fn prefers_settled_root_derived_reads(&self) -> bool {
        matches!(
            self,
            Self::ReadPath(_)
                | Self::ListFindValue { .. }
                | Self::ProjectTime { .. }
                | Self::PrefixRootConcat { .. }
                | Self::NumberInfix { .. }
                | Self::MatchNumberInfixConst { .. }
                | Self::PreviousValue(_)
                | Self::TextTrimOrPrevious { .. }
                | Self::BoolNot(_)
                | Self::BytesLength(_)
                | Self::BytesIsEmpty(_)
                | Self::BytesGet { .. }
                | Self::BytesSet { .. }
                | Self::BytesSlice { .. }
                | Self::BytesTake { .. }
                | Self::BytesDrop { .. }
                | Self::BytesZeros { .. }
                | Self::BytesToHex { .. }
                | Self::BytesFromHex { .. }
                | Self::BytesToBase64 { .. }
                | Self::BytesFromBase64 { .. }
                | Self::BytesReadUnsigned { .. }
                | Self::BytesReadSigned { .. }
                | Self::BytesWriteUnsigned { .. }
                | Self::BytesWriteSigned { .. }
                | Self::FileReadBytes { .. }
                | Self::TextToBytes { .. }
                | Self::BytesToText { .. }
                | Self::BytesConcat { .. }
                | Self::BytesEqual { .. }
                | Self::BytesFind { .. }
                | Self::BytesStartsWith { .. }
                | Self::BytesEndsWith { .. }
                | Self::MatchConst { .. }
                | Self::MatchValueConst { .. }
                | Self::MatchTextIsEmptyConst { .. }
        )
    }

    fn same_event_root_read_paths(&self) -> Vec<&str> {
        let mut reads = Vec::new();
        match self {
            Self::NumberInfix { left, right, .. } => {
                reads.push(left.as_str());
                reads.push(right.as_str());
            }
            Self::MatchNumberInfixConst {
                left, right, arms, ..
            } => {
                reads.push(left.as_str());
                reads.push(right.as_str());
                for arm in arms {
                    update_value_expression_root_read_paths(&arm.output, &mut reads);
                }
            }
            Self::ProjectTime {
                pointer_x,
                pointer_width,
                viewport_start,
                viewport_end,
                fallback,
            } => {
                reads.push(pointer_x.as_str());
                reads.push(pointer_width.as_str());
                reads.push(viewport_start.as_str());
                reads.push(viewport_end.as_str());
                reads.push(fallback.as_str());
            }
            Self::ListFindValue {
                expected, fallback, ..
            } => {
                update_value_expression_root_read_paths(expected, &mut reads);
                if let Some(fallback) = fallback.as_ref() {
                    update_value_expression_root_read_paths(fallback, &mut reads);
                }
            }
            Self::PreviousValue(path)
            | Self::ReadPath(path)
            | Self::BoolNot(path)
            | Self::BytesLength(path)
            | Self::BytesIsEmpty(path)
            | Self::BytesGet { path, .. }
            | Self::BytesSet { path, .. }
            | Self::BytesSlice { path, .. }
            | Self::BytesTake { path, .. }
            | Self::BytesDrop { path, .. }
            | Self::BytesToHex { path }
            | Self::BytesFromHex { path }
            | Self::BytesToBase64 { path }
            | Self::BytesFromBase64 { path }
            | Self::BytesReadUnsigned { path, .. }
            | Self::BytesReadSigned { path, .. }
            | Self::BytesWriteUnsigned { path, .. }
            | Self::BytesWriteSigned { path, .. }
            | Self::TextToBytes { path, .. }
            | Self::BytesToText { path, .. }
            | Self::MatchConst { input: path, .. } => reads.push(path.as_str()),
            Self::BytesConcat { left, right } | Self::BytesEqual { left, right } => {
                reads.push(left.as_str());
                reads.push(right.as_str());
            }
            Self::BytesFind { haystack, needle } => {
                reads.push(haystack.as_str());
                reads.push(needle.as_str());
            }
            Self::BytesStartsWith { path, prefix } => {
                reads.push(path.as_str());
                reads.push(prefix.as_str());
            }
            Self::BytesEndsWith { path, suffix } => {
                reads.push(path.as_str());
                reads.push(suffix.as_str());
            }
            Self::MatchValueConst { input, arms } | Self::MatchTextIsEmptyConst { input, arms } => {
                reads.push(input.as_str());
                for arm in arms {
                    update_value_expression_root_read_paths(&arm.output, &mut reads);
                }
            }
            Self::TextTrimOrPrevious { path, previous } => {
                reads.push(path.as_str());
                reads.push(previous.as_str());
            }
            Self::PrefixRootConcat { path, .. } => reads.push(path.as_str()),
            Self::SourceText
            | Self::SourceKey
            | Self::SourceAddress
            | Self::SourcePayload(_)
            | Self::Const(_)
            | Self::BytesZeros { .. }
            | Self::FileReadBytes { .. }
            | Self::PrefixPayloadConcat { .. }
            | Self::Unsupported => {}
        }
        reads
    }

    fn const_bool(&self) -> Option<bool> {
        match self {
            Self::Const(value) if value == "True" => Some(true),
            Self::Const(value) if value == "False" => Some(false),
            _ => None,
        }
    }
}

