impl GenericRenderLoweringPlan {
    fn generic() -> Self {
        Self
    }

    fn lower_mutation_patch<'a>(
        &self,
        mutation: &GenericSourceMutation<'a>,
        _context: GenericRenderContext<'a>,
    ) -> RuntimeResult<Option<RenderPatch<'a>>> {
        Ok(Some(match mutation {
            GenericSourceMutation::RootText(commit) => patch(
                "PatchRootField",
                RenderTarget::Static(Cow::Owned(commit.target.clone())),
                ProtocolValue::Text(commit.value.clone()),
            ),
            GenericSourceMutation::RootTextSemanticOnly(_) => return Ok(None),
            GenericSourceMutation::RootBool(commit) => patch(
                "PatchRootField",
                RenderTarget::Static(Cow::Owned(commit.target.clone())),
                ProtocolValue::Bool(commit.value),
            ),
            GenericSourceMutation::RootBoolSemanticOnly(_) => return Ok(None),
            GenericSourceMutation::RootNumber(commit) => patch(
                "PatchRootField",
                RenderTarget::Static(Cow::Owned(commit.target.clone())),
                match commit.value {
                    GenericRootNumberValue::Number(value) => ProtocolValue::NumberText(value),
                    GenericRootNumberValue::Null => ProtocolValue::Null,
                },
            ),
            GenericSourceMutation::RootNumberSemanticOnly(_) => return Ok(None),
            GenericSourceMutation::RootBytes(commit) => patch(
                "PatchRootField",
                RenderTarget::Static(Cow::Owned(commit.target.clone())),
                ProtocolValue::Bytes(commit.value.report_json()),
            ),
            GenericSourceMutation::RootBytesSemanticOnly(_) => return Ok(None),
            GenericSourceMutation::TextField(commit) => list_row_field_patch(
                "PatchListRowField",
                &commit.list,
                commit.key,
                commit.generation,
                &commit.field,
                ProtocolValue::Text(commit.value.clone()),
            ),
            GenericSourceMutation::TextFieldIdentity(commit) => list_row_field_patch(
                "PatchListRowField",
                &commit.list,
                commit.key,
                commit.generation,
                &commit.field,
                ProtocolValue::Text(Cow::Owned(commit.value.clone())),
            ),
            GenericSourceMutation::ValueField(commit) => list_row_field_patch(
                "PatchListRowField",
                &commit.list,
                commit.key,
                commit.generation,
                &commit.field,
                commit.value.clone(),
            ),
            GenericSourceMutation::BoolField(commit) => list_row_field_patch(
                "PatchListRowField",
                &commit.list,
                commit.key,
                commit.generation,
                &commit.field,
                ProtocolValue::Bool(commit.value),
            ),
            GenericSourceMutation::ListAppend(_)
            | GenericSourceMutation::ListRemove { .. }
            | GenericSourceMutation::SourceBind(_)
            | GenericSourceMutation::SourceUnbind(_) => {
                generic_document_invalidation_patch(mutation)
            }
        }))
    }

    fn lower_row_affordance_patch<'a>(
        &self,
        list: &'a str,
        _key: u64,
        _generation: u64,
        affordance: &'static str,
        _visible: bool,
    ) -> RuntimeResult<RenderPatch<'a>> {
        Ok(invalidated_patch(
            "InvalidateDocument",
            RenderInvalidation::DocumentStructure,
            RenderTarget::Static(Cow::Borrowed("document")),
            ProtocolValue::Text(Cow::Owned(format!("{list}.{affordance}"))),
        ))
    }

    fn lower_list_move_patch<'a>(
        &self,
        commit: &GenericListRowCommit,
        to: usize,
    ) -> RuntimeResult<RenderPatch<'a>> {
        Ok(invalidated_patch(
            "InvalidateDocument",
            RenderInvalidation::ListStructure,
            RenderTarget::Static(Cow::Borrowed("document")),
            ProtocolValue::Text(Cow::Owned(format!("{}.position:{to}", commit.list))),
        ))
    }
}

impl<'a> GenericSourceMutation<'a> {
    fn semantic_delta(&self) -> Option<SemanticDelta<'a>> {
        match self {
            Self::RootText(commit) => Some(commit.semantic_delta()),
            Self::RootTextSemanticOnly(commit) => Some(commit.semantic_delta()),
            Self::RootBool(commit) => Some(commit.semantic_delta()),
            Self::RootBoolSemanticOnly(commit) => Some(commit.semantic_delta()),
            Self::RootNumber(commit) => Some(commit.semantic_delta()),
            Self::RootNumberSemanticOnly(commit) => Some(commit.semantic_delta()),
            Self::RootBytes(commit) => Some(commit.semantic_delta()),
            Self::RootBytesSemanticOnly(commit) => Some(commit.semantic_delta()),
            Self::TextField(commit) => Some(commit.semantic_delta()),
            Self::TextFieldIdentity(commit) => Some(
                commit.semantic_delta_with_value(ProtocolValue::Text(Cow::Owned(
                    commit.value.clone(),
                ))),
            ),
            Self::ValueField(commit) => Some(commit.semantic_delta()),
            Self::BoolField(commit) => Some(commit.semantic_delta()),
            Self::ListAppend(commit) => Some(commit.semantic_delta()),
            Self::ListRemove {
                list,
                key,
                generation,
            } => Some(SemanticDelta {
                kind: "ListRemove",
                list_id: Some(Cow::Owned(list.clone())),
                key: Some(*key),
                generation: Some(*generation),
                source_id: None,
                bind_epoch: None,
                field_path: None,
                value: ProtocolValue::Null,
            }),
            Self::SourceBind(binding) => Some(GenericCircuitRuntime::semantic_source_delta(
                "SourceBind",
                binding,
                ProtocolValue::Text(Cow::Owned(binding.source_path.clone())),
            )),
            Self::SourceUnbind(binding) => Some(GenericCircuitRuntime::semantic_source_delta(
                "SourceUnbind",
                binding,
                ProtocolValue::Null,
            )),
        }
    }
}

fn root_mutation_target<'a>(mutation: &'a GenericSourceMutation<'_>) -> &'a str {
    match mutation {
        GenericSourceMutation::RootText(commit)
        | GenericSourceMutation::RootTextSemanticOnly(commit) => &commit.target,
        GenericSourceMutation::RootBool(commit)
        | GenericSourceMutation::RootBoolSemanticOnly(commit) => &commit.target,
        GenericSourceMutation::RootNumber(commit)
        | GenericSourceMutation::RootNumberSemanticOnly(commit) => &commit.target,
        GenericSourceMutation::RootBytes(commit)
        | GenericSourceMutation::RootBytesSemanticOnly(commit) => &commit.target,
        GenericSourceMutation::TextField(_)
        | GenericSourceMutation::TextFieldIdentity(_)
        | GenericSourceMutation::ValueField(_)
        | GenericSourceMutation::BoolField(_)
        | GenericSourceMutation::ListAppend(_)
        | GenericSourceMutation::ListRemove { .. }
        | GenericSourceMutation::SourceBind(_)
        | GenericSourceMutation::SourceUnbind(_) => "",
    }
}

fn generic_document_invalidation_patch<'a>(
    mutation: &GenericSourceMutation<'a>,
) -> RenderPatch<'a> {
    let value = match mutation {
        GenericSourceMutation::RootText(commit)
        | GenericSourceMutation::RootTextSemanticOnly(commit) => {
            ProtocolValue::Text(Cow::Owned(commit.target.clone()))
        }
        GenericSourceMutation::RootBool(commit)
        | GenericSourceMutation::RootBoolSemanticOnly(commit) => {
            ProtocolValue::Text(Cow::Owned(commit.target.clone()))
        }
        GenericSourceMutation::RootNumber(commit)
        | GenericSourceMutation::RootNumberSemanticOnly(commit) => {
            ProtocolValue::Text(Cow::Owned(commit.target.clone()))
        }
        GenericSourceMutation::RootBytes(commit)
        | GenericSourceMutation::RootBytesSemanticOnly(commit) => {
            ProtocolValue::Text(Cow::Owned(commit.target.clone()))
        }
        GenericSourceMutation::TextField(commit) => {
            ProtocolValue::Text(Cow::Owned(format!("{}.{}", commit.list, commit.field)))
        }
        GenericSourceMutation::TextFieldIdentity(commit) => {
            ProtocolValue::Text(Cow::Owned(format!("{}.{}", commit.list, commit.field)))
        }
        GenericSourceMutation::ValueField(commit) => {
            ProtocolValue::Text(Cow::Owned(format!("{}.{}", commit.list, commit.field)))
        }
        GenericSourceMutation::BoolField(commit) => {
            ProtocolValue::Text(Cow::Owned(format!("{}.{}", commit.list, commit.field)))
        }
        GenericSourceMutation::ListAppend(commit) => {
            ProtocolValue::Text(Cow::Owned(commit.list.clone()))
        }
        GenericSourceMutation::ListRemove { list, .. } => {
            ProtocolValue::Text(Cow::Owned(list.clone()))
        }
        GenericSourceMutation::SourceBind(binding)
        | GenericSourceMutation::SourceUnbind(binding) => {
            ProtocolValue::Text(Cow::Owned(binding.source_path.clone()))
        }
    };
    let invalidation = match mutation {
        GenericSourceMutation::ListAppend(_) | GenericSourceMutation::ListRemove { .. } => {
            RenderInvalidation::ListStructure
        }
        GenericSourceMutation::SourceBind(_) | GenericSourceMutation::SourceUnbind(_) => {
            RenderInvalidation::SourceBinding
        }
        GenericSourceMutation::RootText(_)
        | GenericSourceMutation::RootTextSemanticOnly(_)
        | GenericSourceMutation::RootBool(_)
        | GenericSourceMutation::RootBoolSemanticOnly(_)
        | GenericSourceMutation::RootNumber(_)
        | GenericSourceMutation::RootNumberSemanticOnly(_)
        | GenericSourceMutation::RootBytes(_)
        | GenericSourceMutation::RootBytesSemanticOnly(_)
        | GenericSourceMutation::TextField(_)
        | GenericSourceMutation::TextFieldIdentity(_)
        | GenericSourceMutation::ValueField(_)
        | GenericSourceMutation::BoolField(_) => RenderInvalidation::DocumentStructure,
    };
    invalidated_patch(
        "InvalidateDocument",
        invalidation,
        RenderTarget::Static(Cow::Borrowed("document")),
        value,
    )
}

fn list_row_field_patch<'a>(
    kind: &'static str,
    list: &str,
    key: u64,
    generation: u64,
    field: &str,
    value: ProtocolValue<'a>,
) -> RenderPatch<'a> {
    let mut patch = patch(
        kind,
        RenderTarget::Static(Cow::Owned(field.to_owned())),
        value,
    );
    patch.list_id = Some(Cow::Owned(list.to_owned()));
    patch.key = Some(key);
    patch.generation = Some(generation);
    patch
}

