struct RootListViewFieldCacheContext {
    root_path: String,
    source_identity: Option<RootListViewFieldSourceIdentity>,
    source_binding: Option<String>,
    record_scope: Option<String>,
    active_field: Option<String>,
    materialization_pass: u64,
    field_profiles: Rc<RefCell<BTreeMap<(String, String), RootListViewFieldProfileAccumulator>>>,
    attribution: Rc<RefCell<RootListViewEvalAttribution>>,
    current_dirty_reads: Rc<BTreeSet<GenericReadKey>>,
    mapped_source_identities: Rc<RefCell<Vec<Option<RootListViewFieldSourceIdentity>>>>,
    field_cache_entries_prevalidated: bool,
}

#[derive(Clone, Debug, Default)]
struct RootListViewFieldProfileAccumulator {
    sample_count: usize,
    cache_hit_count: usize,
    cache_miss_count: usize,
    cache_store_count: usize,
    total_ms: f64,
    max_ms: f64,
}

fn record_root_list_view_field_profile(
    frame: &GenericEvalFrame,
    cache_key: &RootListViewFieldCacheKey,
    elapsed_ms: f64,
    cache_hit: bool,
    cache_store: bool,
) {
    let Some(context) = frame.root_list_view_field_cache_context.as_ref() else {
        return;
    };
    let mut profiles = context.field_profiles.borrow_mut();
    let profile = profiles
        .entry((cache_key.record_scope.clone(), cache_key.field.clone()))
        .or_default();
    profile.sample_count = profile.sample_count.saturating_add(1);
    profile.total_ms += elapsed_ms;
    profile.max_ms = profile.max_ms.max(elapsed_ms);
    if cache_hit {
        profile.cache_hit_count = profile.cache_hit_count.saturating_add(1);
    } else {
        profile.cache_miss_count = profile.cache_miss_count.saturating_add(1);
    }
    if cache_store {
        profile.cache_store_count = profile.cache_store_count.saturating_add(1);
    }
}

fn replace_root_list_view_active_field(
    frame: &mut GenericEvalFrame,
    field: Option<String>,
) -> Option<String> {
    frame
        .root_list_view_field_cache_context
        .as_mut()
        .and_then(|context| std::mem::replace(&mut context.active_field, field))
}

