fn root_path_observation_variants(path: &str) -> Vec<String> {
    let mut variants = BTreeSet::from([path.to_owned()]);
    if let Some(passed) = path.strip_prefix("PASSED.") {
        variants.extend(root_path_observation_variants(passed));
    }
    if let Some(local) = path.strip_prefix("store.") {
        variants.insert(local.to_owned());
    } else if !path.starts_with('@') && !path.contains(':') {
        variants.insert(format!("store.{path}"));
    }
    variants.into_iter().collect()
}

fn observed_path_is_descendant_of_root(observed: &str, root: &str) -> bool {
    observed
        .strip_prefix(root)
        .is_some_and(|tail| tail.starts_with('.'))
}

fn root_paths_observation_overlap(left: &str, right: &str) -> bool {
    let right = root_path_observation_variants(right)
        .into_iter()
        .collect::<BTreeSet<_>>();
    root_path_observation_variants(left)
        .into_iter()
        .any(|candidate| right.contains(&candidate))
}

