fn source_payload_path_in_expr_subtree(
    exprs: &[AstExpr],
    expr_id: usize,
    source: &str,
) -> Option<String> {
    let mut ids = Vec::new();
    let mut seen = BTreeSet::new();
    collect_expr_tree(expr_id, exprs, &mut seen, &mut ids);
    ids.into_iter().find_map(|id| {
        let path = ast_argument_value_in_exprs(exprs, id)?;
        source_payload_field_from_input(&path, source)?;
        Some(path)
    })
}

fn source_payload_path_before_line(exprs: &[AstExpr], line: usize, source: &str) -> Option<String> {
    exprs
        .iter()
        .filter(|expr| expr.line < line)
        .rev()
        .find_map(|expr| {
            let path = ast_argument_value_in_exprs(exprs, expr.id)?;
            source_payload_field_from_input(&path, source)?;
            Some(path)
        })
}

fn runtime_match_const_pattern_label(pattern: &[String]) -> Option<String> {
    if pattern == ["__"] {
        Some("__".to_owned())
    } else if pattern.first().map(String::as_str) == Some("TEXT")
        && pattern.get(1).map(String::as_str) == Some("{")
        && pattern.last().map(String::as_str) == Some("}")
    {
        Some(text_match_pattern_value(&pattern[2..pattern.len() - 1]))
    } else if pattern.len() == 1 {
        Some(pattern[0].clone())
    } else {
        Some(pattern.join("."))
    }
}

fn canonical_transform_text_path(owner_path: &str, path: &str) -> String {
    if path.contains('.') {
        return path.to_owned();
    }
    owner_path
        .rsplit_once('.')
        .map(|(parent, _)| format!("{parent}.{path}"))
        .unwrap_or_else(|| path.to_owned())
}

fn statement_ast_exprs(statement: &AstStatement, expressions: &[AstExpr]) -> Vec<AstExpr> {
    let mut ids = Vec::new();
    let mut seen = BTreeSet::new();
    collect_statement_expr_ids(statement, expressions, &mut seen, &mut ids);
    for expr in expressions {
        if statement_tree_contains_expr(statement, expr) {
            seen.insert(expr.id);
        }
    }
    expressions
        .iter()
        .filter(|expr| seen.contains(&expr.id))
        .cloned()
        .collect()
}

fn statement_tree_contains_expr(statement: &AstStatement, expr: &AstExpr) -> bool {
    (expr.start >= statement.start && expr.end <= statement.end)
        || statement
            .children
            .iter()
            .any(|child| statement_tree_contains_expr(child, expr))
}

fn collect_statement_expr_ids(
    statement: &AstStatement,
    expressions: &[AstExpr],
    seen: &mut BTreeSet<usize>,
    ids: &mut Vec<usize>,
) {
    if let Some(expr) = statement.expr {
        collect_expr_tree(expr, expressions, seen, ids);
    }
    for child in &statement.children {
        collect_statement_expr_ids(child, expressions, seen, ids);
    }
}

fn collect_expr_tree(
    id: usize,
    expressions: &[AstExpr],
    seen: &mut BTreeSet<usize>,
    ids: &mut Vec<usize>,
) {
    if !seen.insert(id) {
        return;
    }
    ids.push(id);
    let Some(expr) = expressions.iter().find(|expr| expr.id == id) else {
        return;
    };
    match &expr.kind {
        AstExprKind::Call { args, .. } => {
            for arg in args {
                collect_expr_tree(arg.value, expressions, seen, ids);
            }
        }
        AstExprKind::Pipe { input, args, .. } => {
            collect_expr_tree(*input, expressions, seen, ids);
            for arg in args {
                collect_expr_tree(arg.value, expressions, seen, ids);
            }
        }
        AstExprKind::Hold { initial, .. } | AstExprKind::When { input: initial } => {
            collect_expr_tree(*initial, expressions, seen, ids);
        }
        AstExprKind::Then { input, output } => {
            collect_expr_tree(*input, expressions, seen, ids);
            if let Some(output) = output {
                collect_expr_tree(*output, expressions, seen, ids);
            }
        }
        AstExprKind::Infix { left, right, .. } => {
            collect_expr_tree(*left, expressions, seen, ids);
            collect_expr_tree(*right, expressions, seen, ids);
        }
        AstExprKind::MatchArm { output, .. } => {
            if let Some(output) = output {
                collect_expr_tree(*output, expressions, seen, ids);
            }
        }
        AstExprKind::Record(fields)
        | AstExprKind::Object(fields)
        | AstExprKind::TaggedObject { fields, .. } => {
            for field in fields {
                collect_expr_tree(field.value, expressions, seen, ids);
            }
        }
        AstExprKind::ListLiteral { items, .. } => {
            for item in items {
                collect_expr_tree(*item, expressions, seen, ids);
            }
        }
        AstExprKind::BytesLiteral { items, .. } => {
            for item in items {
                collect_expr_tree(*item, expressions, seen, ids);
            }
        }
        AstExprKind::Identifier(_)
        | AstExprKind::Path(_)
        | AstExprKind::StringLiteral(_)
        | AstExprKind::TextLiteral(_)
        | AstExprKind::ByteLiteral { .. }
        | AstExprKind::Number(_)
        | AstExprKind::Bool(_)
        | AstExprKind::Enum(_)
        | AstExprKind::Tag(_)
        | AstExprKind::Source
        | AstExprKind::Latest
        | AstExprKind::Delimiter
        | AstExprKind::Unknown(_) => {}
    }
}

fn ast_argument_value_in_exprs(exprs: &[AstExpr], expr_id: usize) -> Option<String> {
    let expr = exprs.iter().find(|expr| expr.id == expr_id)?;
    Some(match &expr.kind {
        AstExprKind::Identifier(value)
        | AstExprKind::Enum(value)
        | AstExprKind::Tag(value)
        | AstExprKind::Number(value) => value.clone(),
        AstExprKind::ByteLiteral { value, .. } => value.to_string(),
        AstExprKind::Path(parts) => parts.join("."),
        AstExprKind::Bool(true) => "True".to_owned(),
        AstExprKind::Bool(false) => "False".to_owned(),
        AstExprKind::StringLiteral(value) | AstExprKind::TextLiteral(value) => value.clone(),
        AstExprKind::Unknown(tokens) => tokens.join("."),
        AstExprKind::Delimiter => String::new(),
        AstExprKind::Source
        | AstExprKind::Call { .. }
        | AstExprKind::Pipe { .. }
        | AstExprKind::Hold { .. }
        | AstExprKind::Latest
        | AstExprKind::When { .. }
        | AstExprKind::Then { .. }
        | AstExprKind::Infix { .. }
        | AstExprKind::MatchArm { .. }
        | AstExprKind::Record(_)
        | AstExprKind::Object(_)
        | AstExprKind::TaggedObject { .. }
        | AstExprKind::BytesLiteral { .. }
        | AstExprKind::ListLiteral { .. } => return None,
    })
}

