#[derive(Clone, Debug, Default)]
struct SourceActionTable {
    by_source: Vec<Option<Arc<[SourceAction]>>>,
}

impl SourceActionTable {
    fn set(&mut self, source_id: SourceId, actions: Vec<SourceAction>) {
        let slot = source_id.as_usize();
        if self.by_source.len() <= slot {
            self.by_source.resize_with(slot + 1, || None);
        }
        self.by_source[slot] = Some(Arc::from(actions.into_boxed_slice()));
    }

    fn actions(&self, source_id: SourceId) -> Option<Arc<[SourceAction]>> {
        self.by_source
            .get(source_id.as_usize())
            .and_then(|actions| actions.clone())
            .filter(|actions| !actions.is_empty())
    }

    fn op_stream_count(&self) -> usize {
        self.by_source
            .iter()
            .filter(|actions| actions.as_ref().is_some_and(|actions| !actions.is_empty()))
            .count()
    }

    fn total_op_count(&self) -> usize {
        self.by_source
            .iter()
            .filter_map(|actions| actions.as_ref())
            .map(|actions| actions.len())
            .sum()
    }

    fn max_op_count(&self) -> usize {
        self.by_source
            .iter()
            .filter_map(|actions| actions.as_ref())
            .map(|actions| actions.len())
            .max()
            .unwrap_or_default()
    }
}

