    #[test]
    fn row_scoped_source_resolves_named_lookup_payload_without_address() {
        let source = r#"
store: [
    rows:
        LIST {
            [file: TEXT { wave_27.fst }, signal: TEXT { tx_data }, label: TEXT { - wave_27.fst }]
            [file: TEXT { simple.vcd }, signal: TEXT { clk }, label: TEXT { - simple.vcd }]
        }
        |> List/map(row, new: new_row(row: row))
]

FUNCTION new_row(row) {
    [
        file: row.file
        signal: row.signal
        label: row.label
        selected_file:
            TEXT { none } |> HOLD selected_file {
                LATEST {
                    elements.select.event.press |> THEN { row.file }
                }
            }
        elements: [
            select: SOURCE
        ]
    ]
}

document: Document/new(root: Element/label(element: [], label: TEXT { Rows }))
"#;
        let mut runtime =
            LoadedRuntimeHarness::from_source("row-lookup-payload-without-address", source)
                .unwrap();
        let route = runtime
            .loaded_runtime_for_test()
            .generic
            .as_ref()
            .and_then(|generic| {
                generic
                    .source_routes
                    .route_slots
                    .iter()
                    .find(|route| route.source.ends_with(".elements.select"))
            })
            .expect("row select route should be compiled");
        assert_eq!(route.row_lookup_field.as_deref(), Some("file"));
        let source_path = route.source.clone();

        let output = runtime
            .apply_source_event(LiveSourceEvent {
                source: source_path,
                payload: BTreeMap::from([("file".to_owned(), "simple.vcd".to_owned())]),
                target_text: Some("- simple.vcd".to_owned()),
                ..LiveSourceEvent::default()
            })
            .expect("row-scoped source should resolve by typed lookup payload without address");

        assert_eq!(
            output.state_summary["rows"][1]["selected_file"],
            "simple.vcd"
        );
        assert!(
            output.semantic_deltas.iter().any(|delta| {
                delta.kind == "FieldSet"
                    && delta.field_path.as_deref() == Some("selected_file")
                    && matches!(&delta.value, ProtocolValue::Text(value) if value == "simple.vcd")
            }),
            "selected_file should update through row-scoped source deltas: {:#?}",
            output.semantic_deltas
        );
    }

    #[test]
    fn root_scalar_same_event_flush_follows_qualified_derived_dependencies() {
        let source = r#"
store: [
    elements: [
        select: SOURCE
    ]
    active:
        TEXT { a } |> HOLD active {
            LATEST {
                elements.select.text
            }
        }
    selected:
        active |> WHEN {
            TEXT { b } => TEXT { B }
            __ => TEXT { A }
        }
    default_label:
        selected |> Text/concat(with: TEXT { ready }, separator: ":")
    cursor:
        default_label |> HOLD cursor {
            LATEST {
                elements.select.text |> THEN { default_label }
            }
        }
]

document: Document/new(root: Element/label(element: [], label: store.cursor))
"#;
        let mut runtime = PlanExecutorLiveSession::from_source(
            "root-scalar-same-event-flush",
            source,
            TargetProfile::SoftwareDefault,
        )
        .unwrap();
        assert_eq!(runtime.state_summary()["store"]["cursor"], "A:ready");

        let step_report = runtime
            .apply_source_event(LiveSourceEvent {
                source: "store.elements.select".to_owned(),
                text: Some("b".to_owned()),
                ..LiveSourceEvent::default()
            })
            .unwrap();
        let output = plan_executor_step_report_to_live_turn_output(&step_report, 0.0)
            .expect("step report should convert to live output");

        let state_summary = runtime.state_summary();
        assert_eq!(state_summary["store"]["active"], "b");
        assert_eq!(state_summary["store"]["selected"], "B");
        assert_eq!(state_summary["store"]["default_label"], "B:ready");
        assert_eq!(
            state_summary["store"]["cursor"], "B:ready",
            "cursor must read the same-event recomputed default_label, not the stale initial value"
        );
        assert!(
            output.semantic_deltas.iter().any(|delta| {
                delta.kind == "FieldSet"
                    && delta.field_path.as_deref() == Some("store.cursor")
                    && matches!(&delta.value, ProtocolValue::Text(value) if value == "B:ready")
            }),
            "cursor update should be emitted from the PlanExecutor same-turn currentness path: {:#?}",
            output.semantic_deltas
        );
    }

