    #[test]
    fn structured_root_parent_change_prunes_owned_child_materialization() {
        let source = r#"
store: [
    elements: [
        cursor_input: SOURCE
    ]
    cursor:
        TEXT { 42 s } |> HOLD cursor {
            LATEST {
                elements.cursor_input.text
            }
        }
    page_ref: [
        ref_type: TEXT { PageRef }
        cursor: cursor
    ]
    page_label:
        page_ref.cursor |> Text/concat(with: page_ref.ref_type, separator: " ")
]

document: Document/new(root: Element/label(element: [], label: store.page_label))
"#;
        let mut runtime =
            LoadedRuntimeHarness::from_source("root-structured-parent-prune-child", source)
                .unwrap();
        {
            let generic = runtime
                .loaded_runtime_for_test()
                .generic
                .as_ref()
                .expect("generic runtime should be available");
            assert!(
                generic
                    .generic_derived
                    .root_field_plan("store.page_ref.cursor")
                    .is_some(),
                "test needs a nested child root field to prove pruning"
            );
        }

        let output = runtime
            .apply_source_event_turn(LiveSourceEvent {
                source: "store.elements.cursor_input".to_owned(),
                text: Some("150 s".to_owned()),
                ..LiveSourceEvent::default()
            })
            .unwrap();
        let summary = runtime.state_summary();
        assert_eq!(summary["store"]["page_label"], "150 s PageRef");
        assert!(
            output.semantic_deltas.iter().any(|delta| {
                delta.kind == "FieldSet" && delta.field_path.as_deref() == Some("store.page_label")
            }),
            "parent child dirty reads must still update downstream dependents: {:#?}",
            output.semantic_deltas
        );
        let materialized_paths = output
            .root_materialization_stats
            .samples
            .iter()
            .map(|sample| sample.path.as_str())
            .collect::<BTreeSet<_>>();
        let child_materialization_count = output
            .root_materialization_stats
            .samples
            .iter()
            .filter(|sample| sample.path == "store.page_ref.cursor")
            .count();
        assert!(
            materialized_paths.contains("store.page_ref"),
            "the structured parent should still materialize: {materialized_paths:#?}"
        );
        assert_eq!(
            child_materialization_count, 0,
            "a structured child root should be pruned when its dirty parent will publish child changed reads: {materialized_paths:#?}"
        );
        assert!(
            output
                .runtime_step_profile
                .source_action_root_dirty_frontier_samples
                .iter()
                .any(|sample| {
                    sample.dependent_root == "store.page_ref.cursor"
                        && sample.dependent_enqueue_count == 0
                        && sample.structured_parent_skip_count > 0
                }),
            "a structured child projection should not be separately enqueued when its dirty parent is pending: {:#?}",
            output
                .runtime_step_profile
                .source_action_root_dirty_frontier_samples
        );
    }

    #[test]
    fn nested_structured_child_change_does_not_dirty_top_level_leaf_alias() {
        let source = r#"
store: [
    elements: [
        filter: SOURCE
    ]
    cursor:
        TEXT { top-cursor } |> HOLD cursor { LATEST {} }
    page_ref: [
        ref_type: TEXT { PageRef }
        cursor: TEXT { nested-cursor }
    ]
    cursor_label:
        cursor |> Text/concat(with: TEXT { label }, separator: " ")
    page_label:
        page_ref.cursor |> Text/concat(with: page_ref.ref_type, separator: " ")
]

document: Document/new(root: Element/label(element: [], label: store.page_label))
"#;
        let mut runtime = LoadedRuntimeHarness::from_source(
            "root-structured-child-no-leaf-alias-collision",
            source,
        )
        .unwrap();
        let initial = runtime.state_summary();
        assert_eq!(initial["store"]["cursor_label"], "top-cursor label");
        assert_eq!(initial["store"]["page_label"], "nested-cursor PageRef");

        let generic = runtime
            .loaded_runtime_for_test_mut()
            .generic
            .as_mut()
            .expect("generic runtime should be available");
        let page_label_reads = generic
            .generic_derived_state
            .root_reads_by_field
            .get("store.page_label")
            .expect("page label should have recorded root reads");
        assert!(
            page_label_reads.contains(&GenericReadKey::RootChild {
                root: "store.page_ref".to_owned(),
                path: "cursor".to_owned(),
            }),
            "page_ref.cursor consumers should subscribe to a structured child key: {page_label_reads:#?}"
        );
        assert!(
            !page_label_reads.contains(&GenericReadKey::Root {
                field: "store.page_ref".to_owned(),
            }),
            "page_ref.cursor consumers must not subscribe to the whole parent root: {page_label_reads:#?}"
        );
        let sample_start = generic.root_materialization_stats.samples.len();
        let dirty_reads = root_read_keys_for_path("store.page_ref.cursor")
            .into_iter()
            .collect::<BTreeSet<_>>();
        let materializations = generic
            .materialize_root_derived_field_commits_for_changed_reads(
                dirty_reads,
                None,
                &BTreeSet::new(),
            )
            .expect("synthetic nested-child dirty wave should materialize");
        let materialized_paths = generic.root_materialization_stats.samples[sample_start..]
            .iter()
            .map(|sample| sample.path.as_str())
            .collect::<BTreeSet<_>>();
        assert!(
            materialized_paths.contains("store.page_label")
                || materializations
                    .iter()
                    .any(|materialization| materialization.target == "store.page_label"),
            "a nested page_ref.cursor dirty key should still reach page_label: {materialized_paths:#?}"
        );
        assert!(
            !materialized_paths.contains("store.cursor_label")
                && materializations
                    .iter()
                    .all(|materialization| materialization.target != "store.cursor_label"),
            "a change to store.page_ref.cursor must not dirty a root that only read top-level store.cursor: {:#?}",
            materialized_paths
        );
    }

