    #[test]
    fn root_list_chunk_direct_materialization_uses_storage_backed_projection() {
        let source = r#"
signals:
    LIST {
        [name: TEXT { clk }, family: TEXT { clock }]
        [name: TEXT { data0 }, family: TEXT { data }]
        [name: TEXT { data1 }, family: TEXT { data }]
        [name: TEXT { data2 }, family: TEXT { data }]
    }
    |> List/map(signal, new: new_signal(signal: signal))

store: [
    elements: [
        filter: SOURCE
    ]
    query:
        TEXT { data } |> HOLD query {
            LATEST {
                elements.filter.text
            }
        }
    search_results:
        signals |> List/filter_text_contains(field: "name", needle: query, prefer_field: "family", empty_field: "family", empty_value: TEXT { data })
    visible_rows:
        List/chunk(search_results, size: 2, items: signals, label: row_number)
]

document: Document/new(root: Element/label(element: [], label: TEXT { Signals }))

FUNCTION new_signal(signal) {
    [
        name: signal.name
        family: signal.family
    ]
}
"#;
        let mut runtime =
            LoadedRuntimeHarness::from_source("root-list-chunk-direct", source).unwrap();
        let initial = runtime.state_summary();
        let initial_rows = initial["store"]["visible_rows"].as_array().unwrap();
        assert_eq!(initial_rows.len(), 2);
        assert_eq!(initial_rows[0]["signals"][0]["name"], "data0");
        assert_eq!(initial_rows[1]["signals"][0]["name"], "data2");

        let output = runtime
            .apply_source_event_turn(LiveSourceEvent {
                source: "store.elements.filter".to_owned(),
                text: Some("clk".to_owned()),
                ..LiveSourceEvent::default()
            })
            .expect("filter text should refresh chunked visible rows");
        let summary = runtime.state_summary();
        let rows = summary["store"]["visible_rows"].as_array().unwrap();
        assert_eq!(rows.len(), 1);
        assert_eq!(rows[0]["row_number"], "0");
        assert_eq!(rows[0]["signals"][0]["name"], "clk");

        let sample = output
            .root_materialization_stats
            .samples
            .iter()
            .find(|sample| sample.path == "store.visible_rows")
            .expect("visible_rows chunk projection should record a materialization sample");
        let profile = sample
            .list_view_profile
            .as_ref()
            .expect("chunk projection should expose a list-view profile");
        assert_eq!(profile.list_storage_mode, "direct_chunk_projection");
        assert_eq!(profile.full_eval_row_count, 0);
        assert_eq!(profile.list_map_call_count, 0);
        assert_eq!(profile.list_map_row_count, 0);
        assert_eq!(profile.row_count, 1);
        assert_eq!(profile.previous_row_count, 2);
        assert!(
            profile.list_value_shape.ends_with("_chunk_projection"),
            "direct chunk profile should classify the source shape: {profile:?}"
        );
        assert!(
            output.list_scan_counters.list_view_direct_rows >= 1,
            "direct chunk path should report direct row handling: {:?}",
            output.list_scan_counters
        );
    }

    #[test]
    fn list_filter_field_and_move_project_selected_rows() {
        let source = r#"
store: [
    elements: [
        load_default_file: SOURCE
        show_empty: SOURCE
        selected_remove_data: SOURCE
        selected_restore_data: SOURCE
        selected_data_up: SOURCE
        selected_data_down: SOURCE
    ]
    selected_signal_defaults:
        LIST {
            [id: TEXT { clk }, name: TEXT { clk }, enabled: TEXT { loaded }]
            [id: TEXT { reset_n }, name: TEXT { reset_n }, enabled: TEXT { loaded }]
            [id: TEXT { data_bus }, name: TEXT { data_bus[7:0] }, enabled: TEXT { loaded }]
            [id: TEXT { data_valid }, name: TEXT { data_valid }, enabled: TEXT { loaded }]
        }
    selected_rows_enabled_value:
        TEXT { none } |> HOLD selected_rows_enabled_value {
            LATEST {
                elements.load_default_file.event.press |> THEN { TEXT { loaded } }
                elements.selected_remove_data.event.press |> THEN { TEXT { loaded } }
                elements.selected_restore_data.event.press |> THEN { TEXT { loaded } }
                elements.selected_data_up.event.press |> THEN { TEXT { loaded } }
                elements.selected_data_down.event.press |> THEN { TEXT { loaded } }
                elements.show_empty.event.press |> THEN { TEXT { none } }
            }
        }
    selected_rows_removed_signal_id:
        LATEST {
            TEXT { none }
            elements.selected_remove_data.event.press |> THEN { TEXT { data_bus } }
            elements.selected_restore_data.event.press |> THEN { TEXT { none } }
            elements.selected_data_up.event.press |> THEN { TEXT { none } }
            elements.selected_data_down.event.press |> THEN { TEXT { none } }
            elements.load_default_file.event.press |> THEN { TEXT { none } }
            elements.show_empty.event.press |> THEN { TEXT { none } }
        }
    selected_rows_first_signal_id:
        LATEST {
            TEXT { none }
            elements.selected_data_up.event.press |> THEN { TEXT { data_bus } }
            elements.selected_remove_data.event.press |> THEN { TEXT { none } }
            elements.selected_restore_data.event.press |> THEN { TEXT { none } }
            elements.selected_data_down.event.press |> THEN { TEXT { none } }
            elements.load_default_file.event.press |> THEN { TEXT { none } }
            elements.show_empty.event.press |> THEN { TEXT { none } }
        }
    selected_rows_last_signal_id:
        LATEST {
            TEXT { none }
            elements.selected_data_down.event.press |> THEN { TEXT { data_bus } }
            elements.selected_remove_data.event.press |> THEN { TEXT { none } }
            elements.selected_restore_data.event.press |> THEN { TEXT { none } }
            elements.selected_data_up.event.press |> THEN { TEXT { none } }
            elements.load_default_file.event.press |> THEN { TEXT { none } }
            elements.show_empty.event.press |> THEN { TEXT { none } }
        }
    selected_signals:
        selected_signal_defaults
        |> List/filter_field_equal(field: "enabled", value: selected_rows_enabled_value)
        |> List/filter_field_not_equal(field: "id", value: selected_rows_removed_signal_id)
        |> List/move_field_first(field: "id", value: selected_rows_first_signal_id)
        |> List/move_field_last(field: "id", value: selected_rows_last_signal_id)
    selected_rows_count:
        selected_signals |> List/length()
    selected_rows_order_label:
        selected_signals |> List/join_field(field: "name", separator: ", ", empty: "none")
]

document: Document/new(root: Element/label(element: [], label: TEXT { Selected rows }))
"#;
        let mut runtime =
            LoadedRuntimeHarness::from_source("selected-list-transforms", source).unwrap();
        assert_eq!(
            runtime.state_summary()["store"]["selected_rows_order_label"],
            "none"
        );

        for (source, expected_count, expected_order) in [
            (
                "store.elements.load_default_file",
                4,
                "clk, reset_n, data_bus[7:0], data_valid",
            ),
            (
                "store.elements.selected_remove_data",
                3,
                "clk, reset_n, data_valid",
            ),
            (
                "store.elements.selected_restore_data",
                4,
                "clk, reset_n, data_bus[7:0], data_valid",
            ),
            (
                "store.elements.selected_data_up",
                4,
                "data_bus[7:0], clk, reset_n, data_valid",
            ),
            (
                "store.elements.selected_data_down",
                4,
                "clk, reset_n, data_valid, data_bus[7:0]",
            ),
            ("store.elements.show_empty", 0, "none"),
        ] {
            runtime
                .apply_source_event(LiveSourceEvent {
                    source: source.to_owned(),
                    ..LiveSourceEvent::default()
                })
                .unwrap();
            let summary = runtime.state_summary();
            assert_eq!(
                summary["store"]["selected_rows_count"],
                serde_json::json!(expected_count),
                "{source}"
            );
            assert_eq!(
                summary["store"]["selected_rows_order_label"], expected_order,
                "{source}"
            );
        }
    }

