    #[test]
    fn root_list_view_materialization_samples_include_phase_profile() {
        let source = r#"
store: [
    elements: [
        click: SOURCE
    ]
    active_file:
        TEXT { simple.vcd } |> HOLD active_file {
            LATEST {
                elements.click.event.press |> THEN { TEXT { uart.fst } }
            }
        }
    waveform_segment_records:
        LIST {
            [file: TEXT { simple.vcd }, signal_id: TEXT { clk }, label: TEXT { 0 }]
            [file: TEXT { uart.fst }, signal_id: TEXT { tx }, label: TEXT { 1 }]
        }
    selected_waveform_segments:
        waveform_segment_records
        |> List/filter_field_equal(field: "file", value: active_file)
        |> List/map(segment, new: segment)
]

document: Document/new(root: Element/label(element: [], label: TEXT { Rows }))
"#;
        let mut runtime =
            LoadedRuntimeHarness::from_source("root-list-view-materialization-profile", source)
                .unwrap();
        let output = runtime
            .apply_source_event_turn(LiveSourceEvent {
                source: "store.elements.click".to_owned(),
                ..LiveSourceEvent::default()
            })
            .expect("click should update list-view rows");
        let sample = output
            .root_materialization_stats
            .samples
            .iter()
            .find(|sample| sample.path == "store.selected_waveform_segments")
            .expect("root list-view materialization sample should be recorded");
        assert_eq!(sample.kind, "list_view");
        let profile = sample
            .list_view_profile
            .as_ref()
            .expect("list-view sample should expose phase profile");
        assert_eq!(profile.list, "selected_waveform_segments");
        assert!(
            matches!(
                profile.list_storage_mode.as_str(),
                "generic_vec_materialization"
                    | "generic_vec_with_source_identities"
                    | "generic_vec_with_row_index_source"
                    | "row_ref_projection_reuse"
                    | "field_only_record_projection"
                    | "field_only_row_index_projection"
            ),
            "list-view profile should classify storage mode: {profile:?}"
        );
        assert!(
            !profile.list_value_shape.is_empty(),
            "list-view profile should classify value shape: {profile:?}"
        );
        assert_eq!(profile.row_count, 1);
        assert_eq!(profile.previous_row_count, 1);
        assert_eq!(profile.changed_row_count, 1);
        assert!(profile.changed_field_count >= 1);
        assert!(!profile.broad_fallback);
        assert!(profile.eval_ms >= 0.0);
        assert!(profile.row_materialize_ms >= 0.0);
        assert!(profile.diff_ms >= 0.0);
        assert!(
            profile.list_map_call_count >= 1,
            "list-view profile should attribute List/map calls: {profile:?}"
        );
        assert_eq!(profile.list_map_row_count, profile.row_count);
        assert!(profile.list_map_total_ms >= profile.list_map_values_ms);
        assert!(profile.list_map_total_ms >= profile.list_map_row_eval_ms);
        assert!(profile.field_profile_total_ms >= 0.0);
        assert!(
            profile.eval_minus_field_profiles_ms >= 0.0,
            "field-profile residual should not go negative: {profile:?}"
        );
        assert!(
            profile.eval_unattributed_ms >= 0.0,
            "eval attribution residual should not go negative: {profile:?}"
        );
    }

