                let generic = runtime
                    .loaded_runtime_for_test()
                    .generic
                    .as_ref()
                    .expect("generic runtime should be present");
                let sources = generic
                    .source_routes
                    .route_slots
                    .iter()
                    .filter(|route| route.source.contains("select_file"))
                    .map(|route| route.source.clone())
                    .collect::<Vec<_>>();
                let row_bindings = generic
                    .list_source_bindings
                    .slots()
                    .iter()
                    .map(|slot| {
                        format!(
                            "{}:{}:{:?}",
                            slot.list, slot.row_scope, slot.source_paths
                        )
                    })
                    .collect::<Vec<_>>();
