    #[test]
    fn exact_list_lookup_invalidation_tracks_old_and_new_text_values() {
        let cached_reads = BTreeSet::from([list_lookup_text_read_key("records", "key", "row-2")]);
        let guards = BTreeMap::new();
        let root_numbers = BTreeMap::new();

        let mut unrelated_change = BTreeSet::new();
        insert_changed_list_field_read_keys_for_values(
            &mut unrelated_change,
            "records",
            0,
            "key",
            Some(&FieldValue::Text("row-1".to_owned())),
            Some(&FieldValue::Text("row-3".to_owned())),
        );
        assert!(
            !cache_entry_invalidated_by_reads(
                &cached_reads,
                &guards,
                &unrelated_change,
                &root_numbers
            ),
            "a row that changes between unrelated key values must not invalidate an exact lookup"
        );

        let mut changed_to_match = BTreeSet::new();
        insert_changed_list_field_read_keys_for_values(
            &mut changed_to_match,
            "records",
            0,
            "key",
            Some(&FieldValue::Text("row-1".to_owned())),
            Some(&FieldValue::Text("row-2".to_owned())),
        );
        assert!(
            cache_entry_invalidated_by_reads(
                &cached_reads,
                &guards,
                &changed_to_match,
                &root_numbers
            ),
            "a row changing to the expected lookup value must invalidate the exact lookup"
        );

        let mut changed_from_match = BTreeSet::new();
        insert_changed_list_field_read_keys_for_values(
            &mut changed_from_match,
            "records",
            1,
            "key",
            Some(&FieldValue::Text("row-2".to_owned())),
            Some(&FieldValue::Text("row-3".to_owned())),
        );
        assert!(
            cache_entry_invalidated_by_reads(
                &cached_reads,
                &guards,
                &changed_from_match,
                &root_numbers
            ),
            "a row changing away from the expected lookup value must invalidate the exact lookup"
        );
    }

    #[test]
    fn indexed_lookup_cache_invalidates_only_changed_list_field() {
        let source = r#"
store: [
    sources: [
        noop: SOURCE
    ]
    ready:
        TEXT { ready } |> HOLD ready { LATEST {} }
    records:
        LIST {
            [key: TEXT { row-1 }, value: TEXT { first }]
            [key: TEXT { row-2 }, value: TEXT { second }]
        }
    defaults:
        LIST {
            [address: TEXT { A0 }, value: TEXT { 5 }]
            [address: TEXT { A1 }, value: TEXT { 7 }]
        }
]

document: Document/new(root: Element/label(element: [], label: TEXT { Rows }))
"#;
        let mut runtime =
            LoadedRuntimeHarness::from_source("indexed-cache-field-invalidation", source).unwrap();
        let generic = runtime
            .loaded_runtime_for_test_mut()
            .generic
            .as_mut()
            .unwrap();
        let records = generic
            .storage
            .list_name_for_path("store.records")
            .unwrap()
            .to_owned();
        let defaults = generic
            .storage
            .list_name_for_path("store.defaults")
            .unwrap()
            .to_owned();

        generic
            .cached_find_list_indices_by_textlike_indexed(&records, "key", "row-2")
            .unwrap();
        generic
            .cached_find_list_indices_by_textlike_indexed(&defaults, "address", "A0")
            .unwrap();

        let records_key = TextLookupCacheKey {
            list: records.clone(),
            field: "key".to_owned(),
            expected: "row-2".to_owned(),
        };
        let defaults_key = TextLookupCacheKey {
            list: defaults.clone(),
            field: "address".to_owned(),
            expected: "A0".to_owned(),
        };
        assert!(generic.indexed_lookup_cache.text.contains_key(&records_key));
        assert!(
            generic
                .indexed_lookup_cache
                .text
                .contains_key(&defaults_key)
        );

        generic.invalidate_indexed_lookup_cache_for_list_field(&records, "value");
        assert!(
            generic.indexed_lookup_cache.text.contains_key(&records_key),
            "changing an unrelated field in the same list must not drop key lookups"
        );
        assert!(
            generic
                .indexed_lookup_cache
                .text
                .contains_key(&defaults_key),
            "changing one list must not drop lookups for another list"
        );

        generic.invalidate_indexed_lookup_cache_for_list_field(&records, "key");
        assert!(
            !generic.indexed_lookup_cache.text.contains_key(&records_key),
            "changing the indexed field must drop stale lookups for that field"
        );
        assert!(
            generic
                .indexed_lookup_cache
                .text
                .contains_key(&defaults_key),
            "field-targeted invalidation must still preserve unrelated list lookups"
        );
    }

